  INSERT INTO lesson_versions (id, lesson_id, version, status, published_at) VALUES ('c9a95da1-fdbf-507d-8923-c099be287015', '48c88a63-4bd6-502b-905f-7f207f9404ad', 1, 'published', now()) ON CONFLICT (lesson_id, version) DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('6375d7c3-805c-51ed-ba19-dae18686fd26', '691ecb7e-ba62-56af-9223-ba8585fda12b', 'markdown', 0, '{"text":"Pick a site idea that can realistically reach a live URL in this track.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('9142a3c7-eac1-5315-a117-f84b786ac307', '691ecb7e-ba62-56af-9223-ba8585fda12b', 'callout', 1, '{"variant":"why","text":"スタックと期限に合わないアイデアを選ぶと、途中で詰まって完成しません。最初に「出せる範囲」を決めることが完走の鍵です。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('77491381-7b11-5fed-b2ad-0afd44ba3a47', '691ecb7e-ba62-56af-9223-ba8585fda12b', 'markdown', 2, '{"text":"自分が作りたいものを 3 つ書き出し、Next.js + Supabase + Vercel で実現できるか・1 週間で MVP に届くかの 2 軸で絞ります。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('ea3b09d9-1f72-5daa-bd3b-166fcd88830d', '691ecb7e-ba62-56af-9223-ba8585fda12b', 'markdown', 3, '{"text":"# Choose a site idea that fits the stack and timeline\n\nPick a site idea that can realistically reach a live URL in this track.\n\n## このレッスンのゴール\nYou will leave with a concrete build target that matches Next.js, Supabase, and Vercel.\n\n## 先に把握しておくこと\n- モジュール: **Scope the Build**\n- 想定時間: **25 分**\n- 到達したい状態: project_goal_defined\n\n## なぜ今やるのか\nスタックと期限に合わないアイデアを選ぶと、途中で詰まって完成しません。最初に「出せる範囲」を決めることが完走の鍵です。\n\n## 進め方\n1. 自分が作りたいものを 3 つ書き出し、Next.\n2. js + Supabase + Vercel で実現できるか・1 週間で MVP に届くかの 2 軸で絞ります。\n\n## このレッスンで残すもの\n- Chosen site concept\n- Target audience note\n\n## 詰まりやすいポイント\n- アイデアが大きすぎて絞れない、誰向けか曖昧なまま進めてしまう。\n\n## AI への依頼例\n```text\n今は「Choose a site idea that fits the stack and timeline」を進めています。\n目的: You will leave with a concrete build target that matches Next.js, Supabase, and Vercel.\n現状: Pick a site idea that can realistically reach a live URL in this track.\n今回残したい成果物: Chosen site concept、Target audience note\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- サイトの目的を一文で説明でき、対象ユーザーを具体的に言えること。\n\n## 関連キーワード\n- `website idea`\n- `mvp project choice`\n- `choose app idea`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('2a1a18c7-2824-51bc-90f0-760f2bbef5d2', '691ecb7e-ba62-56af-9223-ba8585fda12b', 'callout', 4, '{"variant":"warning","text":"アイデアが大きすぎて絞れない、誰向けか曖昧なまま進めてしまう。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('34940fd1-1c32-5ebb-90a1-0579e6f6b53c', '691ecb7e-ba62-56af-9223-ba8585fda12b', 'rubric', 5, '{"criteria":"サイトの目的を一文で説明でき、対象ユーザーを具体的に言えること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d226d19f-20e6-54a1-b657-efdd1d2b3d81', 'd913261c-feb0-565d-bcac-ed11219c2c51', 'markdown', 0, '{"text":"Turn the idea into pages, states, and the one flow that matters most.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('48c34fdc-982b-5771-9c2c-0331f51751b8', 'd913261c-feb0-565d-bcac-ed11219c2c51', 'callout', 1, '{"variant":"why","text":"ページ数と導線を決めずに実装を始めると、作業が発散して完成しなくなります。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('e7cecf72-ce25-5577-8b4f-5ac45e741c76', 'd913261c-feb0-565d-bcac-ed11219c2c51', 'markdown', 2, '{"text":"ゴールから逆算して必要なページを洗い出し、ユーザーが最初にたどる 1 本の導線を図にします。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('9615dc8a-283a-5fc5-a419-ee9b3e78ed9d', 'd913261c-feb0-565d-bcac-ed11219c2c51', 'markdown', 3, '{"text":"# Define the MVP pages and primary user flow\n\nTurn the idea into pages, states, and the one flow that matters most.\n\n## このレッスンのゴール\nYou will know exactly what the first version of the site must include.\n\n## 先に把握しておくこと\n- モジュール: **Scope the Build**\n- 想定時間: **30 分**\n- 到達したい状態: mvp_pages_defined\n\n## なぜ今やるのか\nページ数と導線を決めずに実装を始めると、作業が発散して完成しなくなります。\n\n## 進め方\n1. ゴールから逆算して必要なページを洗い出し、ユーザーが最初にたどる 1 本の導線を図にします。\n\n## このレッスンで残すもの\n- Page list\n- Primary user flow\n\n## 詰まりやすいポイント\n- ページ数を増やしすぎる、ユーザーフローが曖昧なまま次に進む。\n\n## AI への依頼例\n```text\n今は「Define the MVP pages and primary user flow」を進めています。\n目的: You will know exactly what the first version of the site must include.\n現状: Turn the idea into pages, states, and the one flow that matters most.\n今回残したい成果物: Page list、Primary user flow\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- MVP に含めるページ一覧と主要導線を他人に説明できること。\n\n## 関連キーワード\n- `mvp pages`\n- `user flow definition`\n- `website scope`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('91ffe358-9b1e-53bc-b726-6482bfa216a3', 'd913261c-feb0-565d-bcac-ed11219c2c51', 'callout', 4, '{"variant":"warning","text":"ページ数を増やしすぎる、ユーザーフローが曖昧なまま次に進む。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('7896fc40-0ac5-5dd5-ba6a-b0ce4cd3122e', 'd913261c-feb0-565d-bcac-ed11219c2c51', 'rubric', 5, '{"criteria":"MVP に含めるページ一覧と主要導線を他人に説明できること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('45eae57c-a8a0-55a0-a069-8ee72c2fabcc', 'b82a4f8b-ff84-551f-84ce-605cc20a5015', 'markdown', 0, '{"text":"Break the project into tasks that AI can help implement without losing focus.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('a2bac5f3-51d4-5ce2-80c7-700d354cd830', 'b82a4f8b-ff84-551f-84ce-605cc20a5015', 'callout', 1, '{"variant":"why","text":"タスク分解なしに AI に丸投げすると、出力が大きすぎて確認できません。小さな単位に分けることで各ステップを検証できます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('e9e65155-d4dc-518b-b5e4-cecd22c04f67', 'b82a4f8b-ff84-551f-84ce-605cc20a5015', 'markdown', 2, '{"text":"MVP ページ一覧をもとに、画面ごと・機能ごとにタスクを書き出し、優先順位を付けます。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('318d5697-8dc3-5a94-8a53-a4f82d75d837', 'b82a4f8b-ff84-551f-84ce-605cc20a5015', 'markdown', 3, '{"text":"# Turn the idea into an implementation checklist\n\nBreak the project into tasks that AI can help implement without losing focus.\n\n## このレッスンのゴール\nYou will have a build plan you can execute session by session.\n\n## 先に把握しておくこと\n- モジュール: **Scope the Build**\n- 想定時間: **20 分**\n- 到達したい状態: build_checklist_created\n\n## なぜ今やるのか\nタスク分解なしに AI に丸投げすると、出力が大きすぎて確認できません。小さな単位に分けることで各ステップを検証できます。\n\n## 進め方\n1. MVP ページ一覧をもとに、画面ごと・機能ごとにタスクを書き出し、優先順位を付けます。\n\n## このレッスンで残すもの\n- Implementation checklist\n- Priority order\n\n## 詰まりやすいポイント\n- スコープが広がって優先順位がつけられない、タスク粒度が大きすぎる。\n\n## AI への依頼例\n```text\n今は「Turn the idea into an implementation checklist」を進めています。\n目的: You will have a build plan you can execute session by session.\n現状: Break the project into tasks that AI can help implement without losing focus.\n今回残したい成果物: Implementation checklist、Priority order\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- 実装チェックリストが存在し、各タスクに優先順位が付いていること。\n\n## 関連キーワード\n- `implementation checklist`\n- `break project into tasks`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('77762699-1b58-5060-aa43-de98817e1821', 'b82a4f8b-ff84-551f-84ce-605cc20a5015', 'callout', 4, '{"variant":"warning","text":"スコープが広がって優先順位がつけられない、タスク粒度が大きすぎる。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('2eea7699-ea1d-51d7-89ae-eed9d50651c8', 'b82a4f8b-ff84-551f-84ce-605cc20a5015', 'rubric', 5, '{"criteria":"実装チェックリストが存在し、各タスクに優先順位が付いていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('cd7759e7-0687-51a0-8580-01f014079b38', 'd7b4209d-43aa-5af6-9248-29d1e97c1bd3', 'markdown', 0, '{"text":"Prepare the machine and accounts needed for the rest of the track.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('a481ef5e-3a26-51cf-a10c-b056a6918780', 'd7b4209d-43aa-5af6-9248-29d1e97c1bd3', 'callout', 1, '{"variant":"why","text":"開発ツールが揃っていないと、この先のすべてのレッスンで手が止まります。最初に土台を整えることで後続がスムーズになります。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('94508c60-a7af-559e-80e4-85e4078e5e86', 'd7b4209d-43aa-5af6-9248-29d1e97c1bd3', 'markdown', 2, '{"text":"Node.js・pnpm・Git をインストールし、GitHub・Vercel・Supabase のアカウントを作成します。各ツールのバージョン確認コマンドで動作を確認します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c6f8505d-70d4-5147-8e49-01d82d183ec6', 'd7b4209d-43aa-5af6-9248-29d1e97c1bd3', 'markdown', 3, '{"text":"# Install Node.js, pnpm, Git, and required accounts\n\nPrepare the machine and accounts needed for the rest of the track.\n\n## このレッスンのゴール\nYour environment will be ready for building and deployment.\n\n## 先に把握しておくこと\n- モジュール: **Setup the Workspace**\n- 想定時間: **30 分**\n- 到達したい状態: tooling_ready\n\n## なぜ今やるのか\n開発ツールが揃っていないと、この先のすべてのレッスンで手が止まります。最初に土台を整えることで後続がスムーズになります。\n\n## 進め方\n1. Node.\n2. js・pnpm・Git をインストールし、GitHub・Vercel・Supabase のアカウントを作成します。\n3. 各ツールのバージョン確認コマンドで動作を確認します。\n\n## このレッスンで残すもの\n- Required tools installed\n- Accounts confirmed\n\n## 詰まりやすいポイント\n- Node.\n- js 未導入、pnpm のグローバルインストール失敗、必要アカウントの作成漏れ。\n\n## AI への依頼例\n```text\n今は「Install Node.js, pnpm, Git, and required accounts」を進めています。\n目的: Your environment will be ready for building and deployment.\n現状: Prepare the machine and accounts needed for the rest of the track.\n今回残したい成果物: Required tools installed、Accounts confirmed\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- `node -v`、`pnpm -v`、`git --version` が通り、3 サービスのアカウントでログインできること。\n\n## 関連キーワード\n- `install node pnpm git`\n- `vercel account`\n- `supabase account`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('fd54880b-302e-5c60-bf62-e7180dbd7c2a', 'd7b4209d-43aa-5af6-9248-29d1e97c1bd3', 'callout', 4, '{"variant":"warning","text":"Node.js 未導入、pnpm のグローバルインストール失敗、必要アカウントの作成漏れ。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('8a8b35f3-685a-530a-893c-e5cf3370a973', 'd7b4209d-43aa-5af6-9248-29d1e97c1bd3', 'rubric', 5, '{"criteria":"`node -v`、`pnpm -v`、`git --version` が通り、3 サービスのアカウントでログインできること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('6a481ad2-e5f4-5d9e-ab28-b5f769333f0e', '94dd0f1a-6f52-5350-a396-d0e9533de478', 'markdown', 0, '{"text":"AI coding tool が普通のチャット AI と何が違い、Web 制作でどこを任せられるかを整理します。","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('3cf1fef4-a604-5b42-afe7-2229f9ab9683', '94dd0f1a-6f52-5350-a396-d0e9533de478', 'callout', 1, '{"variant":"why","text":"AI coding tool の得意・不得意を知らずに使うと、期待外れな出力に振り回されます。全体像を先に掴むと依頼精度が上がります。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('1441f56f-bdd4-5ec5-b013-09974b114b6a', '94dd0f1a-6f52-5350-a396-d0e9533de478', 'markdown', 2, '{"text":"チャット AI との違いを整理し、ファイル操作・推論・Git 支援の 3 軸で AI coding tool の役割を把握します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('a7fb2d79-d496-5bd4-9f29-20eb671bc87c', '94dd0f1a-6f52-5350-a396-d0e9533de478', 'markdown', 3, '{"text":"# AI coding tool の全体像をつかむ\n\nAI coding tool が普通のチャット AI と何が違い、Web 制作でどこを任せられるかを整理します。\n\n## このレッスンのゴール\nローカル開発、ファイル理解、コマンド実行、Git 操作支援が 1 本の流れとして見えるようになります。\n\n## 先に把握しておくこと\n- モジュール: **Setup the Workspace**\n- 想定時間: **20 分**\n- 到達したい状態: ai_coding_tool_overview_understood\n\n## なぜ今やるのか\nAI coding tool の得意・不得意を知らずに使うと、期待外れな出力に振り回されます。全体像を先に掴むと依頼精度が上がります。\n\n## 進め方\n1. チャット AI との違いを整理し、ファイル操作・推論・Git 支援の 3 軸で AI coding tool の役割を把握します。\n\n## このレッスンで残すもの\n- AI coding tool の役割メモ\n- 使いどころの判断基準\n\n## 詰まりやすいポイント\n- チャット AI と同じ使い方をしてしまう、CLI ベースのツールに抵抗がある。\n\n## AI への依頼例\n```text\n今は「AI coding tool の全体像をつかむ」を進めています。\n目的: ローカル開発、ファイル理解、コマンド実行、Git 操作支援が 1 本の流れとして見えるようになります。\n現状: AI coding tool が普通のチャット AI と何が違い、Web 制作でどこを任せられるかを整理します。\n今回残したい成果物: AI coding tool の役割メモ、使いどころの判断基準\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- AI coding tool の得意な作業を 2 つ以上説明でき、チャット AI との違いを言えること。\n\n## 関連キーワード\n- `ai coding tool overview`\n- `claude code codex overview`\n- `ai 開発ツール 全体像`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('b917ec9c-ef2f-5fb7-afbb-d4bd97aaacb2', '94dd0f1a-6f52-5350-a396-d0e9533de478', 'callout', 4, '{"variant":"warning","text":"チャット AI と同じ使い方をしてしまう、CLI ベースのツールに抵抗がある。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('3e03051b-2f29-5b49-abf7-a0819500c60f', '94dd0f1a-6f52-5350-a396-d0e9533de478', 'rubric', 5, '{"criteria":"AI coding tool の得意な作業を 2 つ以上説明でき、チャット AI との違いを言えること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('a4e17e55-a553-59b9-abc5-b54937f2d1b2', '94dd0f1a-6f52-5350-a396-d0e9533de478', 'image', 6, '{"url":"/lesson-assets/lesson_web_builder_041_ai_coding_tool_overview/claude-code-workflow.png","alt":"Claude Codeがターミナル、AI推論、プロジェクトファイル、Gitコミットをつなぐワークフロー図","caption":"Claude Codeの全体像。開発者がターミナルでClaude Codeを使うと、AIの推論、プロジェクトのファイル理解、Git操作支援がどうつながるかを1枚で示します。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c594a0f0-9f74-5424-8894-6d90c80a1345', '94dd0f1a-6f52-5350-a396-d0e9533de478', 'image', 7, '{"url":"/lesson-assets/lesson_web_builder_041_ai_coding_tool_overview/claude-code-quickstart.png","alt":"Claude Codeのインストール、認証、起動の3ステップを示すインフォグラフィック","caption":"最初の3ステップ。初回セットアップで必要な流れだけを圧縮したクイックスタート図です。本文を読む前の地図として使えます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('166acbd5-8191-5a56-863c-03e9e982bbb0', 'b32d7e45-7ba8-5780-ac80-b1b955e602a5', 'markdown', 0, '{"text":"何を作りたいか、使っている OS、CLI への慣れによって最初に選ぶツールを変えます。","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d1499475-38c4-5e78-9075-ba4729540295', 'b32d7e45-7ba8-5780-ac80-b1b955e602a5', 'callout', 1, '{"variant":"why","text":"自分の環境に合わないツールを選ぶと、セットアップだけで挫折します。条件ベースで選ぶことで不要な試行錯誤を避けられます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('0d907106-3075-54d4-9378-e842134975db', 'b32d7e45-7ba8-5780-ac80-b1b955e602a5', 'markdown', 2, '{"text":"goal・OS・CLI 慣れの 3 条件を書き出し、各ツールの対応表と照合して最適な 1 つを選びます。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('30f34e6b-0a72-5590-9d2e-192eb491e9a9', 'b32d7e45-7ba8-5780-ac80-b1b955e602a5', 'markdown', 3, '{"text":"# goal 別 / OS 別 / CLI 慣れ別に AI tool を選ぶ\n\nこのレッスンでは、最初に使う AI tool を「goal」「OS」「CLI への慣れ」の 3 条件で決めます。迷ったまま複数ツールを触るより、最初の 1 本を決めた方がセットアップと検証が進みます。\n\n## 先に書き出す 3 条件\n- **goal**: 何を作りたいか。要件整理が先か、既存コード編集までしたいか。\n- **OS**: macOS / Windows / Linux のどれか。Windows は WSL が使えるかも確認します。\n- **CLI 慣れ**: 普段から使う / コピペならできる / ほぼ初めて、のどこにいるか。\n\n## 選び方の基本\n1. 既存プロジェクトを読みながらファイル編集やコマンド実行まで進めたいなら、CLI 系を優先します。\n2. まだ作るものが曖昧で、要件整理や画面構成の相談から始めたいなら、まずはチャット系から入って構いません。\n3. CLI が不安な場合でも、最初の目標を「インストール確認」だけに下げると進めやすくなります。\n\n## ツールの見分け方\n- **Claude Code**: リポジトリ理解、複数ファイル編集、コマンド実行、Git 差分確認まで一気通貫で進めたいときに向きます。\n- **Codex CLI**: ターミナル中心で短い反復を回しながら、ローカルのコードを直接進めたいときに向きます。\n- **ブラウザのチャット AI**: 要件整理、コピー作成、エラーの切り分けには便利ですが、ローカル実行や実ファイル編集は別手段が必要です。\n\n## 迷ったときの実務判断\n- **最短でサイトを動かしたい**: CLI 系を 1 つ選ぶ。\n- **まだ要件が固まっていない**: 先にチャット AI で要件を固め、その後 CLI 系に移る。\n- **Windows で CLI が不安**: WSL を使えるか確認し、難しければブラウザ中心で要件整理を進めつつ、ローカル側は最小構成で始める。\n\n## 完了チェック\n- 自分の goal / OS / CLI 慣れを書き出した。\n- 候補を 2 つ以下に絞った。\n- 1 つに決めた理由を一文で説明できる。","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('85f688e7-0228-5d5a-bb92-25ae045a65b3', 'b32d7e45-7ba8-5780-ac80-b1b955e602a5', 'callout', 4, '{"variant":"warning","text":"必要アカウントの未作成、CLI セットアップでの環境差異。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('db17b1b9-98a8-5740-a4c2-169e5139eaff', 'b32d7e45-7ba8-5780-ac80-b1b955e602a5', 'rubric', 5, '{"criteria":"自分の OS と CLI 慣れに合うツールを 1 つ選び、選んだ理由を説明できること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('292c26f7-9ab9-59f1-be7d-c29d377bdef3', 'b32d7e45-7ba8-5780-ac80-b1b955e602a5', 'image', 6, '{"url":"/lesson-assets/lesson_web_builder_042_choose_ai_tool_by_goal_os_cli/tool-decision-flowchart.png","alt":"OS、CLI慣れ、goalの3条件でClaude Code / Codex / ChatGPT / GUI assistantに分岐するフローチャート","caption":"OS・CLI 慣れ・goal の 3 軸で分岐する AI tool 選定フローチャート。自分がどのルートに当てはまるかを確認できます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('2f4cd665-661c-55f9-bc7c-b0d3c9d53865', 'b32d7e45-7ba8-5780-ac80-b1b955e602a5', 'image', 7, '{"url":"/lesson-assets/lesson_web_builder_042_choose_ai_tool_by_goal_os_cli/tool-comparison-table.png","alt":"Claude Code、Codex、ChatGPT、GUI assistantの比較表（得意な場面、向かないケース、導入の手軽さ）","caption":"4 つの AI tool を「得意な場面」「向かないケース」「導入の手軽さ」で比較した一覧表。選定後の振り返りにも使えます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('bc374957-4ae0-52de-8235-80826ea49c76', 'f7e6a0c3-5324-57c2-83de-8022847eb17a', 'markdown', 0, '{"text":"Web 制作トラックで Claude Code と Codex が有力になる理由を、作業の種類ごとに比較します。","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('50172c57-6ea7-53f8-a784-b80c173a1aa7', 'f7e6a0c3-5324-57c2-83de-8022847eb17a', 'callout', 1, '{"variant":"why","text":"ツール選定を曖昧にすると、以降のレッスンで手順が噛み合わなくなります。理由付きで選ぶことで迷いが消えます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d71f6bb6-41be-520e-8e92-d1c4c9c664f7', 'f7e6a0c3-5324-57c2-83de-8022847eb17a', 'markdown', 2, '{"text":"Claude Code と Codex の得意な作業タイプを比較し、自分の進め方との相性で 1 つに決めます。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('13968b61-8795-5e29-9e9a-dd7ddcd778fa', 'f7e6a0c3-5324-57c2-83de-8022847eb17a', 'markdown', 3, '{"text":"# Claude Code または Codex をなぜ使うのか\n\nWeb 制作トラックで Claude Code と Codex が有力になる理由を、作業の種類ごとに比較します。\n\n## このレッスンのゴール\nどちらを採用するかを、自分の進め方と相性ベースで判断できます。\n\n## 先に把握しておくこと\n- モジュール: **Setup the Workspace**\n- 想定時間: **15 分**\n- 到達したい状態: claude_or_codex_rationale_defined\n\n## なぜ今やるのか\nツール選定を曖昧にすると、以降のレッスンで手順が噛み合わなくなります。理由付きで選ぶことで迷いが消えます。\n\n## 進め方\n1. Claude Code と Codex の得意な作業タイプを比較し、自分の進め方との相性で 1 つに決めます。\n\n## このレッスンで残すもの\n- 採用するツールの理由メモ\n\n## 詰まりやすいポイント\n- CLI セットアップへの不安で判断を先延ばしにする。\n\n## AI への依頼例\n```text\n今は「Claude Code または Codex をなぜ使うのか」を進めています。\n目的: どちらを採用するかを、自分の進め方と相性ベースで判断できます。\n現状: Web 制作トラックで Claude Code と Codex が有力になる理由を、作業の種類ごとに比較します。\n今回残したい成果物: 採用するツールの理由メモ\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- Claude Code と Codex の向き不向きを説明でき、採用ツールの理由メモが書けていること。\n\n## 関連キーワード\n- `why claude code`\n- `why codex`\n- `claude code vs codex web development`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('a736ab27-f215-5e48-862d-eef40b04b42d', 'f7e6a0c3-5324-57c2-83de-8022847eb17a', 'callout', 4, '{"variant":"warning","text":"CLI セットアップへの不安で判断を先延ばしにする。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('40b1fb38-e998-5316-b035-7c1f25c72312', 'f7e6a0c3-5324-57c2-83de-8022847eb17a', 'rubric', 5, '{"criteria":"Claude Code と Codex の向き不向きを説明でき、採用ツールの理由メモが書けていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('033f23d6-ac67-51f0-841c-0489b4ed7079', 'f7e6a0c3-5324-57c2-83de-8022847eb17a', 'image', 6, '{"url":"/lesson-assets/lesson_web_builder_043_why_claude_code_or_codex/claude-code-vs-codex.png","alt":"Claude CodeとCodexの作業フロー比較図。Claude Codeは長い文脈保持、Codexはタスク単位の依頼が特徴","caption":"Claude Code と Codex の作業スタイル比較。同じ goal を扱うとき、それぞれがどのように進めるかを並べて示します。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('8ff9ef71-24a7-5bf1-97fd-1b088f66684c', '082c10d9-d174-5092-8f1e-085341f8fdea', 'markdown', 0, '{"text":"Claude Code をローカルに導入し、起動前に確認すべきコマンドと状態を揃えます。","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('987c8721-0e51-5394-becb-0e6096a5839e', '082c10d9-d174-5092-8f1e-085341f8fdea', 'callout', 1, '{"variant":"why","text":"Claude Code が動かない状態で次に進むと、AI 支援なしで実装することになり効率が大きく下がります。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('f1583c88-5772-56a1-b37a-755aa88d974c', '082c10d9-d174-5092-8f1e-085341f8fdea', 'markdown', 2, '{"text":"npm でグローバルインストールし、`claude --version` で確認、認証ログインを済ませます。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('3bb05651-b7a9-599e-80ed-66ecc005bb50', '082c10d9-d174-5092-8f1e-085341f8fdea', 'markdown', 3, '{"text":"# Claude Code をインストールして確認する\n\nClaude Code をローカルに導入し、起動前に確認すべきコマンドと状態を揃えます。\n\n## このレッスンのゴール\nClaude Code をインストールして、バージョン確認と認証前チェックまで自力で進められます。\n\n## 先に把握しておくこと\n- モジュール: **Setup the Workspace**\n- 想定時間: **25 分**\n- 到達したい状態: claude_code_cli_installed\n\n## なぜ今やるのか\nClaude Code が動かない状態で次に進むと、AI 支援なしで実装することになり効率が大きく下がります。\n\n## 進め方\n1. npm でグローバルインストールし、`claude --version` で確認、認証ログインを済ませます。\n\n## このレッスンで残すもの\n- Claude Code インストール完了\n- 確認コマンド結果\n\n## 詰まりやすいポイント\n- Node.\n- js 未導入、PATH が通っていない、認証トークンの取得失敗。\n\n## AI への依頼例\n```text\n今は「Claude Code をインストールして確認する」を進めています。\n目的: Claude Code をインストールして、バージョン確認と認証前チェックまで自力で進められます。\n現状: Claude Code をローカルに導入し、起動前に確認すべきコマンドと状態を揃えます。\n今回残したい成果物: Claude Code インストール完了、確認コマンド結果\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- Claude Code のバージョン確認が通り、認証状態が正常であること。\n\n## 関連キーワード\n- `install claude code cli`\n- `claude code install`\n- `verify claude code setup`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('91ba1308-de78-57fe-a209-46b0f0529d70', '082c10d9-d174-5092-8f1e-085341f8fdea', 'callout', 4, '{"variant":"warning","text":"Node.js 未導入、PATH が通っていない、認証トークンの取得失敗。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('8bbdcabd-c6cc-512e-bc2e-558babb7fbe9', '082c10d9-d174-5092-8f1e-085341f8fdea', 'rubric', 5, '{"criteria":"Claude Code のバージョン確認が通り、認証状態が正常であること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('080e1b27-6b58-5fba-8d55-a9aaf1e4bc64', '082c10d9-d174-5092-8f1e-085341f8fdea', 'image', 6, '{"url":"/lesson-assets/lesson_web_builder_044_install_claude_code_and_verify/install-steps.png","alt":"ターミナルでnpm install -g @anthropic-ai/claude-codeを実行し、バージョン確認するスクリーンショット","caption":"Claude Code インストールの 3 ステップ。npm install → claude --version → 認証の流れをスクリーンショットで示します。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('95e166ba-7da2-5548-b582-db0f28773516', '082c10d9-d174-5092-8f1e-085341f8fdea', 'image', 7, '{"url":"/lesson-assets/lesson_web_builder_044_install_claude_code_and_verify/verify-checklist.png","alt":"Claude Codeインストール後の確認チェックリスト（バージョン、PATH、認証）","caption":"インストール後の確認チェックリスト。バージョン表示、PATH 確認、認証状態の 3 点を確認します。"}'::jsonb) ON CONFLICT DO NOTHING;
