  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('2b7e150b-f0a4-5a59-a9a0-c66a5d8a86d0', '74cd59de-928f-5338-8bf0-eb5f5bf515a2', 'markdown', 2, '{"text":"npm でグローバルインストールし、バージョン確認コマンドで動作を検証、認証を済ませます。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('91ba1a42-123c-53c2-b154-8a2007cb2761', '74cd59de-928f-5338-8bf0-eb5f5bf515a2', 'markdown', 3, '{"text":"# Codex CLI をインストールして確認する\n\nCodex CLI をローカルに導入し、起動前に確認すべきコマンドと状態を揃えます。\n\n## このレッスンのゴール\nCodex CLI をインストールして、バージョン確認と認証前チェックまで自力で進められます。\n\n## 先に把握しておくこと\n- モジュール: **Setup the Workspace**\n- 想定時間: **25 分**\n- 到達したい状態: codex_cli_installed\n\n## なぜ今やるのか\nCodex CLI が動かない状態で次に進むと、AI 支援なしで実装することになり効率が大きく下がります。\n\n## 進め方\n1. npm でグローバルインストールし、バージョン確認コマンドで動作を検証、認証を済ませます。\n\n## このレッスンで残すもの\n- Codex CLI インストール完了\n- 確認コマンド結果\n\n## 詰まりやすいポイント\n- Node.\n- js 未導入、PATH が通っていない、API キーの設定ミス。\n\n## AI への依頼例\n```text\n今は「Codex CLI をインストールして確認する」を進めています。\n目的: Codex CLI をインストールして、バージョン確認と認証前チェックまで自力で進められます。\n現状: Codex CLI をローカルに導入し、起動前に確認すべきコマンドと状態を揃えます。\n今回残したい成果物: Codex CLI インストール完了、確認コマンド結果\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- Codex CLI のバージョン確認が通り、認証状態が正常であること。\n\n## 関連キーワード\n- `install codex cli`\n- `codex cli install`\n- `verify codex cli setup`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('cd7abe9c-df44-5b90-bac9-f7ca40c524ec', '74cd59de-928f-5338-8bf0-eb5f5bf515a2', 'callout', 4, '{"variant":"warning","text":"Node.js 未導入、PATH が通っていない、API キーの設定ミス。"}'::jsonb) ON CONFLICT DO NOTHING;
