  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('bc5a36b5-51d3-5dc5-8342-e33f0ecea7be', '74cd59de-928f-5338-8bf0-eb5f5bf515a2', 'image', 6, '{"url":"/lesson-assets/lesson_web_builder_045_install_codex_cli_and_verify/install-steps.png","alt":"ターミナルでCodex CLIをインストールし、バージョン確認するスクリーンショット","caption":"Codex CLI インストールの 3 ステップ。npm install → codex --version → 認証の流れをスクリーンショットで示します。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('fde7a034-ee26-5aa6-962a-fdb34a6092b7', '74cd59de-928f-5338-8bf0-eb5f5bf515a2', 'image', 7, '{"url":"/lesson-assets/lesson_web_builder_045_install_codex_cli_and_verify/verify-checklist.png","alt":"Codex CLIインストール後の確認チェックリスト（バージョン、PATH、認証）","caption":"インストール後の確認チェックリスト。バージョン表示、PATH 確認、認証状態の 3 点を確認します。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('3155fdab-d3b0-5443-8331-92d61b2ad316', 'a96a7681-c052-5e04-b3e2-c95ee172118a', 'markdown', 0, '{"text":"最初のプロジェクトを作り、AI へ何をどこまで頼むかを具体的な依頼文の形に落とします。","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('e1a28c38-ea22-554f-a03a-22061c383bcb', 'a96a7681-c052-5e04-b3e2-c95ee172118a', 'callout', 1, '{"variant":"why","text":"インストールだけで止まると AI coding の体験が始まりません。最初の依頼まで繋げることで workflow が定着します。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('882ed61a-89fa-5409-a7d1-f0cd68c10d52', 'a96a7681-c052-5e04-b3e2-c95ee172118a', 'markdown', 2, '{"text":"プロジェクトを作成し、AI に最初の依頼文を書いて実行、出力を確認します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('289c77bc-6f4e-58f5-90f9-1dd1ef5f9abf', 'a96a7681-c052-5e04-b3e2-c95ee172118a', 'markdown', 3, '{"text":"# 最初のプロジェクト作成と AI への依頼の基本\n\n最初のプロジェクトを作り、AI へ何をどこまで頼むかを具体的な依頼文の形に落とします。\n\n## このレッスンのゴール\n空の状態からプロジェクト作成と最初の依頼までを、詰まらずに一周できます。\n\n## 先に把握しておくこと\n- モジュール: **Setup the Workspace**\n- 想定時間: **25 分**\n- 到達したい状態: first_ai_project_created\n\n## なぜ今やるのか\nインストールだけで止まると AI coding の体験が始まりません。最初の依頼まで繋げることで workflow が定着します。\n\n## 進め方\n1. プロジェクトを作成し、AI に最初の依頼文を書いて実行、出力を確認します。\n\n## このレッスンで残すもの\n- 最初のプロジェクト作成メモ\n- 基本プロンプトひな形\n\n## 詰まりやすいポイント\n- 依頼の粒度が大きすぎて AI の出力が確認できない、フレームワーク構造で迷う。\n\n## AI への依頼例\n```text\n今は「最初のプロジェクト作成と AI への依頼の基本」を進めています。\n目的: 空の状態からプロジェクト作成と最初の依頼までを、詰まらずに一周できます。\n現状: 最初のプロジェクトを作り、AI へ何をどこまで頼むかを具体的な依頼文の形に落とします。\n今回残したい成果物: 最初のプロジェクト作成メモ、基本プロンプトひな形\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- 最初の依頼文を 1 つ書けて、AI の出力を確認できていること。\n\n## 関連キーワード\n- `first project with ai coding tool`\n- `basic ai coding prompt`\n- `create project with claude code codex`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('e6ca3afa-ecec-543c-bbaa-0fa882681a75', 'a96a7681-c052-5e04-b3e2-c95ee172118a', 'callout', 4, '{"variant":"warning","text":"依頼の粒度が大きすぎて AI の出力が確認できない、フレームワーク構造で迷う。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('9c2acfa9-c46f-5ad3-8de9-01d5076e4ba7', 'a96a7681-c052-5e04-b3e2-c95ee172118a', 'rubric', 5, '{"criteria":"最初の依頼文を 1 つ書けて、AI の出力を確認できていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('05751b0f-ab7c-54b7-bdfe-8c8b7a01381f', 'a96a7681-c052-5e04-b3e2-c95ee172118a', 'image', 6, '{"url":"/lesson-assets/lesson_web_builder_046_first_project_and_basic_ai_requests/first-prompt-example.png","alt":"AI coding toolへの最初の依頼文テンプレート（goal・現在の状態・やりたいことの3要素）","caption":"最初の AI 依頼文の書き方。goal、現在の状態、やりたいことの 3 要素を含むプロンプト例です。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('9d49397b-f9b9-57fc-bf10-c512bd83da1c', 'a96a7681-c052-5e04-b3e2-c95ee172118a', 'image', 7, '{"url":"/lesson-assets/lesson_web_builder_046_first_project_and_basic_ai_requests/project-creation-flow.png","alt":"プロジェクト作成から最初のAI依頼までの4ステップフロー図","caption":"プロジェクト作成から最初の依頼までのフロー図。ディレクトリ作成 → AI 起動 → 依頼 → 確認の一連を示します。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('b80ddddd-4ab8-5d13-ad54-11f08de8eb4b', '3e297a67-c66c-543f-a729-99f253323426', 'markdown', 0, '{"text":"CLI 導入時に起こりやすい失敗を、原因の切り分けと再確認手順で整理します。","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('fdd3a770-1249-5f79-96be-d273be916ca3', '3e297a67-c66c-543f-a729-99f253323426', 'callout', 1, '{"variant":"why","text":"インストール失敗で止まると先に進めません。典型パターンを知っておくと自力で復帰できます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('81480b7c-521b-5e03-83e5-e8782936f883', '3e297a67-c66c-543f-a729-99f253323426', 'markdown', 2, '{"text":"権限エラー・PATH 未設定・Node.js バージョン不一致・認証失敗の 4 パターンを確認し、各対処法を実行します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('fc9756ba-22e4-5cd1-af5e-54e7a5a4f3c1', '3e297a67-c66c-543f-a729-99f253323426', 'markdown', 3, '{"text":"# よくあるインストール失敗と対処\n\nCLI 導入時に起こりやすい失敗を、原因の切り分けと再確認手順で整理します。\n\n## このレッスンのゴール\n権限、PATH、Node.js、認証まわりの典型トラブルを自分で潰せるようになります。\n\n## 先に把握しておくこと\n- モジュール: **Setup the Workspace**\n- 想定時間: **20 分**\n- 到達したい状態: install_failure_recovery_understood\n\n## なぜ今やるのか\nインストール失敗で止まると先に進めません。典型パターンを知っておくと自力で復帰できます。\n\n## 進め方\n1. 権限エラー・PATH 未設定・Node.\n2. js バージョン不一致・認証失敗の 4 パターンを確認し、各対処法を実行します。\n\n## このレッスンで残すもの\n- トラブルシュートチェックリスト\n\n## 詰まりやすいポイント\n- エラーメッセージを読まずに再実行を繰り返す、環境差異に気付かない。\n\n## AI への依頼例\n```text\n今は「よくあるインストール失敗と対処」を進めています。\n目的: 権限、PATH、Node.js、認証まわりの典型トラブルを自分で潰せるようになります。\n現状: CLI 導入時に起こりやすい失敗を、原因の切り分けと再確認手順で整理します。\n今回残したい成果物: トラブルシュートチェックリスト\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- 典型的な失敗原因を 2 つ以上切り分けられること。\n\n## 関連キーワード\n- `claude code install failure`\n- `codex install failure`\n- `cli path issue fix`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('0155d820-c88e-5ec3-aea1-be2c8c66d75d', '3e297a67-c66c-543f-a729-99f253323426', 'callout', 4, '{"variant":"warning","text":"エラーメッセージを読まずに再実行を繰り返す、環境差異に気付かない。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('ec9eafdf-51bf-5d7f-a947-48045bc6c983', '3e297a67-c66c-543f-a729-99f253323426', 'rubric', 5, '{"criteria":"典型的な失敗原因を 2 つ以上切り分けられること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c659de83-ea5d-5f2e-88d4-e6a8c312f0d5', '3e297a67-c66c-543f-a729-99f253323426', 'image', 6, '{"url":"/lesson-assets/lesson_web_builder_047_common_install_failures_and_fixes/troubleshoot-flowchart.png","alt":"CLIインストール失敗時のトラブルシュートフローチャート（権限、PATH、Node.js、認証の順）","caption":"インストール失敗時の切り分けフローチャート。権限エラー → PATH 問題 → Node.js バージョン → 認証失敗の順に確認します。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('1a02b90c-8fa4-5ff1-9959-bbf12e54992e', 'ad01b1c4-b233-5cfd-ab58-2ffe76dd4c98', 'markdown', 0, '{"text":"Node.js と pnpm を CLI で導入し、バージョン確認まで通して開発の前提を揃えます。各 OS で PATH や実行結果を確認しながら詰まりやすい点も潰します。","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('5b8682c4-5a81-5ba1-9a5c-224ae1a3faab', 'ad01b1c4-b233-5cfd-ab58-2ffe76dd4c98', 'callout', 1, '{"variant":"why","text":"Node.js と pnpm はこのトラック全体の土台です。ここが不安定だと、以降のすべてのステップで問題が起きます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c030bf91-bf4c-52e1-a232-85c0e87da900', 'ad01b1c4-b233-5cfd-ab58-2ffe76dd4c98', 'markdown', 2, '{"text":"OS に合った方法で Node.js をインストールし、corepack または npm で pnpm を有効化、バージョン確認で動作を検証します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('86f2e108-cfbb-5b1f-b5db-f6ed5e8924cc', 'ad01b1c4-b233-5cfd-ab58-2ffe76dd4c98', 'markdown', 3, '{"text":"# Node.js と pnpm を CLI でセットアップする\n\nNode.js と pnpm を CLI で導入し、バージョン確認まで通して開発の前提を揃えます。各 OS で PATH や実行結果を確認しながら詰まりやすい点も潰します。\n\n## このレッスンのゴール\n次の Next.js セットアップに入る前に、Node.js と pnpm が迷わず使える状態になります。\n\n## 先に把握しておくこと\n- モジュール: **Setup the Workspace**\n- 想定時間: **20 分**\n- 到達したい状態: node_and_pnpm_cli_ready\n\n## なぜ今やるのか\nNode.js と pnpm はこのトラック全体の土台です。ここが不安定だと、以降のすべてのステップで問題が起きます。\n\n## 進め方\n1. OS に合った方法で Node.\n2. js をインストールし、corepack または npm で pnpm を有効化、バージョン確認で動作を検証します。\n\n## このレッスンで残すもの\n- Node.js セットアップ完了\n- pnpm セットアップ完了\n- バージョン確認結果\n\n## 詰まりやすいポイント\n- PATH が通らない、corepack が無効、OS ごとのインストール手順の違い。\n\n## AI への依頼例\n```text\n今は「Node.js と pnpm を CLI でセットアップする」を進めています。\n目的: 次の Next.js セットアップに入る前に、Node.js と pnpm が迷わず使える状態になります。\n現状: Node.js と pnpm を CLI で導入し、バージョン確認まで通して開発の前提を揃えます。各 OS で PATH や実行結果を確認しながら詰まりやすい点も潰します。\n今回残したい成果物: Node.js セットアップ完了、pnpm セットアップ完了、バージョン確認結果\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- `node -v` と `pnpm -v` が通り、PATH の問題を自分で確認できること。\n\n## 関連キーワード\n- `node setup cli`\n- `pnpm setup cli`\n- `node pnpm version check`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('8befb980-bc58-5925-aa03-ca1b1c08c7ad', 'ad01b1c4-b233-5cfd-ab58-2ffe76dd4c98', 'callout', 4, '{"variant":"warning","text":"PATH が通らない、corepack が無効、OS ごとのインストール手順の違い。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('8c6442a2-132f-53ef-a7d5-7ff8adff6107', 'ad01b1c4-b233-5cfd-ab58-2ffe76dd4c98', 'rubric', 5, '{"criteria":"`node -v` と `pnpm -v` が通り、PATH の問題を自分で確認できること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('a1950d16-39e1-5575-8627-7c2cfa9e93e7', 'ad01b1c4-b233-5cfd-ab58-2ffe76dd4c98', 'image', 6, '{"url":"/lesson-assets/lesson_web_builder_048_node_pnpm_setup/node-pnpm-verify.png","alt":"ターミナルでnode -vとpnpm -vを実行した結果のスクリーンショット","caption":"Node.js と pnpm のバージョン確認スクリーンショット。`node -v` と `pnpm -v` の期待される出力を示します。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('7cb70314-08fc-585c-81f8-08f9e16081c5', 'c05c886b-b14d-5d4c-a8b7-253076cec03d', 'markdown', 0, '{"text":"Git の基本設定と GitHub 連携を CLI で確認し、commit・push に進める土台を作ります。認証方式と初回の確認手順も整理します。","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('ede180e3-d67c-5d44-9c4f-329bd57c4248', 'c05c886b-b14d-5d4c-a8b7-253076cec03d', 'callout', 1, '{"variant":"why","text":"Git が使えないとコードの変更管理ができず、AI の変更を元に戻すこともできません。バージョン管理は安全網です。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('770ff8c0-5a81-54b6-9d40-0c008e9b4a9f', 'c05c886b-b14d-5d4c-a8b7-253076cec03d', 'markdown', 2, '{"text":"Git の初期設定（user.name, user.email）を行い、GitHub への認証方式を選んで接続確認します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('bcf29c54-c3a5-56e7-872d-749e765dfa35', 'c05c886b-b14d-5d4c-a8b7-253076cec03d', 'markdown', 3, '{"text":"# Git / GitHub を CLI で使える状態にする\n\nGit の基本設定と GitHub 連携を CLI で確認し、commit・push に進める土台を作ります。認証方式と初回の確認手順も整理します。\n\n## このレッスンのゴール\nローカル変更を安全に記録し、GitHub へ送る基本操作を CLI で再現できるようになります。\n\n## 先に把握しておくこと\n- モジュール: **Setup the Workspace**\n- 想定時間: **20 分**\n- 到達したい状態: git_and_github_cli_ready\n\n## なぜ今やるのか\nGit が使えないとコードの変更管理ができず、AI の変更を元に戻すこともできません。バージョン管理は安全網です。\n\n## 進め方\n1. Git の初期設定（user.\n2. name, user.\n3. email）を行い、GitHub への認証方式を選んで接続確認します。\n\n## このレッスンで残すもの\n- Git 初期設定確認\n- GitHub CLI または認証確認\n- commit/push 前提チェック\n\n## 詰まりやすいポイント\n- Git 未設定、GitHub 認証方式の選択で迷う、SSH 鍵の設定ミス。\n\n## AI への依頼例\n```text\n今は「Git / GitHub を CLI で使える状態にする」を進めています。\n目的: ローカル変更を安全に記録し、GitHub へ送る基本操作を CLI で再現できるようになります。\n現状: Git の基本設定と GitHub 連携を CLI で確認し、commit・push に進める土台を作ります。認証方式と初回の確認手順も整理します。\n今回残したい成果物: Git 初期設定確認、GitHub CLI または認証確認、commit/push 前提チェック\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- `git config` の主要設定を確認でき、GitHub へ接続する方法を 1 つ説明できること。\n\n## 関連キーワード\n- `git setup cli`\n- `github cli auth`\n- `git config github push`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('02ecc589-4e30-5ecc-a078-5af05810548e', 'c05c886b-b14d-5d4c-a8b7-253076cec03d', 'callout', 4, '{"variant":"warning","text":"Git 未設定、GitHub 認証方式の選択で迷う、SSH 鍵の設定ミス。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('db005040-f00c-59d7-b882-6c2c689a9bfc', 'c05c886b-b14d-5d4c-a8b7-253076cec03d', 'rubric', 5, '{"criteria":"`git config` の主要設定を確認でき、GitHub へ接続する方法を 1 つ説明できること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('ea8f1677-d637-5e44-9d12-393ad30c2cdd', 'c05c886b-b14d-5d4c-a8b7-253076cec03d', 'image', 6, '{"url":"/lesson-assets/lesson_web_builder_049_git_github_cli/git-setup-checklist.png","alt":"Git初期設定とGitHub認証の確認チェックリスト","caption":"Git / GitHub 設定の確認チェックリスト。`git config`、SSH or HTTPS 認証、`gh auth status` を確認します。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('26c28018-7c7c-537a-a443-9673a64c2361', 'c13692b7-8a09-5c05-b560-dc0e6f5a10da', 'markdown', 0, '{"text":"Initialize the app and get the local server running.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('7cb1be4a-c7e1-5bc3-b127-328246bfb1d5', 'c13692b7-8a09-5c05-b560-dc0e6f5a10da', 'callout', 1, '{"variant":"why","text":"ローカルで動くアプリがないと、UI 実装もデータ連携も始められません。最初の土台を確実に作ることが全体の起点です。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('bc693fcd-fa5f-5785-a5b1-2c0583bb3432', 'c13692b7-8a09-5c05-b560-dc0e6f5a10da', 'markdown', 2, '{"text":"`pnpm create next-app` でプロジェクトを生成し、`pnpm dev` でローカルサーバーを起動して初期画面を確認します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('242c8423-281d-516d-a7d4-a0800bc7fb0d', 'c13692b7-8a09-5c05-b560-dc0e6f5a10da', 'markdown', 3, '{"text":"# Create the Next.js app\n\nInitialize the app and get the local server running.\n\n## このレッスンのゴール\nYou will have a working Next.js project as the base for the track.\n\n## 先に把握しておくこと\n- モジュール: **Setup the Workspace**\n- 想定時間: **30 分**\n- 到達したい状態: local_next_app_running\n\n## なぜ今やるのか\nローカルで動くアプリがないと、UI 実装もデータ連携も始められません。最初の土台を確実に作ることが全体の起点です。\n\n## 進め方\n1. `pnpm create next-app` でプロジェクトを生成し、`pnpm dev` でローカルサーバーを起動して初期画面を確認します。\n\n## このレッスンで残すもの\n- Next.js app created\n- Dev server running\n\n## 詰まりやすいポイント\n- 依存インストールの失敗、ポート競合で dev サーバーが起動しない。\n\n## AI への依頼例\n```text\n今は「Create the Next.js app」を進めています。\n目的: You will have a working Next.js project as the base for the track.\n現状: Initialize the app and get the local server running.\n今回残したい成果物: Next.js app created、Dev server running\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- ローカルで `pnpm dev` が起動し、app router の初期画面がブラウザに表示されること。\n\n## 関連キーワード\n- `create next.js app`\n- `run dev server`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('ae494659-f530-5a58-b38a-f44800bad84c', 'c13692b7-8a09-5c05-b560-dc0e6f5a10da', 'callout', 4, '{"variant":"warning","text":"依存インストールの失敗、ポート競合で dev サーバーが起動しない。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('fcfe8231-c94c-5049-8e89-6a896a4a6431', 'c13692b7-8a09-5c05-b560-dc0e6f5a10da', 'rubric', 5, '{"criteria":"ローカルで `pnpm dev` が起動し、app router の初期画面がブラウザに表示されること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('93d95f15-879f-57da-a8d7-cfb3d8a9eaba', 'c13692b7-8a09-5c05-b560-dc0e6f5a10da', 'image', 6, '{"url":"/lesson-assets/lesson_web_builder_050_create_next_app/create-next-app-terminal.png","alt":"ターミナルでpnpm create next-appを実行し、設定項目を選択する画面のスクリーンショット","caption":"`pnpm create next-app` の実行結果。プロジェクト名、TypeScript、App Router などの選択肢が表示されます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('1d7c8c3b-5971-515d-bb3d-cebd2c068c77', 'c13692b7-8a09-5c05-b560-dc0e6f5a10da', 'image', 7, '{"url":"/lesson-assets/lesson_web_builder_050_create_next_app/dev-server-running.png","alt":"Next.jsの初期画面がlocalhost:3000で表示されているブラウザのスクリーンショット","caption":"`pnpm dev` でローカルサーバーが起動した状態。ブラウザで localhost:3000 を開いた初期画面です。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('29ca2f39-a90e-5230-8ce6-8b12fdbdd327', '2c4f7b45-1ef7-5ec1-9cb0-8598bcb709c5', 'markdown', 0, '{"text":"Supabase プロジェクト、接続情報、最初のテーブル方針を揃え、AI が安全に触れる前提を作ります。","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('44ccc17b-09cb-5121-b364-0e5a01906c7d', '2c4f7b45-1ef7-5ec1-9cb0-8598bcb709c5', 'callout', 1, '{"variant":"why","text":"AI に DB 設計を丸投げすると、大きすぎるスキーマや不要なテーブルが作られます。前提を整理してから頼むと精度が上がります。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('4011ffd1-3dac-5319-b7fe-4a45f17553f5', '2c4f7b45-1ef7-5ec1-9cb0-8598bcb709c5', 'markdown', 2, '{"text":"Supabase プロジェクト作成→接続情報を .env.local に配置→最初の schema 方針を 3-5 行で書きます。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('cea8e706-39b4-5623-bcc7-41d1de0bb892', '2c4f7b45-1ef7-5ec1-9cb0-8598bcb709c5', 'markdown', 3, '{"text":"# Supabaseを導入してAIから扱いやすい状態にする\n\nSupabase プロジェクト、接続情報、最初のテーブル方針を揃え、AI が安全に触れる前提を作ります。\n\n## このレッスンのゴール\nAI に DB まわりの実装を頼む前に、プロジェクト URL・anon key・schema 方針・命名ルールを 1 セットで説明できるようになります。\n\n## 先に把握しておくこと\n- モジュール: **Add Real Data**\n- 想定時間: **35 分**\n- 到達したい状態: supabase_ai_ready\n\n## なぜ今やるのか\nAI に DB 設計を丸投げすると、大きすぎるスキーマや不要なテーブルが作られます。前提を整理してから頼むと精度が上がります。\n\n## 進め方\n1. Supabase プロジェクト作成→接続情報を .\n2. env.\n3. local に配置→最初の schema 方針を 3-5 行で書きます。\n\n## このレッスンで残すもの\n- Supabase プロジェクト作成完了\n- 接続情報メモ\n- 最初の schema 方針メモ\n\n## 詰まりやすいポイント\n- 接続先が未確定のまま進む、環境変数の設定漏れ、schema を大きくしすぎる。\n\n## AI への依頼例\n```text\n今は「Supabaseを導入してAIから扱いやすい状態にする」を進めています。\n目的: AI に DB まわりの実装を頼む前に、プロジェクト URL・anon key・schema 方針・命名ルールを 1 セットで説明できるようになります。\n現状: Supabase プロジェクト、接続情報、最初のテーブル方針を揃え、AI が安全に触れる前提を作ります。\n今回残したい成果物: Supabase プロジェクト作成完了、接続情報メモ、最初の schema 方針メモ\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- project URL と anon key の置き場を説明でき、AI に渡す schema 方針を 3 行程度で書けること。\n\n## 関連キーワード\n- `supabase setup for ai coding`\n- `supabase project env schema prompt`\n- `supabase ai ready`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('3176c884-ca46-5781-8e5b-3554f93e9fad', '2c4f7b45-1ef7-5ec1-9cb0-8598bcb709c5', 'callout', 4, '{"variant":"warning","text":"接続先が未確定のまま進む、環境変数の設定漏れ、schema を大きくしすぎる。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('1962dd43-9d23-5eaa-9ad8-0ced419d9f98', '2c4f7b45-1ef7-5ec1-9cb0-8598bcb709c5', 'rubric', 5, '{"criteria":"project URL と anon key の置き場を説明でき、AI に渡す schema 方針を 3 行程度で書けること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('1d71ffe3-9663-5dea-a7d0-00bd0ce8bd46', 'd533cac9-857c-5f36-a863-4155fddf9975', 'markdown', 0, '{"text":"AI が実装した Next.js アプリを Vercel へ接続し、環境変数と build の確認まで一気に通します。","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('eb3ee1da-d070-5027-b9b1-41a331dcb0eb', 'd533cac9-857c-5f36-a863-4155fddf9975', 'callout', 1, '{"variant":"why","text":"早めに公開導線に乗せることで、ローカルだけでは見つからない問題を発見でき、AI と build error を往復しながら仕上げられます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('6e30ffcd-fc3a-5129-bc66-c550e7e406ec', 'd533cac9-857c-5f36-a863-4155fddf9975', 'markdown', 2, '{"text":"GitHub repo を Vercel に接続→環境変数を設定→初回デプロイ→build log を確認して問題があれば AI に渡します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('06205aef-2572-50c4-8732-5dcf80c32a44', 'd533cac9-857c-5f36-a863-4155fddf9975', 'markdown', 3, '{"text":"# AIが作ったアプリをVercelにデプロイする\n\nAI が実装した Next.js アプリを Vercel へ接続し、環境変数と build の確認まで一気に通します。\n\n## このレッスンのゴール\nGitHub 連携から最初の production deploy、失敗時の切り分けまでを AI と往復しながら進められます。\n\n## 先に把握しておくこと\n- モジュール: **Ship It**\n- 想定時間: **35 分**\n- 到達したい状態: ai_app_deployed_to_vercel\n\n## なぜ今やるのか\n早めに公開導線に乗せることで、ローカルだけでは見つからない問題を発見でき、AI と build error を往復しながら仕上げられます。\n\n## 進め方\n1. GitHub repo を Vercel に接続→環境変数を設定→初回デプロイ→build log を確認して問題があれば AI に渡します。\n\n## このレッスンで残すもの\n- Vercel プロジェクト接続完了\n- 環境変数チェックリスト\n- 公開 URL\n\n## 詰まりやすいポイント\n- 本番用 env の不足、Vercel 環境変数の未設定、ビルド失敗。\n\n## AI への依頼例\n```text\n今は「AIが作ったアプリをVercelにデプロイする」を進めています。\n目的: GitHub 連携から最初の production deploy、失敗時の切り分けまでを AI と往復しながら進められます。\n現状: AI が実装した Next.js アプリを Vercel へ接続し、環境変数と build の確認まで一気に通します。\n今回残したい成果物: Vercel プロジェクト接続完了、環境変数チェックリスト、公開 URL\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- Vercel に GitHub repo を接続でき、deploy 後に build log を見て 1 回は検証できること。\n\n## 関連キーワード\n- `deploy ai app to vercel`\n- `vercel github nextjs deployment`\n- `vercel production env ai coding`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('0a1c7efd-7162-58ac-ba51-333b0af4bfba', 'd533cac9-857c-5f36-a863-4155fddf9975', 'callout', 4, '{"variant":"warning","text":"本番用 env の不足、Vercel 環境変数の未設定、ビルド失敗。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('7abfd624-1d20-5ab3-9aa7-3a971cd5f7e4', 'd533cac9-857c-5f36-a863-4155fddf9975', 'rubric', 5, '{"criteria":"Vercel に GitHub repo を接続でき、deploy 後に build log を見て 1 回は検証できること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('e0b2b9b8-603f-5014-958e-7c372e8a7ffd', '628c7294-2988-5576-bbd6-aea9a8a8cd8e', 'markdown', 0, '{"text":"Push the repo early and work in a way that keeps AI-assisted changes safe.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('79eeeee2-1242-5b85-a599-e91a1fc5f79f', '628c7294-2988-5576-bbd6-aea9a8a8cd8e', 'callout', 1, '{"variant":"why","text":"リモートリポジトリなしだと AI の変更を安全に戻せません。早めに push しておくことでバックアップと共有の基盤ができます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('128b1463-b942-5f3f-9111-362cf3adf906', '628c7294-2988-5576-bbd6-aea9a8a8cd8e', 'markdown', 2, '{"text":"GitHub にリポジトリを作成し、ローカルの変更を commit して push します。ブランチ運用の基本も確認します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('8dd74d0e-894f-5f8b-abc3-7e422ec981bf', '628c7294-2988-5576-bbd6-aea9a8a8cd8e', 'markdown', 3, '{"text":"# Publish the repository and establish version-control habits\n\nPush the repo early and work in a way that keeps AI-assisted changes safe.\n\n## このレッスンのゴール\nYour project will have a reliable source of truth before the build grows.\n\n## 先に把握しておくこと\n- モジュール: **Setup the Workspace**\n- 想定時間: **25 分**\n- 到達したい状態: repository_published\n\n## なぜ今やるのか\nリモートリポジトリなしだと AI の変更を安全に戻せません。早めに push しておくことでバックアップと共有の基盤ができます。\n\n## 進め方\n1. GitHub にリポジトリを作成し、ローカルの変更を commit して push します。\n2. ブランチ運用の基本も確認します。\n\n## このレッスンで残すもの\n- Git repository created\n- Remote repo published\n\n## 詰まりやすいポイント\n- Git が未設定、リモート URL の設定ミス。\n\n## AI への依頼例\n```text\n今は「Publish the repository and establish version-control habits」を進めています。\n目的: Your project will have a reliable source of truth before the build grows.\n現状: Push the repo early and work in a way that keeps AI-assisted changes safe.\n今回残したい成果物: Git repository created、Remote repo published\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- GitHub にリポジトリが公開され、ローカルから push できること。\n\n## 関連キーワード\n- `publish repo`\n- `push github repo`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('7b947f85-3e27-5e72-b93e-963f94f21d33', '628c7294-2988-5576-bbd6-aea9a8a8cd8e', 'callout', 4, '{"variant":"warning","text":"Git が未設定、リモート URL の設定ミス。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('f44078d6-4542-5baa-9ad8-6af3b8cf5fe1', '628c7294-2988-5576-bbd6-aea9a8a8cd8e', 'rubric', 5, '{"criteria":"GitHub にリポジトリが公開され、ローカルから push できること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('286bc372-bf23-5def-838a-1fb16d594fa4', 'ec1b56e2-f162-52e7-808c-d69e37c7ab96', 'markdown', 0, '{"text":"Map the important files so you know where future lessons will land.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('3a9c7fc0-8c26-5968-bbd8-666f20196e29', 'ec1b56e2-f162-52e7-808c-d69e37c7ab96', 'callout', 1, '{"variant":"why","text":"プロジェクト構造が分からないと、AI に指示を出すときにどのファイルを指せばいいか分かりません。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('84b319d7-dd81-5269-9c14-ae94870c12da', 'ec1b56e2-f162-52e7-808c-d69e37c7ab96', 'markdown', 2, '{"text":"app/ ディレクトリ、layout.tsx、page.tsx の役割を確認し、今後触るフォルダだけをメモします。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('fd673498-500c-54d7-a59b-89e20d93984c', 'ec1b56e2-f162-52e7-808c-d69e37c7ab96', 'markdown', 3, '{"text":"# Read the generated project structure without getting lost\n\nMap the important files so you know where future lessons will land.\n\n## このレッスンのゴール\nYou will understand the parts of the project you actually need right now.\n\n## 先に把握しておくこと\n- モジュール: **Setup the Workspace**\n- 想定時間: **20 分**\n- 到達したい状態: project_structure_understood\n\n## なぜ今やるのか\nプロジェクト構造が分からないと、AI に指示を出すときにどのファイルを指せばいいか分かりません。\n\n## 進め方\n1. app/ ディレクトリ、layout.\n2. tsx、page.\n3. tsx の役割を確認し、今後触るフォルダだけをメモします。\n\n## このレッスンで残すもの\n- File map\n- Key folders explained\n\n## 詰まりやすいポイント\n- Next.\n- js の app router 構造に圧倒される、不要なファイルまで理解しようとする。\n\n## AI への依頼例\n```text\n今は「Read the generated project structure without getting lost」を進めています。\n目的: You will understand the parts of the project you actually need right now.\n現状: Map the important files so you know where future lessons will land.\n今回残したい成果物: File map、Key folders explained\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- 重要なフォルダとファイルの役割を説明できること。\n\n## 関連キーワード\n- `next.js project structure`\n- `app router basics`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('2c9bd31a-0a1e-5cf3-be21-85058c42cba9', 'ec1b56e2-f162-52e7-808c-d69e37c7ab96', 'callout', 4, '{"variant":"warning","text":"Next.js の app router 構造に圧倒される、不要なファイルまで理解しようとする。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('36fe1075-e1fb-5947-bf01-b25a3154f39e', 'ec1b56e2-f162-52e7-808c-d69e37c7ab96', 'rubric', 5, '{"criteria":"重要なフォルダとファイルの役割を説明できること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c1f0f690-946c-5366-a5a3-c06b99966bbf', 'c567cb4f-7267-50ae-9eef-9fe32eabd49f', 'markdown', 0, '{"text":"Confirm styling primitives are working so design changes are fast.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('febf84bb-d74b-5ca8-8faf-623b13da09cf', 'c567cb4f-7267-50ae-9eef-9fe32eabd49f', 'callout', 1, '{"variant":"why","text":"Tailwind が動いていないと、この先の UI 実装がすべて手書き CSS になり速度が落ちます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('f8597055-87f8-5df4-a149-45512b1130a7', 'c567cb4f-7267-50ae-9eef-9fe32eabd49f', 'markdown', 2, '{"text":"テスト用のクラスを適用して色や余白が反映されるか確認し、設定ファイルが正しいか検証します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('7de39b93-f342-50f6-a4af-ea419b29ca46', 'c567cb4f-7267-50ae-9eef-9fe32eabd49f', 'markdown', 3, '{"text":"# Verify Tailwind CSS in the project\n\nConfirm styling primitives are working so design changes are fast.\n\n## このレッスンのゴール\nYou will be able to style the project confidently with utility classes.\n\n## 先に把握しておくこと\n- モジュール: **Build the UI Foundation**\n- 想定時間: **20 分**\n- 到達したい状態: tailwind_verified\n\n## なぜ今やるのか\nTailwind が動いていないと、この先の UI 実装がすべて手書き CSS になり速度が落ちます。\n\n## 進め方\n1. テスト用のクラスを適用して色や余白が反映されるか確認し、設定ファイルが正しいか検証します。\n\n## このレッスンで残すもの\n- Tailwind styles visible\n\n## 詰まりやすいポイント\n- Tailwind の設定ファイルが間違っている、PostCSS の設定不備。\n\n## AI への依頼例\n```text\n今は「Verify Tailwind CSS in the project」を進めています。\n目的: You will be able to style the project confidently with utility classes.\n現状: Confirm styling primitives are working so design changes are fast.\n今回残したい成果物: Tailwind styles visible\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- ユーティリティクラスでスタイルが反映されることをブラウザで確認できること。\n\n## 関連キーワード\n- `verify tailwind css`\n- `tailwind in next.js`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('a4874430-1875-5f55-b48a-14ac0b777773', 'c567cb4f-7267-50ae-9eef-9fe32eabd49f', 'callout', 4, '{"variant":"warning","text":"Tailwind の設定ファイルが間違っている、PostCSS の設定不備。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('a39da8da-fa96-5a90-b40a-01320b2df6b0', 'c567cb4f-7267-50ae-9eef-9fe32eabd49f', 'rubric', 5, '{"criteria":"ユーティリティクラスでスタイルが反映されることをブラウザで確認できること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('ce1b2403-9076-5766-999e-aa3666788f91', 'c567cb4f-7267-50ae-9eef-9fe32eabd49f', 'code_prompt', 6, '{"exerciseId":"ex-tailwind-card","title":"Tailwind でカードコンポーネントを作ろう","instruction":"Tailwind CSS のユーティリティクラスを使って、丸みのある影付きカードを作成してください。bg-white, rounded-lg, shadow-md, p-6 クラスを使います。","language":"html","starterCode":"<div class=\"\">\n  <h2 class=\"\">カードタイトル</h2>\n  <p class=\"\">カードの説明文がここに入ります。</p>\n</div>","solutionHint":"div に bg-white rounded-lg shadow-md p-6 を、h2 に text-lg font-bold を、p に text-gray-600 mt-2 を追加します。","validationPatterns":["rounded-lg","shadow-md","p-6","bg-white"]}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('7741b40a-8e51-5582-a152-a6eae1188f6a', '209edd86-074c-5d6f-a00c-e2c17ed3d643', 'markdown', 0, '{"text":"Add reusable UI components that let you move quickly without losing quality.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('55fad65b-0cc8-5ef2-a1d5-3f02b93bc975', '209edd86-074c-5d6f-a00c-e2c17ed3d643', 'callout', 1, '{"variant":"why","text":"UI パーツを毎回ゼロから作ると時間がかかりすぎます。shadcn/ui を入れることで品質を保ちながら速く進めます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('4ba54821-1622-51b8-91fd-a20a4fa85fdd', '209edd86-074c-5d6f-a00c-e2c17ed3d643', 'markdown', 2, '{"text":"shadcn/ui の init コマンドを実行し、最初のコンポーネント（Button など）を追加して表示確認します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('9f596966-2670-55b2-882d-8eb9ec3ef63d', '209edd86-074c-5d6f-a00c-e2c17ed3d643', 'markdown', 3, '{"text":"# Install and configure shadcn/ui\n\nAdd reusable UI components that let you move quickly without losing quality.\n\n## このレッスンのゴール\nYou will have composable UI primitives ready for the first pages.\n\n## 先に把握しておくこと\n- モジュール: **Build the UI Foundation**\n- 想定時間: **35 分**\n- 到達したい状態: shadcn_installed\n\n## なぜ今やるのか\nUI パーツを毎回ゼロから作ると時間がかかりすぎます。shadcn/ui を入れることで品質を保ちながら速く進めます。\n\n## 進め方\n1. shadcn/ui の init コマンドを実行し、最初のコンポーネント（Button など）を追加して表示確認します。\n\n## このレッスンで残すもの\n- shadcn/ui configured\n- First reusable component added\n\n## 詰まりやすいポイント\n- CLI セットアップエラー、Tailwind との設定競合。\n\n## AI への依頼例\n```text\n今は「Install and configure shadcn/ui」を進めています。\n目的: You will have composable UI primitives ready for the first pages.\n現状: Add reusable UI components that let you move quickly without losing quality.\n今回残したい成果物: shadcn/ui configured、First reusable component added\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- shadcn/ui のコンポーネントが画面に表示され、スタイルが適用されていること。\n\n## 関連キーワード\n- `install shadcn ui`\n- `shadcn next.js setup`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('259516fc-8f65-5b9e-9c33-815b09a54e8c', '209edd86-074c-5d6f-a00c-e2c17ed3d643', 'callout', 4, '{"variant":"warning","text":"CLI セットアップエラー、Tailwind との設定競合。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('bd556bd4-8ed8-568b-a02f-3f60ba360c47', '209edd86-074c-5d6f-a00c-e2c17ed3d643', 'rubric', 5, '{"criteria":"shadcn/ui のコンポーネントが画面に表示され、スタイルが適用されていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('b54e1bc1-1359-581f-bbc0-919584fc9850', '0292c2b7-f25c-521a-9b43-bc8dfc767ca9', 'markdown', 0, '{"text":"Create the layout skeleton that makes the site feel like a real product.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('0abccd76-ae52-55f5-9835-9a87d889e749', '0292c2b7-f25c-521a-9b43-bc8dfc767ca9', 'callout', 1, '{"variant":"why","text":"共通レイアウトがないと、ページごとにナビゲーションを作り直すことになり、一貫性が崩れます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('2a87915e-67e2-5bbc-b0ab-b196f31728be', '0292c2b7-f25c-521a-9b43-bc8dfc767ca9', 'markdown', 2, '{"text":"layout.tsx に共通ヘッダー・ナビゲーション・フッターを配置し、全ページで共有される骨格を作ります。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d147c1e7-ba14-5bee-9a3b-44430cb239c7', '0292c2b7-f25c-521a-9b43-bc8dfc767ca9', 'markdown', 3, '{"text":"# Build the app shell, navigation, and layout\n\nCreate the layout skeleton that makes the site feel like a real product.\n\n## このレッスンのゴール\nYour site will have navigation and a reusable shell for all pages.\n\n## 先に把握しておくこと\n- モジュール: **Build the UI Foundation**\n- 想定時間: **40 分**\n- 到達したい状態: app_shell_built\n\n## なぜ今やるのか\n共通レイアウトがないと、ページごとにナビゲーションを作り直すことになり、一貫性が崩れます。\n\n## 進め方\n1. layout.\n2. tsx に共通ヘッダー・ナビゲーション・フッターを配置し、全ページで共有される骨格を作ります。\n\n## このレッスンで残すもの\n- Layout component\n- Navigation\n\n## 詰まりやすいポイント\n- 共通レイアウトが揃わない、ナビゲーションの構造で迷う。\n\n## AI への依頼例\n```text\n今は「Build the app shell, navigation, and layout」を進めています。\n目的: Your site will have navigation and a reusable shell for all pages.\n現状: Create the layout skeleton that makes the site feel like a real product.\n今回残したい成果物: Layout component、Navigation\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- ナビゲーションが全ページで共通表示され、レイアウトが一貫していること。\n\n## 関連キーワード\n- `build app shell`\n- `next.js layout navigation`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('1fd3ee87-a4b6-5c64-924a-4cfe09f89c22', '0292c2b7-f25c-521a-9b43-bc8dfc767ca9', 'callout', 4, '{"variant":"warning","text":"共通レイアウトが揃わない、ナビゲーションの構造で迷う。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('8a537293-b8be-5ba9-86dd-17736ea88fc0', '0292c2b7-f25c-521a-9b43-bc8dfc767ca9', 'rubric', 5, '{"criteria":"ナビゲーションが全ページで共通表示され、レイアウトが一貫していること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('68f75630-d477-5fde-86da-f2110497d3e0', '0292c2b7-f25c-521a-9b43-bc8dfc767ca9', 'code_prompt', 6, '{"exerciseId":"ex-layout-component","title":"Next.js の layout.tsx を書いてみよう","instruction":"Next.js の App Router で使う layout.tsx の基本構造を完成させてください。children を受け取り、ヘッダーとメインコンテンツ領域を含むレイアウトを作ります。","language":"tsx","starterCode":"export default function RootLayout({\n  children,\n}: {\n  children: React.ReactNode\n}) {\n  return (\n    <html lang=\"ja\">\n      <body>\n        {/* ここにヘッダーナビゲーションを追加 */}\n        <main>{children}</main>\n      </body>\n    </html>\n  )\n}","solutionHint":"body 内に <header> と <nav> を追加し、リンク要素でページ間のナビゲーションを実装します。","validationPatterns":["<header","<nav","children","RootLayout"]}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('11c7b963-0154-5f16-9c72-98fb1a2f0c16', '758b1cde-d3cc-5a97-9805-8a97acb5507a', 'markdown', 0, '{"text":"Design the first page around the promise and primary action.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('a15134df-b1b2-5bf7-aff6-e9e1d0105140', '758b1cde-d3cc-5a97-9805-8a97acb5507a', 'callout', 1, '{"variant":"why","text":"ホームページはユーザーが最初に見る画面です。ここで価値が伝わらないと離脱されます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('1ba5cc5b-f0ab-5192-9b08-2a48e64f89ba', '758b1cde-d3cc-5a97-9805-8a97acb5507a', 'markdown', 2, '{"text":"サイトの約束を見出しに、主要アクションを CTA ボタンに配置し、ファーストビューで価値を伝えます。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d6b63838-af4c-5b21-adee-68acfce1acd2', '758b1cde-d3cc-5a97-9805-8a97acb5507a', 'markdown', 3, '{"text":"# Create a homepage that communicates the product clearly\n\nDesign the first page around the promise and primary action.\n\n## このレッスンのゴール\nVisitors will understand what the site does and where to click first.\n\n## 先に把握しておくこと\n- モジュール: **Build the UI Foundation**\n- 想定時間: **35 分**\n- 到達したい状態: homepage_shipped\n\n## なぜ今やるのか\nホームページはユーザーが最初に見る画面です。ここで価値が伝わらないと離脱されます。\n\n## 進め方\n1. サイトの約束を見出しに、主要アクションを CTA ボタンに配置し、ファーストビューで価値を伝えます。\n\n## このレッスンで残すもの\n- Homepage built\n- Primary CTA added\n\n## 詰まりやすいポイント\n- トップページの訴求が弱い、情報を詰め込みすぎる。\n\n## AI への依頼例\n```text\n今は「Create a homepage that communicates the product clearly」を進めています。\n目的: Visitors will understand what the site does and where to click first.\n現状: Design the first page around the promise and primary action.\n今回残したい成果物: Homepage built、Primary CTA added\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- ホームページが完成し、主要 CTA が配置されていること。\n\n## 関連キーワード\n- `homepage design`\n- `product landing page`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d20a17b8-8758-5db9-94b8-bdc3a7d77b95', '758b1cde-d3cc-5a97-9805-8a97acb5507a', 'callout', 4, '{"variant":"warning","text":"トップページの訴求が弱い、情報を詰め込みすぎる。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('9353d8a7-f1b9-50b6-8679-f3363e47421f', '758b1cde-d3cc-5a97-9805-8a97acb5507a', 'rubric', 5, '{"criteria":"ホームページが完成し、主要 CTA が配置されていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('65b587e9-76be-528f-86cf-9a5c3165262d', '758b1cde-d3cc-5a97-9805-8a97acb5507a', 'code_prompt', 6, '{"exerciseId":"ex-hero-section","title":"ヒーローセクションを作ろう","instruction":"サイトのファーストビューとなるヒーローセクションを作成してください。大きな見出し、説明文、CTA ボタンを含めます。","language":"jsx","starterCode":"export default function HeroSection() {\n  return (\n    <section className=\"px-6 py-24 text-center\">\n      {/* 見出し・説明・CTAボタンを追加 */}\n    </section>\n  )\n}","solutionHint":"<h1> で大きな見出し、<p> で説明文、<button> または <a> で CTA ボタンを配置します。bg-blue-600 text-white rounded-lg px-6 py-3 などで目立つボタンにしましょう。","validationPatterns":["<h1","<button","className"]}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('251ef7f3-ba44-51b1-9e7e-691a741412a0', '7eabd5cb-8aa0-5557-816d-835b6392c031', 'markdown', 0, '{"text":"Extend the site beyond the homepage with another user-facing route.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('4e319972-a947-5511-be9b-8b30c185c912', '7eabd5cb-8aa0-5557-816d-835b6392c031', 'callout', 1, '{"variant":"why","text":"1 ページだけではサイトとして成立しません。2 ページ目を作ることで導線が生まれ、実用性が見えてきます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('64a29bda-1a5b-5609-8dda-02200b129dc2', '7eabd5cb-8aa0-5557-816d-835b6392c031', 'markdown', 2, '{"text":"MVP プランから次に必要なページを選び、app router にルートを追加して実装します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('1211ce11-41de-5599-9d3c-e0797d010e11', '7eabd5cb-8aa0-5557-816d-835b6392c031', 'markdown', 3, '{"text":"# Build a second page from the MVP plan\n\nExtend the site beyond the homepage with another user-facing route.\n\n## このレッスンのゴール\nYour product will stop feeling like a mockup and start feeling like a real website.\n\n## 先に把握しておくこと\n- モジュール: **Build the UI Foundation**\n- 想定時間: **30 分**\n- 到達したい状態: second_page_built\n\n## なぜ今やるのか\n1 ページだけではサイトとして成立しません。2 ページ目を作ることで導線が生まれ、実用性が見えてきます。\n\n## 進め方\n1. MVP プランから次に必要なページを選び、app router にルートを追加して実装します。\n\n## このレッスンで残すもの\n- Second page added\n\n## 詰まりやすいポイント\n- ページ間の一貫性が保てない、レイアウトの使い回しで迷う。\n\n## AI への依頼例\n```text\n今は「Build a second page from the MVP plan」を進めています。\n目的: Your product will stop feeling like a mockup and start feeling like a real website.\n現状: Extend the site beyond the homepage with another user-facing route.\n今回残したい成果物: Second page added\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- ページ目が追加され、ホームページからの導線が機能していること。\n\n## 関連キーワード\n- `add second page next.js`\n- `app router routes`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d84cb818-efc6-575c-b30b-f9d4a117786f', '7eabd5cb-8aa0-5557-816d-835b6392c031', 'callout', 4, '{"variant":"warning","text":"ページ間の一貫性が保てない、レイアウトの使い回しで迷う。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('138a0c16-dea8-5a22-803e-63af5d2cf643', '7eabd5cb-8aa0-5557-816d-835b6392c031', 'rubric', 5, '{"criteria":"2 ページ目が追加され、ホームページからの導線が機能していること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('9fc5e79b-f09a-5b25-9e79-97c506c662f8', '44e033ef-ab68-5ac2-a915-5f79849c97cc', 'markdown', 0, '{"text":"Apply a simple design system so the UI looks finished instead of random.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('629482c6-2b89-5f13-b83b-b37d1c2a7d5b', '44e033ef-ab68-5ac2-a915-5f79849c97cc', 'callout', 1, '{"variant":"why","text":"余白や文字サイズがバラバラだと、機能が揃っていても「雑」に見えて信頼感が下がります。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('4a32991d-0c00-5a5f-aa63-b6d5ca33e55c', '44e033ef-ab68-5ac2-a915-5f79849c97cc', 'markdown', 2, '{"text":"余白・文字サイズ・色の使い方を統一するルールを決め、全ページに適用します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c05adaea-b5a2-5707-8ef2-b5284af6ccb6', '44e033ef-ab68-5ac2-a915-5f79849c97cc', 'markdown', 3, '{"text":"# Make the UI feel consistent with spacing, typography, and states\n\nApply a simple design system so the UI looks finished instead of random.\n\n## このレッスンのゴール\nThe app will feel polished enough to share confidently.\n\n## 先に把握しておくこと\n- モジュール: **Build the UI Foundation**\n- 想定時間: **30 分**\n- 到達したい状態: ui_polished\n\n## なぜ今やるのか\n余白や文字サイズがバラバラだと、機能が揃っていても「雑」に見えて信頼感が下がります。\n\n## 進め方\n1. 余白・文字サイズ・色の使い方を統一するルールを決め、全ページに適用します。\n\n## このレッスンで残すもの\n- Consistent spacing\n- Type scale\n- State styles\n\n## 詰まりやすいポイント\n- 余白や文字組が不揃い、ページ間で異なるスタイリング。\n\n## AI への依頼例\n```text\n今は「Make the UI feel consistent with spacing, typography, and states」を進めています。\n目的: The app will feel polished enough to share confidently.\n現状: Apply a simple design system so the UI looks finished instead of random.\n今回残したい成果物: Consistent spacing、Type scale、State styles\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- 余白・タイプスケール・状態スタイルが全ページで一貫していること。\n\n## 関連キーワード\n- `ui consistency`\n- `tailwind spacing typography`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('ac5bc145-921b-556f-9021-a525da43acbd', '44e033ef-ab68-5ac2-a915-5f79849c97cc', 'callout', 4, '{"variant":"warning","text":"余白や文字組が不揃い、ページ間で異なるスタイリング。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('61f73cd5-ad48-54c4-8554-cbe4eb0c948b', '44e033ef-ab68-5ac2-a915-5f79849c97cc', 'rubric', 5, '{"criteria":"余白・タイプスケール・状態スタイルが全ページで一貫していること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('458e42a9-c097-5682-a4f9-4388d005b678', '0958eb1d-c057-5285-90fe-57ba5bd25259', 'markdown', 0, '{"text":"Spin up the backend service that will power real data or auth.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('91f609e4-9f1e-59c1-8e38-47152fe02eb2', '0958eb1d-c057-5285-90fe-57ba5bd25259', 'callout', 1, '{"variant":"why","text":"バックエンドサービスがないと、データの読み書きや認証が実装できません。Supabase プロジェクトが全てのデータ機能の起点です。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('b6da808c-766f-5723-8123-e57bf096ab33', '0958eb1d-c057-5285-90fe-57ba5bd25259', 'markdown', 2, '{"text":"Supabase ダッシュボードで新しいプロジェクトを作成し、リージョンとプロジェクト名を決めます。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('05acdaa8-80c1-50c5-9665-31302a7c8bd5', '0958eb1d-c057-5285-90fe-57ba5bd25259', 'markdown', 3, '{"text":"# Create the Supabase project\n\nSpin up the backend service that will power real data or auth.\n\n## このレッスンのゴール\nYou will have a Supabase project ready to connect to the app.\n\n## 先に把握しておくこと\n- モジュール: **Add Real Data**\n- 想定時間: **20 分**\n- 到達したい状態: supabase_project_created\n\n## なぜ今やるのか\nバックエンドサービスがないと、データの読み書きや認証が実装できません。Supabase プロジェクトが全てのデータ機能の起点です。\n\n## 進め方\n1. Supabase ダッシュボードで新しいプロジェクトを作成し、リージョンとプロジェクト名を決めます。\n\n## このレッスンで残すもの\n- Supabase project created\n\n## 詰まりやすいポイント\n- 接続先 URL が未確定のまま進む、リージョン選択で迷う。\n\n## AI への依頼例\n```text\n今は「Create the Supabase project」を進めています。\n目的: You will have a Supabase project ready to connect to the app.\n現状: Spin up the backend service that will power real data or auth.\n今回残したい成果物: Supabase project created\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- Supabase プロジェクトが作成され、ダッシュボードにアクセスできること。\n\n## 関連キーワード\n- `create supabase project`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('105cb803-48db-5598-addb-2cbfadfdcd48', '0958eb1d-c057-5285-90fe-57ba5bd25259', 'callout', 4, '{"variant":"warning","text":"接続先 URL が未確定のまま進む、リージョン選択で迷う。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('239babd5-cbd0-5ec1-b22b-47e2c22ea2ba', '0958eb1d-c057-5285-90fe-57ba5bd25259', 'rubric', 5, '{"criteria":"Supabase プロジェクトが作成され、ダッシュボードにアクセスできること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d40c7658-f98a-5642-80c2-847addbcb0a1', '0fb9397d-c3df-5c1d-9416-a127d004b878', 'markdown', 0, '{"text":"Supabase CLI を導入し、ログインやプロジェクト連携の確認まで進めます。ローカルで schema や migration を扱う準備を先に整えます。","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('9e4662d3-ccf2-5cc0-ba70-47a12f59898a', '0fb9397d-c3df-5c1d-9416-a127d004b878', 'callout', 1, '{"variant":"why","text":"CLI がないとマイグレーションやスキーマ管理がブラウザ操作だけになり、再現性が下がります。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('1d260ed6-01d1-5797-8b04-75c2e614d748', '0fb9397d-c3df-5c1d-9416-a127d004b878', 'markdown', 2, '{"text":"Supabase CLI をインストールし、ログインとプロジェクト連携の確認を行います。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('f9e179c4-ddc2-5b38-8e82-9f4bc0d020e1', '0fb9397d-c3df-5c1d-9416-a127d004b878', 'markdown', 3, '{"text":"# Supabase CLI をセットアップする\n\nSupabase CLI を導入し、ログインやプロジェクト連携の確認まで進めます。ローカルで schema や migration を扱う準備を先に整えます。\n\n## このレッスンのゴール\nSupabase の管理作業をブラウザ任せにせず、CLI から安全に進める土台ができます。\n\n## 先に把握しておくこと\n- モジュール: **Add Real Data**\n- 想定時間: **20 分**\n- 到達したい状態: supabase_cli_ready\n\n## なぜ今やるのか\nCLI がないとマイグレーションやスキーマ管理がブラウザ操作だけになり、再現性が下がります。\n\n## 進め方\n1. Supabase CLI をインストールし、ログインとプロジェクト連携の確認を行います。\n\n## このレッスンで残すもの\n- Supabase CLI セットアップ完了\n- 認証または接続確認\n\n## 詰まりやすいポイント\n- CLI セットアップエラー、認証トークンの取得失敗、プロジェクト連携の設定ミス。\n\n## AI への依頼例\n```text\n今は「Supabase CLI をセットアップする」を進めています。\n目的: Supabase の管理作業をブラウザ任せにせず、CLI から安全に進める土台ができます。\n現状: Supabase CLI を導入し、ログインやプロジェクト連携の確認まで進めます。ローカルで schema や migration を扱う準備を先に整えます。\n今回残したい成果物: Supabase CLI セットアップ完了、認証または接続確認\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- Supabase CLI のバージョン確認が通り、プロジェクト連携の前提条件を確認できること。\n\n## 関連キーワード\n- `supabase cli setup`\n- `supabase login cli`\n- `supabase link project`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c28fe4e0-eeed-5954-9e50-ee5fc08f6a3d', '0fb9397d-c3df-5c1d-9416-a127d004b878', 'callout', 4, '{"variant":"warning","text":"CLI セットアップエラー、認証トークンの取得失敗、プロジェクト連携の設定ミス。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('9aeaeba9-8bc3-5157-a0b0-3d98227b873f', '0fb9397d-c3df-5c1d-9416-a127d004b878', 'rubric', 5, '{"criteria":"Supabase CLI のバージョン確認が通り、プロジェクト連携の前提条件を確認できること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('dd681976-fcf1-51e6-9991-d0ba1c439890', '4a99881b-c521-58f0-ac6f-c2ff7f40a653', 'markdown', 0, '{"text":"Wire local credentials correctly without leaking them into the repository.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('14bd9b52-21ea-56ee-8e86-bd7a6d87ef96', '4a99881b-c521-58f0-ac6f-c2ff7f40a653', 'callout', 1, '{"variant":"why","text":"環境変数を間違えるとアプリが Supabase に繋がらず、正しく設定しないとシークレットが漏洩するリスクもあります。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('22899ae9-23b2-5f2c-800a-ccfc622f7516', '4a99881b-c521-58f0-ac6f-c2ff7f40a653', 'markdown', 2, '{"text":".env.local ファイルに Supabase の project URL と anon key を配置し、.gitignore で除外されていることを確認します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('26c668d6-c4dd-5204-89db-7fdbc94d21db', '4a99881b-c521-58f0-ac6f-c2ff7f40a653', 'markdown', 3, '{"text":"# Connect local environment variables safely\n\nWire local credentials correctly without leaking them into the repository.\n\n## このレッスンのゴール\nYour app will be able to talk to Supabase in local development.\n\n## 先に把握しておくこと\n- モジュール: **Add Real Data**\n- 想定時間: **25 分**\n- 到達したい状態: env_connected\n\n## なぜ今やるのか\n環境変数を間違えるとアプリが Supabase に繋がらず、正しく設定しないとシークレットが漏洩するリスクもあります。\n\n## 進め方\n1. .\n2. env.\n3. local ファイルに Supabase の project URL と anon key を配置し、.\n4. gitignore で除外されていることを確認します。\n\n## このレッスンで残すもの\n- Env file configured\n\n## 詰まりやすいポイント\n- 環境変数の設定漏れ、.\n- gitignore への追加忘れ、変数名の typo。\n\n## AI への依頼例\n```text\n今は「Connect local environment variables safely」を進めています。\n目的: Your app will be able to talk to Supabase in local development.\n現状: Wire local credentials correctly without leaking them into the repository.\n今回残したい成果物: Env file configured\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- アプリが Supabase に接続でき、.\n- env.\n- local がリポジトリに含まれていないこと。\n\n## 関連キーワード\n- `supabase env variables`\n- `next.js env setup`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('5e23e86e-1655-549b-9b2c-9395d3c4c9f2', '4a99881b-c521-58f0-ac6f-c2ff7f40a653', 'callout', 4, '{"variant":"warning","text":"環境変数の設定漏れ、.gitignore への追加忘れ、変数名の typo。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c14e34fb-d5a3-58dc-a7ed-37bd8463b983', '4a99881b-c521-58f0-ac6f-c2ff7f40a653', 'rubric', 5, '{"criteria":"アプリが Supabase に接続でき、.env.local がリポジトリに含まれていないこと。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('5cd5a414-d3b1-5ea7-959d-c53fee7db1c4', '53c362f4-1243-5acb-9fce-4045c9324fae', 'markdown', 0, '{"text":"Choose the minimal data model that supports the first real interaction.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('0e65c4c3-0763-57f1-97dc-c4ef88c664ae', '53c362f4-1243-5acb-9fce-4045c9324fae', 'callout', 1, '{"variant":"why","text":"データモデルを決めずにコードを書くと、後からテーブル構造の変更が大量に発生します。最初に最小限のモデルを決めることが重要です。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d837b12d-44ea-5921-97d3-59ef03c57e40', '53c362f4-1243-5acb-9fce-4045c9324fae', 'markdown', 2, '{"text":"最初の画面に必要なデータを洗い出し、1 テーブルに必要な最小カラムを定義します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('cd3039b4-89de-52fd-b22a-1f5c6a00f540', '53c362f4-1243-5acb-9fce-4045c9324fae', 'markdown', 3, '{"text":"# Design the first table or content model\n\nChoose the minimal data model that supports the first real interaction.\n\n## このレッスンのゴール\nYou will know what the app stores and why.\n\n## 先に把握しておくこと\n- モジュール: **Add Real Data**\n- 想定時間: **30 分**\n- 到達したい状態: first_table_designed\n\n## なぜ今やるのか\nデータモデルを決めずにコードを書くと、後からテーブル構造の変更が大量に発生します。最初に最小限のモデルを決めることが重要です。\n\n## 進め方\n1. 最初の画面に必要なデータを洗い出し、1 テーブルに必要な最小カラムを定義します。\n\n## このレッスンで残すもの\n- Data model defined\n\n## 詰まりやすいポイント\n- スキーマを大きくしすぎる、関連テーブルを最初から作りすぎる。\n\n## AI への依頼例\n```text\n今は「Design the first table or content model」を進めています。\n目的: You will know what the app stores and why.\n現状: Choose the minimal data model that supports the first real interaction.\n今回残したい成果物: Data model defined\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- データモデルが定義され、最初のテーブルが 1 つに絞られていること。\n\n## 関連キーワード\n- `design first table`\n- `supabase schema basics`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('e131aee4-cd48-5af3-a695-f5f0e05ef890', '53c362f4-1243-5acb-9fce-4045c9324fae', 'callout', 4, '{"variant":"warning","text":"スキーマを大きくしすぎる、関連テーブルを最初から作りすぎる。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('45e7466f-cce8-5a73-892b-73795264fa18', '53c362f4-1243-5acb-9fce-4045c9324fae', 'rubric', 5, '{"criteria":"データモデルが定義され、最初のテーブルが 1 つに絞られていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('bda0324a-c410-5f6d-a92c-f6c7286e46b9', '47d87914-5160-5ccd-bb2b-2f4c7f8880d3', 'markdown', 0, '{"text":"Fetch real records and render them in the app.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('784de9ce-b4d5-52c5-801a-8d5a20a60ebe', '47d87914-5160-5ccd-bb2b-2f4c7f8880d3', 'callout', 1, '{"variant":"why","text":"ハードコードされたデータではプロダクトとして成立しません。実データを表示できることで、サイトが本物になります。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('6fc2dece-59f7-5b9d-be94-f40981e66eef', '47d87914-5160-5ccd-bb2b-2f4c7f8880d3', 'markdown', 2, '{"text":"Supabase client を使ってテーブルからデータを取得し、コンポーネントでレンダリングします。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('87b77099-35cb-5c7e-88f7-ff1bfc8d5cb0', '47d87914-5160-5ccd-bb2b-2f4c7f8880d3', 'markdown', 3, '{"text":"# Read data from Supabase inside Next.js\n\nFetch real records and render them in the app.\n\n## このレッスンのゴール\nYour site will start showing live data instead of placeholders.\n\n## 先に把握しておくこと\n- モジュール: **Add Real Data**\n- 想定時間: **35 分**\n- 到達したい状態: data_read_working\n\n## なぜ今やるのか\nハードコードされたデータではプロダクトとして成立しません。実データを表示できることで、サイトが本物になります。\n\n## 進め方\n1. Supabase client を使ってテーブルからデータを取得し、コンポーネントでレンダリングします。\n\n## このレッスンで残すもの\n- Supabase read flow working\n\n## 詰まりやすいポイント\n- クエリの失敗、RLS ポリシーによるアクセス拒否、型の不一致。\n\n## AI への依頼例\n```text\n今は「Read data from Supabase inside Next.js」を進めています。\n目的: Your site will start showing live data instead of placeholders.\n現状: Fetch real records and render them in the app.\n今回残したい成果物: Supabase read flow working\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- 一覧または詳細画面で Supabase の実データが表示されること。\n\n## 関連キーワード\n- `read supabase data next.js`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('acac5cba-4639-5fe8-b9b2-f1776dd1e6ad', '47d87914-5160-5ccd-bb2b-2f4c7f8880d3', 'callout', 4, '{"variant":"warning","text":"クエリの失敗、RLS ポリシーによるアクセス拒否、型の不一致。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('de2cb89b-93a8-5eae-b6d1-ac2adb7f2ddb', '47d87914-5160-5ccd-bb2b-2f4c7f8880d3', 'rubric', 5, '{"criteria":"一覧または詳細画面で Supabase の実データが表示されること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('43dc3b1d-c41b-510b-89cb-45c7e4e3de33', '47d87914-5160-5ccd-bb2b-2f4c7f8880d3', 'code_prompt', 6, '{"exerciseId":"ex-supabase-query","title":"Supabase からデータを取得するコードを書こう","instruction":"Supabase クライアントを使って posts テーブルからデータを取得する Server Component を完成させてください。","language":"tsx","starterCode":"import { createClient } from ''@/lib/supabase/server''\n\nexport default async function PostList() {\n  const supabase = await createClient()\n\n  // TODO: posts テーブルから全レコードを取得\n  // const { data: posts } = await ...\n\n  return (\n    <ul>\n      {/* posts をリスト表示 */}\n    </ul>\n  )\n}","solutionHint":"supabase.from(''posts'').select(''*'') でデータ取得し、posts?.map() で各行を <li> に表示します。","validationPatterns":[".from(",".select(","posts","map("]}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('f038d3ef-7b9c-5a58-9c5b-8ae71ecd262e', '0f31a0ad-016f-508c-9184-c7fe77aa8215', 'markdown', 0, '{"text":"Add the first form or interaction that changes real backend data.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c2ca1df1-33fe-5893-b770-0d16331a832e', '0f31a0ad-016f-508c-9184-c7fe77aa8215', 'callout', 1, '{"variant":"why","text":"読み取りだけではインタラクティブなサイトになりません。データの書き込みができて初めて、ユーザーにとって価値のある機能になります。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('2a96fbb4-f6a1-5138-b54b-0df7cfa24d5c', '0f31a0ad-016f-508c-9184-c7fe77aa8215', 'markdown', 2, '{"text":"フォームを作成し、送信時に Supabase へデータを insert、結果を画面に反映します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('1f8bf347-6388-590d-aaa5-640ab25b11ba', '0f31a0ad-016f-508c-9184-c7fe77aa8215', 'markdown', 3, '{"text":"# Write data back through a user-facing flow\n\nAdd the first form or interaction that changes real backend data.\n\n## このレッスンのゴール\nThe site will have a meaningful end-to-end feature.\n\n## 先に把握しておくこと\n- モジュール: **Add Real Data**\n- 想定時間: **40 分**\n- 到達したい状態: data_write_working\n\n## なぜ今やるのか\n読み取りだけではインタラクティブなサイトになりません。データの書き込みができて初めて、ユーザーにとって価値のある機能になります。\n\n## 進め方\n1. フォームを作成し、送信時に Supabase へデータを insert、結果を画面に反映します。\n\n## このレッスンで残すもの\n- User-facing write flow\n\n## 詰まりやすいポイント\n- データ保存の失敗、入力検証の不足、RLS ポリシーの書き込み権限。\n\n## AI への依頼例\n```text\n今は「Write data back through a user-facing flow」を進めています。\n目的: The site will have a meaningful end-to-end feature.\n現状: Add the first form or interaction that changes real backend data.\n今回残したい成果物: User-facing write flow\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- フォーム送信でデータが保存され、保存結果を画面で確認できること。\n\n## 関連キーワード\n- `write supabase data next.js`\n- `submit form supabase`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('e4530168-431d-5ade-9760-97081e03ba17', '0f31a0ad-016f-508c-9184-c7fe77aa8215', 'callout', 4, '{"variant":"warning","text":"データ保存の失敗、入力検証の不足、RLS ポリシーの書き込み権限。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('45f28e85-eef9-5be2-a060-8f6630b81d0d', '0f31a0ad-016f-508c-9184-c7fe77aa8215', 'rubric', 5, '{"criteria":"フォーム送信でデータが保存され、保存結果を画面で確認できること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('e802623b-af2c-59e4-a9d4-4669e5d55570', '8a2c1cee-601f-5807-9922-e42ba83b4855', 'markdown', 0, '{"text":"Optional extension for projects that need accounts or private data.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('9e105af6-9eed-57cb-a2f5-6def64ae71a6', '8a2c1cee-601f-5807-9922-e42ba83b4855', 'callout', 1, '{"variant":"why","text":"ユーザーごとのデータ保護やパーソナライズが必要なプロジェクトでは、認証がないとセキュリティリスクになります。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('16fe0307-2d31-5776-8904-6d0670a6039f', '8a2c1cee-601f-5807-9922-e42ba83b4855', 'markdown', 2, '{"text":"Supabase Auth を設定し、サインイン/サインアウトの UI を追加、認証状態に応じた画面表示を実装します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d10ecf99-31f3-5776-8031-505269897d46', '8a2c1cee-601f-5807-9922-e42ba83b4855', 'markdown', 3, '{"text":"# Add user authentication with Supabase Auth\n\nOptional extension for projects that need accounts or private data.\n\n## このレッスンのゴール\nYou will know how to add sign-in without rebuilding the whole app.\n\n## 先に把握しておくこと\n- モジュール: **Add Real Data**\n- 想定時間: **40 分**\n- 到達したい状態: auth_extension_added\n\n## なぜ今やるのか\nユーザーごとのデータ保護やパーソナライズが必要なプロジェクトでは、認証がないとセキュリティリスクになります。\n\n## 進め方\n1. Supabase Auth を設定し、サインイン/サインアウトの UI を追加、認証状態に応じた画面表示を実装します。\n\n## このレッスンで残すもの\n- Auth flow added\n\n## 詰まりやすいポイント\n- 認証リダイレクトがループする、セッション管理の設定ミス。\n\n## AI への依頼例\n```text\n今は「Add user authentication with Supabase Auth」を進めています。\n目的: You will know how to add sign-in without rebuilding the whole app.\n現状: Optional extension for projects that need accounts or private data.\n今回残したい成果物: Auth flow added\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- サインイン・サインアウトが動作し、認証状態に応じた画面切替ができること。\n\n## 関連キーワード\n- `supabase auth next.js`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c3368ae1-437b-5e3f-aa1f-09d414ee9b70', '8a2c1cee-601f-5807-9922-e42ba83b4855', 'callout', 4, '{"variant":"warning","text":"認証リダイレクトがループする、セッション管理の設定ミス。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('e6ed0839-147c-50ae-bc22-9c138c84f50d', '8a2c1cee-601f-5807-9922-e42ba83b4855', 'rubric', 5, '{"criteria":"サインイン・サインアウトが動作し、認証状態に応じた画面切替ができること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('faf3539d-5e62-51d7-8f20-d75c5a7d7a63', 'f38fa474-06b9-582f-b6de-1ee68b0419a2', 'markdown', 0, '{"text":"Clean up obvious production issues before the first deployment attempt.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('fa75bbf6-64fa-51cf-96e2-13404e656ac5', 'f38fa474-06b9-582f-b6de-1ee68b0419a2', 'callout', 1, '{"variant":"why","text":"デプロイ前に明らかな問題を潰さないと、ビルド失敗の原因特定に余計な時間がかかります。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('2ab1c03b-9208-5fb7-b3d9-c2ea0253c75e', 'f38fa474-06b9-582f-b6de-1ee68b0419a2', 'markdown', 2, '{"text":"本番チェックリストを確認し、env の過不足・ビルド警告・未使用コードを整理します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('e71b09a4-2857-58a1-9dc6-119839ebdca5', 'f38fa474-06b9-582f-b6de-1ee68b0419a2', 'markdown', 3, '{"text":"# Prepare the app for deployment\n\nClean up obvious production issues before the first deployment attempt.\n\n## このレッスンのゴール\nYou will reduce surprise failures when Vercel builds the app.\n\n## 先に把握しておくこと\n- モジュール: **Ship It**\n- 想定時間: **25 分**\n- 到達したい状態: app_prepared_for_deploy\n\n## なぜ今やるのか\nデプロイ前に明らかな問題を潰さないと、ビルド失敗の原因特定に余計な時間がかかります。\n\n## 進め方\n1. 本番チェックリストを確認し、env の過不足・ビルド警告・未使用コードを整理します。\n\n## このレッスンで残すもの\n- Production checklist reviewed\n\n## 詰まりやすいポイント\n- 本番用 env の不足、ビルド警告が残っている。\n\n## AI への依頼例\n```text\n今は「Prepare the app for deployment」を進めています。\n目的: You will reduce surprise failures when Vercel builds the app.\n現状: Clean up obvious production issues before the first deployment attempt.\n今回残したい成果物: Production checklist reviewed\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- 本番用チェックリストが埋まり、env と build warning の確認が終わっていること。\n\n## 関連キーワード\n- `prepare next.js app for deployment`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('b9566b86-afe7-5733-b012-16880d347020', 'f38fa474-06b9-582f-b6de-1ee68b0419a2', 'callout', 4, '{"variant":"warning","text":"本番用 env の不足、ビルド警告が残っている。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('5d29b4aa-e1b9-52d0-be69-678c7a8a9b94', 'f38fa474-06b9-582f-b6de-1ee68b0419a2', 'rubric', 5, '{"criteria":"本番用チェックリストが埋まり、env と build warning の確認が終わっていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('47dad500-8b01-5a84-937f-252b82a15814', '9a263249-427e-5a9e-ad56-196dc1723140', 'markdown', 0, '{"text":"Vercel CLI を導入し、ログインとプロジェクト操作の入口を確認します。ブラウザ設定に入る前に、CLI で deploy まわりの前提を揃えます。","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('2825c6a7-579a-56ca-97d6-3f7aa7fdf044', '9a263249-427e-5a9e-ad56-196dc1723140', 'callout', 1, '{"variant":"why","text":"CLI がないとデプロイのトラブルシュートがブラウザだけになり、再現性のある操作ができません。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('7e498a53-46ae-5d68-b74d-7ba02ffef143', '9a263249-427e-5a9e-ad56-196dc1723140', 'markdown', 2, '{"text":"Vercel CLI をインストールし、ログインとプロジェクト連携の確認を行います。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('dce5984c-8d4e-586b-bca3-12e56e1822ab', '9a263249-427e-5a9e-ad56-196dc1723140', 'markdown', 3, '{"text":"# Vercel CLI をセットアップする\n\nVercel CLI を導入し、ログインとプロジェクト操作の入口を確認します。ブラウザ設定に入る前に、CLI で deploy まわりの前提を揃えます。\n\n## このレッスンのゴール\nVercel の設定確認やデプロイ補助を CLI から進められる状態になります。\n\n## 先に把握しておくこと\n- モジュール: **Ship It**\n- 想定時間: **20 分**\n- 到達したい状態: vercel_cli_ready\n\n## なぜ今やるのか\nCLI がないとデプロイのトラブルシュートがブラウザだけになり、再現性のある操作ができません。\n\n## 進め方\n1. Vercel CLI をインストールし、ログインとプロジェクト連携の確認を行います。\n\n## このレッスンで残すもの\n- Vercel CLI セットアップ完了\n- ログイン確認\n- プロジェクト操作前提チェック\n\n## 詰まりやすいポイント\n- CLI セットアップエラー、アカウント未作成、環境変数の未設定。\n\n## AI への依頼例\n```text\n今は「Vercel CLI をセットアップする」を進めています。\n目的: Vercel の設定確認やデプロイ補助を CLI から進められる状態になります。\n現状: Vercel CLI を導入し、ログインとプロジェクト操作の入口を確認します。ブラウザ設定に入る前に、CLI で deploy まわりの前提を揃えます。\n今回残したい成果物: Vercel CLI セットアップ完了、ログイン確認、プロジェクト操作前提チェック\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- Vercel CLI のバージョン確認が通り、ログイン後に次の操作を説明できること。\n\n## 関連キーワード\n- `vercel cli setup`\n- `vercel login cli`\n- `vercel project link`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('5ea2c021-0b01-559f-a254-ee93d9cdf2a7', '9a263249-427e-5a9e-ad56-196dc1723140', 'callout', 4, '{"variant":"warning","text":"CLI セットアップエラー、アカウント未作成、環境変数の未設定。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('f5a510c3-e0e7-524a-9d12-bb44a389b87f', '9a263249-427e-5a9e-ad56-196dc1723140', 'rubric', 5, '{"criteria":"Vercel CLI のバージョン確認が通り、ログイン後に次の操作を説明できること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('bd27e4cc-4d77-5a54-92dc-eb1133c739a5', '0787a861-787b-5e86-8bfc-1a5b006d9e16', 'markdown', 0, '{"text":"Connect the repo to Vercel and set production configuration correctly.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('09b9a2cd-ee60-5e2d-8780-071da14c7f03', '0787a861-787b-5e86-8bfc-1a5b006d9e16', 'callout', 1, '{"variant":"why","text":"Vercel の設定が間違っていると、コードは正しくてもビルドが通りません。env と設定を正確に揃えることが初回デプロイ成功の鍵です。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('5db64dd6-b644-54af-b4e7-55d689122ea2', '0787a861-787b-5e86-8bfc-1a5b006d9e16', 'markdown', 2, '{"text":"Vercel ダッシュボードでリポジトリを接続し、Framework Preset と環境変数を設定します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('bce5aa6c-de61-5c8c-96a9-db8e2c51dd48', '0787a861-787b-5e86-8bfc-1a5b006d9e16', 'markdown', 3, '{"text":"# Configure Vercel project settings and environment variables\n\nConnect the repo to Vercel and set production configuration correctly.\n\n## このレッスンのゴール\nThe deployment service will be ready to build the app.\n\n## 先に把握しておくこと\n- モジュール: **Ship It**\n- 想定時間: **25 分**\n- 到達したい状態: vercel_configured\n\n## なぜ今やるのか\nVercel の設定が間違っていると、コードは正しくてもビルドが通りません。env と設定を正確に揃えることが初回デプロイ成功の鍵です。\n\n## 進め方\n1. Vercel ダッシュボードでリポジトリを接続し、Framework Preset と環境変数を設定します。\n\n## このレッスンで残すもの\n- Vercel project created\n- Prod env vars set\n\n## 詰まりやすいポイント\n- Vercel 環境変数の未設定、monorepo での root directory 指定漏れ。\n\n## AI への依頼例\n```text\n今は「Configure Vercel project settings and environment variables」を進めています。\n目的: The deployment service will be ready to build the app.\n現状: Connect the repo to Vercel and set production configuration correctly.\n今回残したい成果物: Vercel project created、Prod env vars set\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- Vercel プロジェクトが作成され、本番用 env が設定されていること。\n\n## 関連キーワード\n- `configure vercel next.js`\n- `vercel environment variables`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('5551cd39-4b1c-577b-b5f7-2ea192ff9181', '0787a861-787b-5e86-8bfc-1a5b006d9e16', 'callout', 4, '{"variant":"warning","text":"Vercel 環境変数の未設定、monorepo での root directory 指定漏れ。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('17ac01ff-07da-546c-8ee5-dd73d4fda4e7', '0787a861-787b-5e86-8bfc-1a5b006d9e16', 'rubric', 5, '{"criteria":"Vercel プロジェクトが作成され、本番用 env が設定されていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('cce3a490-3d51-5fec-abe2-2b2fe8e0c251', '6f285270-d981-5bdc-a560-75a93778b37a', 'markdown', 0, '{"text":"Push the first production deployment and fix the issues it exposes.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('9e4f5be7-84bb-5080-a7e9-4bab3ddc4e9a', '6f285270-d981-5bdc-a560-75a93778b37a', 'callout', 1, '{"variant":"why","text":"初回ビルドは高確率で失敗します。失敗を前提にログを読んで直す経験が、本番運用スキルの第一歩です。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('336dccfd-cb36-5777-a016-495409b6d468', '6f285270-d981-5bdc-a560-75a93778b37a', 'markdown', 2, '{"text":"デプロイを実行し、build log を確認、エラーがあれば AI にログを渡して修正を繰り返します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('f1f6f883-5f80-502e-a457-658ddb9730e1', '6f285270-d981-5bdc-a560-75a93778b37a', 'markdown', 3, '{"text":"# Deploy the site and diagnose the first production build\n\nPush the first production deployment and fix the issues it exposes.\n\n## このレッスンのゴール\nYour app will reach a live URL even if the first build fails.\n\n## 先に把握しておくこと\n- モジュール: **Ship It**\n- 想定時間: **35 分**\n- 到達したい状態: deployment_completed\n\n## なぜ今やるのか\n初回ビルドは高確率で失敗します。失敗を前提にログを読んで直す経験が、本番運用スキルの第一歩です。\n\n## 進め方\n1. デプロイを実行し、build log を確認、エラーがあれば AI にログを渡して修正を繰り返します。\n\n## このレッスンで残すもの\n- First Vercel deployment\n\n## 詰まりやすいポイント\n- ビルド失敗、ローカルと本番の環境差異。\n\n## AI への依頼例\n```text\n今は「Deploy the site and diagnose the first production build」を進めています。\n目的: Your app will reach a live URL even if the first build fails.\n現状: Push the first production deployment and fix the issues it exposes.\n今回残したい成果物: First Vercel deployment\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- デプロイが成功し、公開 URL でアプリが動作すること。\n\n## 関連キーワード\n- `deploy site vercel`\n- `debug vercel build`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c30f0f24-913f-5276-9809-e2e2b4448a5c', '6f285270-d981-5bdc-a560-75a93778b37a', 'callout', 4, '{"variant":"warning","text":"ビルド失敗、ローカルと本番の環境差異。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('92b31946-e08e-5e5f-9a27-97b0ead9f03a', '6f285270-d981-5bdc-a560-75a93778b37a', 'rubric', 5, '{"criteria":"デプロイが成功し、公開 URL でアプリが動作すること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('31d3398c-623b-53d6-88c8-73960fb505f0', '69800c65-ed90-5c85-bcfe-bf8efc20cac9', 'markdown', 0, '{"text":"Test the public site like a real launch and confirm the promise is met.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('f98ff313-627d-59ce-99fc-d59b11064e70', '69800c65-ed90-5c85-bcfe-bf8efc20cac9', 'callout', 1, '{"variant":"why","text":"デプロイ成功＝本番で使えるとは限りません。実際の URL で動作確認しないと、ユーザーが踏む不具合を見逃します。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('79586995-b4c4-59a1-8477-36e3a3a214d7', '69800c65-ed90-5c85-bcfe-bf8efc20cac9', 'markdown', 2, '{"text":"公開 URL を開き、主要導線・フォーム送信・レスポンシブ表示をチェックリストに沿って検証します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('13f18a12-4aa2-5e4f-be88-eba09156e578', '69800c65-ed90-5c85-bcfe-bf8efc20cac9', 'markdown', 3, '{"text":"# Verify the live URL with a launch checklist\n\nTest the public site like a real launch and confirm the promise is met.\n\n## このレッスンのゴール\nYou will have evidence that the site works in production.\n\n## 先に把握しておくこと\n- モジュール: **Ship It**\n- 想定時間: **20 分**\n- 到達したい状態: launch_verified\n\n## なぜ今やるのか\nデプロイ成功＝本番で使えるとは限りません。実際の URL で動作確認しないと、ユーザーが踏む不具合を見逃します。\n\n## 進め方\n1. 公開 URL を開き、主要導線・フォーム送信・レスポンシブ表示をチェックリストに沿って検証します。\n\n## このレッスンで残すもの\n- Launch checklist complete\n\n## 詰まりやすいポイント\n- 本番だけで起きる env 差異、画像やフォントの読み込み失敗。\n\n## AI への依頼例\n```text\n今は「Verify the live URL with a launch checklist」を進めています。\n目的: You will have evidence that the site works in production.\n現状: Test the public site like a real launch and confirm the promise is met.\n今回残したい成果物: Launch checklist complete\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- ランチチェックリストの全項目を通過し、主要機能が本番 URL で動作すること。\n\n## 関連キーワード\n- `launch checklist website`\n- `verify live url`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('5fcc43e8-88bc-50f2-acd9-af7104a029f0', '69800c65-ed90-5c85-bcfe-bf8efc20cac9', 'callout', 4, '{"variant":"warning","text":"本番だけで起きる env 差異、画像やフォントの読み込み失敗。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('562dd321-849f-567f-8d82-4036789141ca', '69800c65-ed90-5c85-bcfe-bf8efc20cac9', 'rubric', 5, '{"criteria":"ランチチェックリストの全項目を通過し、主要機能が本番 URL で動作すること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('3724b027-523d-5999-847f-f3240389a204', 'd010afbe-d79c-5dcc-8d19-4c1a101923ff', 'markdown', 0, '{"text":"Use AI deliberately to improve the product without bloating the scope.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('2ab42c98-7c1d-5fd1-a7fb-5b35e0aa1c6d', 'd010afbe-d79c-5dcc-8d19-4c1a101923ff', 'callout', 1, '{"variant":"why","text":"MVP を出しただけでは「試作品」止まりです。1 つ磨き込むことで完成度が上がり、自信を持って人に見せられます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('530e88f4-cc09-518b-b85d-4d208fd88ad7', 'd010afbe-d79c-5dcc-8d19-4c1a101923ff', 'markdown', 2, '{"text":"ユーザー体験に最もインパクトのある改善を 1 つ選び、AI に依頼して実装・確認します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('62ac0480-12e9-5b0d-8acf-100f7543c709', 'd010afbe-d79c-5dcc-8d19-4c1a101923ff', 'markdown', 3, '{"text":"# Add one polish feature with AI support\n\nUse AI deliberately to improve the product without bloating the scope.\n\n## このレッスンのゴール\nThe site will feel one step closer to a real shipped product.\n\n## 先に把握しておくこと\n- モジュール: **Polish and Close**\n- 想定時間: **30 分**\n- 到達したい状態: polish_feature_added\n\n## なぜ今やるのか\nMVP を出しただけでは「試作品」止まりです。1 つ磨き込むことで完成度が上がり、自信を持って人に見せられます。\n\n## 進め方\n1. ユーザー体験に最もインパクトのある改善を 1 つ選び、AI に依頼して実装・確認します。\n\n## このレッスンで残すもの\n- One polish feature\n\n## 詰まりやすいポイント\n- スコープが広がって終わらない、改善の優先度が決められない。\n\n## AI への依頼例\n```text\n今は「Add one polish feature with AI support」を進めています。\n目的: The site will feel one step closer to a real shipped product.\n現状: Use AI deliberately to improve the product without bloating the scope.\n今回残したい成果物: One polish feature\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- つの polish 機能が追加され、本番 URL で動作していること。\n\n## 関連キーワード\n- `website polish ideas`\n- `ai design refinement`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('8bf05475-ea38-5175-84f8-f949fce1559d', 'd010afbe-d79c-5dcc-8d19-4c1a101923ff', 'callout', 4, '{"variant":"warning","text":"スコープが広がって終わらない、改善の優先度が決められない。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('ca4251c1-db05-5ef5-813f-9d20e3047795', 'd010afbe-d79c-5dcc-8d19-4c1a101923ff', 'rubric', 5, '{"criteria":"1 つの polish 機能が追加され、本番 URL で動作していること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('8b5066d6-92e2-5f28-a561-58eeb5976c17', '896c96e0-42fc-59d3-ab2c-d020104e814c', 'markdown', 0, '{"text":"Capture what you built, how it works, and where the stack fits together.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('ed50baaa-54dc-5c03-9a81-d8c21825d678', '896c96e0-42fc-59d3-ab2c-d020104e814c', 'callout', 1, '{"variant":"why","text":"作ったものを言語化しないと、学びが定着せず次のプロジェクトに活かせません。ハンドオフ資料は自分の成長記録にもなります。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d33ded40-f26e-5999-ae4f-d623788163e1', '896c96e0-42fc-59d3-ab2c-d020104e814c', 'markdown', 2, '{"text":"何を作ったか・技術スタックの構成・次にやるべきことを短くまとめます。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('7f073b3a-3002-5821-a83c-2322ef06fcda', '896c96e0-42fc-59d3-ab2c-d020104e814c', 'markdown', 3, '{"text":"# Write a short project handoff or build summary\n\nCapture what you built, how it works, and where the stack fits together.\n\n## このレッスンのゴール\nYou will be able to explain the project to yourself or someone else later.\n\n## 先に把握しておくこと\n- モジュール: **Polish and Close**\n- 想定時間: **20 分**\n- 到達したい状態: build_summary_written\n\n## なぜ今やるのか\n作ったものを言語化しないと、学びが定着せず次のプロジェクトに活かせません。ハンドオフ資料は自分の成長記録にもなります。\n\n## 進め方\n1. 何を作ったか・技術スタックの構成・次にやるべきことを短くまとめます。\n\n## このレッスンで残すもの\n- Short handoff note\n\n## 詰まりやすいポイント\n- 何を書けばいいか分からない、詳細に書きすぎて終わらない。\n\n## AI への依頼例\n```text\n今は「Write a short project handoff or build summary」を進めています。\n目的: You will be able to explain the project to yourself or someone else later.\n現状: Capture what you built, how it works, and where the stack fits together.\n今回残したい成果物: Short handoff note\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- プロジェクト概要・スタック構成・次のステップを含むハンドオフノートが書けていること。\n\n## 関連キーワード\n- `project handoff summary`\n- `build summary`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('904457e4-029b-5b31-b02c-e602f78fcacc', '896c96e0-42fc-59d3-ab2c-d020104e814c', 'callout', 4, '{"variant":"warning","text":"何を書けばいいか分からない、詳細に書きすぎて終わらない。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('0a725af8-9689-5fea-8d25-0c5835bfc79d', '896c96e0-42fc-59d3-ab2c-d020104e814c', 'rubric', 5, '{"criteria":"プロジェクト概要・スタック構成・次のステップを含むハンドオフノートが書けていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('01f26d6a-7868-591b-a656-bf638b5a5153', '9b19e573-0213-5dbe-b94b-0be911e3fdd7', 'markdown', 0, '{"text":"Pick the next improvement path instead of leaving the project unfinished.","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('939def89-c8aa-522a-a2d1-746d08d77ed6', '9b19e573-0213-5dbe-b94b-0be911e3fdd7', 'callout', 1, '{"variant":"why","text":"公開して終わりにすると学びが一度きりで止まります。次の一歩を決めることで継続的な成長サイクルが回り始めます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('3b1245ba-20df-54bf-a164-c977a8357767', '9b19e573-0213-5dbe-b94b-0be911e3fdd7', 'markdown', 2, '{"text":"コンテンツ追加・認証導入・グロース施策の 3 方向から、今の自分に最も価値がある次のステップを 1 つ選びます。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('61b6959e-581e-5812-9f93-a64665f71ffa', '9b19e573-0213-5dbe-b94b-0be911e3fdd7', 'markdown', 3, '{"text":"# Decide the next iteration: content, auth, or growth\n\nPick the next improvement path instead of leaving the project unfinished.\n\n## このレッスンのゴール\nYou will have a clear next step after shipping the first version.\n\n## 先に把握しておくこと\n- モジュール: **Polish and Close**\n- 想定時間: **20 分**\n- 到達したい状態: next_iteration_chosen\n\n## なぜ今やるのか\n公開して終わりにすると学びが一度きりで止まります。次の一歩を決めることで継続的な成長サイクルが回り始めます。\n\n## 進め方\n1. コンテンツ追加・認証導入・グロース施策の 3 方向から、今の自分に最も価値がある次のステップを 1 つ選びます。\n\n## このレッスンで残すもの\n- Next iteration plan\n\n## 詰まりやすいポイント\n- 選択肢が多すぎて決められない、完璧主義で現状に満足できない。\n\n## AI への依頼例\n```text\n今は「Decide the next iteration: content, auth, or growth」を進めています。\n目的: You will have a clear next step after shipping the first version.\n現状: Pick the next improvement path instead of leaving the project unfinished.\n今回残したい成果物: Next iteration plan\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- 次のイテレーション方針を 1 つ選び、理由を説明できること。\n\n## 関連キーワード\n- `next iteration website`\n- `post launch roadmap`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('69fc69f7-3890-5dca-a544-f633895455dc', '9b19e573-0213-5dbe-b94b-0be911e3fdd7', 'callout', 4, '{"variant":"warning","text":"選択肢が多すぎて決められない、完璧主義で現状に満足できない。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d2b53339-2118-5982-a7c9-a2e4d9324dfe', '9b19e573-0213-5dbe-b94b-0be911e3fdd7', 'rubric', 5, '{"criteria":"次のイテレーション方針を 1 つ選び、理由を説明できること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('658925e1-2a22-572f-8af0-c836915f1240', '4919a9a9-bff7-5c31-86eb-aa6d734b9099', 'markdown', 0, '{"text":"ChatGPT・Claude などの AI チャットツールの基本操作を学び、情報整理・文章作成・要約に活用する","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('97d082d5-91d2-5701-939b-97bfc88c41c4', '4919a9a9-bff7-5c31-86eb-aa6d734b9099', 'callout', 1, '{"variant":"why","text":"AIチャットは自動化の入口です。まずチャットで AI と対話する感覚を掴むことで、後のスクリプト自動化へスムーズに進めます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('a7a49cbd-efe8-596f-b210-54948cd550c5', '4919a9a9-bff7-5c31-86eb-aa6d734b9099', 'markdown', 2, '{"text":"ChatGPT または Claude にアクセスし、① 業務メールの要約 ② 会議議事録の整理 ③ アイデアのブレスト の 3 つを実際に試します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('7a661863-3a29-52dc-b1c3-bc5a737a6218', '4919a9a9-bff7-5c31-86eb-aa6d734b9099', 'markdown', 3, '{"text":"# AIチャットで業務を加速しよう\n\nChatGPT・Claude などの AI チャットツールの基本操作を学び、情報整理・文章作成・要約に活用する\n\n## このレッスンのゴール\nこの lesson を終えると、AI チャットを使って日常業務を効率化できるようになります\n\n## 先に把握しておくこと\n- モジュール: **AIチャット活用基礎**\n- 想定時間: **20 分**\n- 到達したい状態: AIチャットで業務タスクを処理するスキル\n\n## なぜ今やるのか\nAIチャットは自動化の入口です。まずチャットで AI と対話する感覚を掴むことで、後のスクリプト自動化へスムーズに進めます。\n\n## 進め方\n1. ChatGPT または Claude にアクセスし、① 業務メールの要約 ② 会議議事録の整理 ③ アイデアのブレスト の 3 つを実際に試します。\n\n## このレッスンで残すもの\n- AI対話ログ\n- 生成した成果物（要約・整理済み文書）\n\n## 詰まりやすいポイント\n- プロンプトが漠然としすぎて期待通りの出力が得られない、AI の回答を鵜呑みにしてしまう。\n\n## AI への依頼例\n```text\n今は「AIチャットで業務を加速しよう」を進めています。\n目的: この lesson を終えると、AI チャットを使って日常業務を効率化できるようになります\n現状: ChatGPT・Claude などの AI チャットツールの基本操作を学び、情報整理・文章作成・要約に活用する\n今回残したい成果物: AI対話ログ、生成した成果物（要約・整理済み文書）\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- AI チャットで 3 つ以上の業務タスク（要約・整理・生成）を実行し、成果物を保存できていること。\n\n## 関連キーワード\n- `AIチャット`\n- `ChatGPT`\n- `Claude`\n- `要約`\n- `文章作成`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('ff017595-7c45-5a08-b7c1-32e133a22abe', '4919a9a9-bff7-5c31-86eb-aa6d734b9099', 'callout', 4, '{"variant":"warning","text":"プロンプトが漠然としすぎて期待通りの出力が得られない、AI の回答を鵜呑みにしてしまう。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c91713e1-564f-56f8-8764-e6da9f329f74', '4919a9a9-bff7-5c31-86eb-aa6d734b9099', 'rubric', 5, '{"criteria":"AI チャットで 3 つ以上の業務タスク（要約・整理・生成）を実行し、成果物を保存できていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('41a5fbbf-5e35-56d9-9446-309e3baf5188', '84dfd568-457d-5949-b6c7-2127704735af', 'markdown', 0, '{"text":"日常業務を棚卸しして、繰り返し・定型・時間がかかるタスクを特定する","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c5681f68-a97d-5d5d-a37c-491221e58df3', '84dfd568-457d-5949-b6c7-2127704735af', 'callout', 1, '{"variant":"why","text":"自動化の効果は「何を自動化するか」で決まります。闇雲にスクリプトを書く前に、最も効果の高いタスクを見極めることが成功の鍵です。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c0eec343-e80f-50b7-a5f5-2a24e3bfa7f9', '84dfd568-457d-5949-b6c7-2127704735af', 'markdown', 2, '{"text":"1 週間の業務を書き出し、「頻度 × 所要時間 × 定型度」の 3 軸でスコアリングして上位 3 件を自動化候補にします。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('03ef8f4e-4b6d-5bcc-b62c-f0ac8bcd562c', '84dfd568-457d-5949-b6c7-2127704735af', 'markdown', 3, '{"text":"# 自動化できるタスクを見つけよう\n\n日常業務を棚卸しして、繰り返し・定型・時間がかかるタスクを特定する\n\n## このレッスンのゴール\nこの lesson を終えると、自動化すべきタスクが明確になります\n\n## 先に把握しておくこと\n- モジュール: **自動化対象の特定**\n- 想定時間: **20 分**\n- 到達したい状態: 自動化対象タスクのリストと優先順位\n\n## なぜ今やるのか\n自動化の効果は「何を自動化するか」で決まります。闇雲にスクリプトを書く前に、最も効果の高いタスクを見極めることが成功の鍵です。\n\n## 進め方\n1. 週間の業務を書き出し、「頻度 × 所要時間 × 定型度」の 3 軸でスコアリングして上位 3 件を自動化候補にします。\n\n## このレッスンで残すもの\n- タスク棚卸しシート\n- 優先順位付きリスト\n\n## 詰まりやすいポイント\n- タスクが多すぎて絞れない、自動化可能かどうかの判断がつかない。\n\n## AI への依頼例\n```text\n今は「自動化できるタスクを見つけよう」を進めています。\n目的: この lesson を終えると、自動化すべきタスクが明確になります\n現状: 日常業務を棚卸しして、繰り返し・定型・時間がかかるタスクを特定する\n今回残したい成果物: タスク棚卸しシート、優先順位付きリスト\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- 自動化候補タスクのリストが作成され、優先順位と期待効果が説明できること。\n\n## 関連キーワード\n- `自動化`\n- `業務効率`\n- `タスク分析`\n- `棚卸し`\n- `automation`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('3c792fe1-4f14-589b-bae4-5e32a9dcb1a0', '84dfd568-457d-5949-b6c7-2127704735af', 'callout', 4, '{"variant":"warning","text":"タスクが多すぎて絞れない、自動化可能かどうかの判断がつかない。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('7d6d74ae-6154-5127-8f77-70e8ec779ba6', '84dfd568-457d-5949-b6c7-2127704735af', 'rubric', 5, '{"criteria":"自動化候補タスクのリストが作成され、優先順位と期待効果が説明できること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('8c9c6123-25cb-5997-b3c7-ff7a473addfe', 'a26a6702-4aa6-55fd-84e6-0d0d789400eb', 'markdown', 0, '{"text":"自動化対象タスクの業務フローを可視化し、自動化範囲と手動作業の境界を設計する","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c973a021-0b05-5f09-ace9-675e73f3da4d', 'a26a6702-4aa6-55fd-84e6-0d0d789400eb', 'callout', 1, '{"variant":"why","text":"業務全体のフローを把握せずに一部だけ自動化すると、前後の工程とつながらず効果が半減します。全体を俯瞰してから自動化ポイントを決めましょう。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d0130a85-9ed7-517a-9da1-7e49a5554154', 'a26a6702-4aa6-55fd-84e6-0d0d789400eb', 'markdown', 2, '{"text":"対象タスクの手順を「入力→処理→出力」で書き出し、各ステップに「自動化可能 / 判断が必要」のラベルを付けます。Miro や紙でフロー図を描くと効果的です。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('6fc65e78-e166-5249-b69d-f12cf9316352', 'a26a6702-4aa6-55fd-84e6-0d0d789400eb', 'markdown', 3, '{"text":"# 業務フロー自動化を設計しよう\n\n自動化対象タスクの業務フローを可視化し、自動化範囲と手動作業の境界を設計する\n\n## このレッスンのゴール\nこの lesson を終えると、どこを自動化しどこを人が判断するか明確になります\n\n## 先に把握しておくこと\n- モジュール: **自動化対象の特定**\n- 想定時間: **25 分**\n- 到達したい状態: 自動化設計書（フロー図＋自動化範囲）\n\n## なぜ今やるのか\n業務全体のフローを把握せずに一部だけ自動化すると、前後の工程とつながらず効果が半減します。全体を俯瞰してから自動化ポイントを決めましょう。\n\n## 進め方\n1. 対象タスクの手順を「入力→処理→出力」で書き出し、各ステップに「自動化可能 / 判断が必要」のラベルを付けます。\n2. Miro や紙でフロー図を描くと効果的です。\n\n## このレッスンで残すもの\n- 業務フロー図\n- 自動化範囲の定義書\n\n## 詰まりやすいポイント\n- フローが複雑すぎて整理できない、例外ケースを考えすぎて進まない。\n\n## AI への依頼例\n```text\n今は「業務フロー自動化を設計しよう」を進めています。\n目的: この lesson を終えると、どこを自動化しどこを人が判断するか明確になります\n現状: 自動化対象タスクの業務フローを可視化し、自動化範囲と手動作業の境界を設計する\n今回残したい成果物: 業務フロー図、自動化範囲の定義書\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- 業務フロー図が完成し、自動化範囲と手動範囲の境界が明示されていること。\n\n## 関連キーワード\n- `業務フロー`\n- `ワークフロー`\n- `自動化設計`\n- `フロー図`\n- `プロセス設計`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('1e850ef6-ebd2-5c1a-8122-0ddac6ad5a29', 'a26a6702-4aa6-55fd-84e6-0d0d789400eb', 'callout', 4, '{"variant":"warning","text":"フローが複雑すぎて整理できない、例外ケースを考えすぎて進まない。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('ca602075-4316-55b0-905f-94a227122be1', 'a26a6702-4aa6-55fd-84e6-0d0d789400eb', 'rubric', 5, '{"criteria":"業務フロー図が完成し、自動化範囲と手動範囲の境界が明示されていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('2a7bc0f8-c7f0-5071-8e4d-698895b78f0d', 'adc6a449-92e3-5062-adfd-56864489079a', 'markdown', 0, '{"text":"Python をインストールし、AI API（Claude / OpenAI）への接続を設定する","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('4d2cf5c7-ca5c-514f-83be-14a7b1a687d8', 'adc6a449-92e3-5062-adfd-56864489079a', 'callout', 1, '{"variant":"why","text":"環境構築でつまずくと、自動化スクリプト作成に到達できません。最短で「AI API を呼べる状態」まで整えることが次のステップへの前提です。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('a6a6b0bb-29e3-5559-bb6a-6e1d1ec3d29a', 'adc6a449-92e3-5062-adfd-56864489079a', 'markdown', 2, '{"text":"Python をインストールし、pip で openai / anthropic パッケージを追加、API キーを環境変数に設定して疎通テストを実行します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('bc074451-c63f-5581-bd37-df34c911da4f', 'adc6a449-92e3-5062-adfd-56864489079a', 'markdown', 3, '{"text":"# Python と AI ツールのセットアップ\n\nPython をインストールし、AI API（Claude / OpenAI）への接続を設定する\n\n## このレッスンのゴール\nこの lesson を終えると、AI を使ったスクリプト開発ができる環境が整います\n\n## 先に把握しておくこと\n- モジュール: **自動化環境のセットアップ**\n- 想定時間: **30 分**\n- 到達したい状態: Python + AI API が動作する開発環境\n\n## なぜ今やるのか\n環境構築でつまずくと、自動化スクリプト作成に到達できません。最短で「AI API を呼べる状態」まで整えることが次のステップへの前提です。\n\n## 進め方\n1. Python をインストールし、pip で openai / anthropic パッケージを追加、API キーを環境変数に設定して疎通テストを実行します。\n\n## このレッスンで残すもの\n- Python インストール確認\n- API キー設定\n- テストスクリプト実行\n\n## 詰まりやすいポイント\n- Python のバージョン違い、pip のパス設定ミス、API キーの取得方法がわからない。\n\n## AI への依頼例\n```text\n今は「Python と AI ツールのセットアップ」を進めています。\n目的: この lesson を終えると、AI を使ったスクリプト開発ができる環境が整います\n現状: Python をインストールし、AI API（Claude / OpenAI）への接続を設定する\n今回残したい成果物: Python インストール確認、API キー設定、テストスクリプト実行\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- Python スクリプトから AI API を呼び出し、レスポンスが返ることを確認できていること。\n\n## 関連キーワード\n- `Python`\n- `セットアップ`\n- `AI API`\n- `環境構築`\n- `pip`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('f3a2fc29-06ba-5298-a0c3-106090301e7f', 'adc6a449-92e3-5062-adfd-56864489079a', 'callout', 4, '{"variant":"warning","text":"Python のバージョン違い、pip のパス設定ミス、API キーの取得方法がわからない。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('3e377227-3bdc-53db-be6b-8dbb77f51db6', 'adc6a449-92e3-5062-adfd-56864489079a', 'rubric', 5, '{"criteria":"Python スクリプトから AI API を呼び出し、レスポンスが返ることを確認できていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c9eee290-65c5-50ac-8baf-816b116774c6', '0d11fe86-6a07-5540-9363-e25b649e2fb8', 'markdown', 0, '{"text":"AI API のリクエスト構造を理解し、Python から API を呼び出してレスポンスを処理する","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('3c28d302-55e0-5d23-b271-46dde36060c4', '0d11fe86-6a07-5540-9363-e25b649e2fb8', 'callout', 1, '{"variant":"why","text":"自動化スクリプトの中核は AI API 呼び出しです。リクエスト/レスポンスの仕組みを理解すれば、あらゆる業務に応用できます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('ad1e8d58-09ab-5d7f-9ca0-e3f848669e92', '0d11fe86-6a07-5540-9363-e25b649e2fb8', 'markdown', 2, '{"text":"Claude API の messages エンドポイントを Python から呼び出し、system プロンプト・temperature・max_tokens の効果を確認します。エラーハンドリングも実装します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d2f82551-40f2-59cb-b375-2cdc7832047b', '0d11fe86-6a07-5540-9363-e25b649e2fb8', 'markdown', 3, '{"text":"# AI API コールの基礎を学ぼう\n\nAI API のリクエスト構造を理解し、Python から API を呼び出してレスポンスを処理する\n\n## このレッスンのゴール\nこの lesson を終えると、Python スクリプトから AI API を自在に呼び出せるようになります\n\n## 先に把握しておくこと\n- モジュール: **自動化環境のセットアップ**\n- 想定時間: **35 分**\n- 到達したい状態: AI API を呼び出す Python スクリプト\n\n## なぜ今やるのか\n自動化スクリプトの中核は AI API 呼び出しです。リクエスト/レスポンスの仕組みを理解すれば、あらゆる業務に応用できます。\n\n## 進め方\n1. Claude API の messages エンドポイントを Python から呼び出し、system プロンプト・temperature・max_tokens の効果を確認します。\n2. エラーハンドリングも実装します。\n\n## このレッスンで残すもの\n- API 呼び出しスクリプト\n- レスポンス処理コード\n- エラーハンドリング実装\n\n## 詰まりやすいポイント\n- API レスポンスの JSON 構造がわからない、レート制限に引っかかる、エラー処理を忘れて落ちる。\n\n## AI への依頼例\n```text\n今は「AI API コールの基礎を学ぼう」を進めています。\n目的: この lesson を終えると、Python スクリプトから AI API を自在に呼び出せるようになります\n現状: AI API のリクエスト構造を理解し、Python から API を呼び出してレスポンスを処理する\n今回残したい成果物: API 呼び出しスクリプト、レスポンス処理コード、エラーハンドリング実装\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- Python スクリプトで AI API を呼び出し、レスポンスをパースして整形表示できること。\n- エラー時にリトライする処理が動くこと。\n\n## 関連キーワード\n- `AI API`\n- `APIコール`\n- `Python API`\n- `Claude API`\n- `リクエスト`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('f94d6240-8256-52ea-b995-ccbe37a902c2', '0d11fe86-6a07-5540-9363-e25b649e2fb8', 'callout', 4, '{"variant":"warning","text":"API レスポンスの JSON 構造がわからない、レート制限に引っかかる、エラー処理を忘れて落ちる。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('45cef8d6-1011-507b-97c2-3b4aa0e8f8b5', '0d11fe86-6a07-5540-9363-e25b649e2fb8', 'rubric', 5, '{"criteria":"Python スクリプトで AI API を呼び出し、レスポンスをパースして整形表示できること。エラー時にリトライする処理が動くこと。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('db9e89ec-3eaa-5b24-be40-1d1f7d71163b', '02ab42d5-ba8f-5700-8c79-9219a0aa7d66', 'markdown', 0, '{"text":"AI から望む出力を安定して引き出すためのプロンプト設計パターンを学ぶ","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('3101841a-9be0-535e-913f-1a614ba63dd2', '02ab42d5-ba8f-5700-8c79-9219a0aa7d66', 'callout', 1, '{"variant":"why","text":"同じ AI でもプロンプト次第で出力品質が劇的に変わります。自動化スクリプトに組み込むプロンプトの品質が、自動化の精度を左右します。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('b824912b-6ad4-5183-821d-fafa947a3862', '02ab42d5-ba8f-5700-8c79-9219a0aa7d66', 'markdown', 2, '{"text":"① 役割設定（system prompt）② 具体的な指示 ③ 出力形式指定 ④ Few-shot 例示 の 4 パターンを順に試し、同じタスクで出力品質の差を比較します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d137d245-f5df-5bf4-9d14-a07abbc91aa8', '02ab42d5-ba8f-5700-8c79-9219a0aa7d66', 'markdown', 3, '{"text":"# プロンプトエンジニアリング入門\n\nAI から望む出力を安定して引き出すためのプロンプト設計パターンを学ぶ\n\n## このレッスンのゴール\nこの lesson を終えると、目的に応じた効果的なプロンプトを設計できるようになります\n\n## 先に把握しておくこと\n- モジュール: **プロンプトエンジニアリング入門**\n- 想定時間: **30 分**\n- 到達したい状態: プロンプト設計パターンの理解とテンプレート集\n\n## なぜ今やるのか\n同じ AI でもプロンプト次第で出力品質が劇的に変わります。自動化スクリプトに組み込むプロンプトの品質が、自動化の精度を左右します。\n\n## 進め方\n1. 役割設定（system prompt）② 具体的な指示 ③ 出力形式指定 ④ Few-shot 例示 の 4 パターンを順に試し、同じタスクで出力品質の差を比較します。\n\n## このレッスンで残すもの\n- プロンプトパターン比較表\n- 業務用プロンプトテンプレート集\n\n## 詰まりやすいポイント\n- プロンプトが長すぎて管理できない、期待と異なる出力への対処法がわからない。\n\n## AI への依頼例\n```text\n今は「プロンプトエンジニアリング入門」を進めています。\n目的: この lesson を終えると、目的に応じた効果的なプロンプトを設計できるようになります\n現状: AI から望む出力を安定して引き出すためのプロンプト設計パターンを学ぶ\n今回残したい成果物: プロンプトパターン比較表、業務用プロンプトテンプレート集\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- つのプロンプトパターンを使い分けた比較結果があり、業務用プロンプトテンプレートを 3 つ以上作成できていること。\n\n## 関連キーワード\n- `プロンプト`\n- `プロンプトエンジニアリング`\n- `prompt`\n- `Few-shot`\n- `指示設計`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('a85bca21-f33e-5f2a-af6c-637b89cd3ae2', '02ab42d5-ba8f-5700-8c79-9219a0aa7d66', 'callout', 4, '{"variant":"warning","text":"プロンプトが長すぎて管理できない、期待と異なる出力への対処法がわからない。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('5adbc77c-5cbf-5e1f-a009-bdeeddb48c2b', '02ab42d5-ba8f-5700-8c79-9219a0aa7d66', 'rubric', 5, '{"criteria":"4 つのプロンプトパターンを使い分けた比較結果があり、業務用プロンプトテンプレートを 3 つ以上作成できていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('ddd8becf-98af-5024-9fb7-7f646b073f8d', 'f95b04ae-d077-5d90-9614-b830870ed98d', 'markdown', 0, '{"text":"AI コーディングツールを使って、特定したタスクを自動化するスクリプトを作成する","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('ae1de0b8-9b8b-539c-b767-a3a1da2b0e80', 'f95b04ae-d077-5d90-9614-b830870ed98d', 'callout', 1, '{"variant":"why","text":"ここまでに学んだ「タスク特定・環境構築・API 呼び出し・プロンプト設計」を統合し、実際に動くスクリプトを作ることで自動化スキルが定着します。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('9d8454ac-71fd-59c2-bb77-22437a5b3fc7', 'f95b04ae-d077-5d90-9614-b830870ed98d', 'markdown', 2, '{"text":"設計した業務フローに沿って、入力取得→AI API 呼び出し→結果整形→出力保存の順でスクリプトを組み立てます。Claude Code をペアプログラマとして活用します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('561b5be9-6fa6-5a6b-b0a7-d75070bfb22a', 'f95b04ae-d077-5d90-9614-b830870ed98d', 'markdown', 3, '{"text":"# AI と一緒に自動化スクリプトを書こう\n\nAI コーディングツールを使って、特定したタスクを自動化するスクリプトを作成する\n\n## このレッスンのゴール\nこの lesson を終えると、1 つの業務タスクが自動で実行されるようになります\n\n## 先に把握しておくこと\n- モジュール: **最初の自動化スクリプト作成**\n- 想定時間: **45 分**\n- 到達したい状態: 動作する自動化スクリプト\n\n## なぜ今やるのか\nここまでに学んだ「タスク特定・環境構築・API 呼び出し・プロンプト設計」を統合し、実際に動くスクリプトを作ることで自動化スキルが定着します。\n\n## 進め方\n1. 設計した業務フローに沿って、入力取得→AI API 呼び出し→結果整形→出力保存の順でスクリプトを組み立てます。\n2. Claude Code をペアプログラマとして活用します。\n\n## このレッスンで残すもの\n- 自動化スクリプトファイル\n- 実行結果の確認\n\n## 詰まりやすいポイント\n- スクリプトのエラーが解決できない、API レート制限に引っかかる、出力フォーマットが安定しない。\n\n## AI への依頼例\n```text\n今は「AI と一緒に自動化スクリプトを書こう」を進めています。\n目的: この lesson を終えると、1 つの業務タスクが自動で実行されるようになります\n現状: AI コーディングツールを使って、特定したタスクを自動化するスクリプトを作成する\n今回残したい成果物: 自動化スクリプトファイル、実行結果の確認\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- スクリプトを実行して対象業務タスクが自動処理され、期待通りの出力が得られること。\n\n## 関連キーワード\n- `スクリプト`\n- `自動化`\n- `AI コーディング`\n- `Python スクリプト`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d189c0c3-2371-5622-aee0-660499de5e27', 'f95b04ae-d077-5d90-9614-b830870ed98d', 'callout', 4, '{"variant":"warning","text":"スクリプトのエラーが解決できない、API レート制限に引っかかる、出力フォーマットが安定しない。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('f00d269d-c2df-58c9-9d0c-17dbe928dae4', 'f95b04ae-d077-5d90-9614-b830870ed98d', 'rubric', 5, '{"criteria":"スクリプトを実行して対象業務タスクが自動処理され、期待通りの出力が得られること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('bf4dfc3e-fac7-5eb9-afaf-0bdc15755470', '1b799850-dbd2-5192-9316-a0db3c56506b', 'markdown', 0, '{"text":"複数のスクリプトをつなげてエンドツーエンドの自動化ワークフローを構築する","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('254aa10a-403a-59d8-9530-f53e6fcfcfd8', '1b799850-dbd2-5192-9316-a0db3c56506b', 'callout', 1, '{"variant":"why","text":"単体スクリプトだけでは業務全体は自動化できません。複数処理をパイプラインとしてつなげることで、真の業務効率化が実現します。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('0f753f83-b300-5303-b1f9-22716e02f340', '1b799850-dbd2-5192-9316-a0db3c56506b', 'markdown', 2, '{"text":"① データ取得 ② AI 処理 ③ 結果整形 ④ 出力・通知 の 4 ステップをそれぞれ関数化し、メインスクリプトから順番に呼び出すパイプラインを構築します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('729d05e1-a2cd-51da-b875-393aa7b9be93', '1b799850-dbd2-5192-9316-a0db3c56506b', 'markdown', 3, '{"text":"# 自動化ワークフローを構築しよう\n\n複数のスクリプトをつなげてエンドツーエンドの自動化ワークフローを構築する\n\n## このレッスンのゴール\nこの lesson を終えると、複数ステップの業務が一気通貫で自動化されます\n\n## 先に把握しておくこと\n- モジュール: **最初の自動化スクリプト作成**\n- 想定時間: **40 分**\n- 到達したい状態: エンドツーエンドの自動化ワークフロー\n\n## なぜ今やるのか\n単体スクリプトだけでは業務全体は自動化できません。複数処理をパイプラインとしてつなげることで、真の業務効率化が実現します。\n\n## 進め方\n1. データ取得 ② AI 処理 ③ 結果整形 ④ 出力・通知 の 4 ステップをそれぞれ関数化し、メインスクリプトから順番に呼び出すパイプラインを構築します。\n\n## このレッスンで残すもの\n- パイプラインスクリプト\n- 実行ログ\n- エラーハンドリング実装\n\n## 詰まりやすいポイント\n- ステップ間のデータ受け渡しでエラーが起きる、途中で失敗した場合のリカバリがない。\n\n## AI への依頼例\n```text\n今は「自動化ワークフローを構築しよう」を進めています。\n目的: この lesson を終えると、複数ステップの業務が一気通貫で自動化されます\n現状: 複数のスクリプトをつなげてエンドツーエンドの自動化ワークフローを構築する\n今回残したい成果物: パイプラインスクリプト、実行ログ、エラーハンドリング実装\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- 複数ステップを含むワークフローが最初から最後まで自動実行され、各ステップのログが出力されること。\n\n## 関連キーワード\n- `ワークフロー`\n- `パイプライン`\n- `自動化構築`\n- `エンドツーエンド`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('80318c8c-35eb-552a-96bf-e98c1286afc6', '1b799850-dbd2-5192-9316-a0db3c56506b', 'callout', 4, '{"variant":"warning","text":"ステップ間のデータ受け渡しでエラーが起きる、途中で失敗した場合のリカバリがない。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('ac0fe2f7-d4ca-54ec-97d7-fc335f17ea74', '1b799850-dbd2-5192-9316-a0db3c56506b', 'rubric', 5, '{"criteria":"複数ステップを含むワークフローが最初から最後まで自動実行され、各ステップのログが出力されること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('ccbc4443-8d76-5cdd-bbde-15f5f8138eea', '0a82ff0e-aa40-5f84-a60b-7e634350dfa1', 'markdown', 0, '{"text":"スクリプトを cron やタスクスケジューラで定期実行する設定を行う","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('75c2d4fa-f93a-567a-855b-c684ad0b411d', '0a82ff0e-aa40-5f84-a60b-7e634350dfa1', 'callout', 1, '{"variant":"why","text":"手動でスクリプトを起動しているうちは真の自動化とは言えません。定期実行の仕組みを入れることで、完全に手放せる自動化が完成します。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('8435e48e-1bdc-5ccc-883e-53eb0a8c3d41', '0a82ff0e-aa40-5f84-a60b-7e634350dfa1', 'markdown', 2, '{"text":"macOS/Linux なら crontab、Windows ならタスクスケジューラでスクリプトを登録します。実行ログをファイルに残し、失敗時の通知も設定します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('42c690ce-e4a0-5505-aee6-94a638b8e13f', '0a82ff0e-aa40-5f84-a60b-7e634350dfa1', 'markdown', 3, '{"text":"# 定期実行をセットアップしよう\n\nスクリプトを cron やタスクスケジューラで定期実行する設定を行う\n\n## このレッスンのゴール\nこの lesson を終えると、自動化が人手なしで定期的に動くようになります\n\n## 先に把握しておくこと\n- モジュール: **テストとスケジュール実行**\n- 想定時間: **30 分**\n- 到達したい状態: 定期実行される自動化ワークフロー\n\n## なぜ今やるのか\n手動でスクリプトを起動しているうちは真の自動化とは言えません。定期実行の仕組みを入れることで、完全に手放せる自動化が完成します。\n\n## 進め方\n1. macOS/Linux なら crontab、Windows ならタスクスケジューラでスクリプトを登録します。\n2. 実行ログをファイルに残し、失敗時の通知も設定します。\n\n## このレッスンで残すもの\n- cron 設定\n- 実行ログの確認\n- 失敗通知設定\n\n## 詰まりやすいポイント\n- cron の書式ミス、実行環境のパス設定漏れ、ログの確認方法がわからない。\n\n## AI への依頼例\n```text\n今は「定期実行をセットアップしよう」を進めています。\n目的: この lesson を終えると、自動化が人手なしで定期的に動くようになります\n現状: スクリプトを cron やタスクスケジューラで定期実行する設定を行う\n今回残したい成果物: cron 設定、実行ログの確認、失敗通知設定\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- スクリプトが設定した時間に自動実行され、実行ログが記録されていること。\n\n## 関連キーワード\n- `定期実行`\n- `cron`\n- `スケジュール`\n- `タスクスケジューラ`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('46defd31-94ad-512f-b49c-f45112e37a71', '0a82ff0e-aa40-5f84-a60b-7e634350dfa1', 'callout', 4, '{"variant":"warning","text":"cron の書式ミス、実行環境のパス設定漏れ、ログの確認方法がわからない。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('48dffc26-70d2-5a8f-84c5-1e059422feae', '0a82ff0e-aa40-5f84-a60b-7e634350dfa1', 'rubric', 5, '{"criteria":"スクリプトが設定した時間に自動実行され、実行ログが記録されていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('e7e9e5ca-02dd-57c1-a214-7b41fe3ddc6b', '4cccaa52-992a-5b99-89db-5d6a1239c95a', 'markdown', 0, '{"text":"AIチャットツールを使って文章を生成・編集する基本スキルを学ぶ","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('f7320aa3-13a8-575d-89b0-dfc496c68879', '4cccaa52-992a-5b99-89db-5d6a1239c95a', 'callout', 1, '{"variant":"why","text":"AIライティングはコンテンツ制作の基盤です。まず「AIに文章を書かせる」感覚を掴むことで、後のブログ・SNS・教材制作にスムーズに進めます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('60dee25c-0db3-5c23-9b13-d02e614982ed', '4cccaa52-992a-5b99-89db-5d6a1239c95a', 'markdown', 2, '{"text":"ChatGPT または Claude を使い、① 自己紹介文の生成 ② メール文面のリライト ③ 要約文の作成 の 3 つを実際に試します。出力の品質を比較し、良い指示の出し方を学びます。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('9ae44caa-8201-5adf-80e7-0c321e0563f4', '4cccaa52-992a-5b99-89db-5d6a1239c95a', 'markdown', 3, '{"text":"# AIで文章を書いてみよう\n\nAIチャットツールを使って文章を生成・編集する基本スキルを学ぶ\n\n## このレッスンのゴール\nこの lesson を終えると、AIを使って目的に応じた文章を生成できるようになります\n\n## 先に把握しておくこと\n- モジュール: **AIライティング基礎**\n- 想定時間: **20 分**\n- 到達したい状態: AIで目的に応じた文章を生成するスキル\n\n## なぜ今やるのか\nAIライティングはコンテンツ制作の基盤です。まず「AIに文章を書かせる」感覚を掴むことで、後のブログ・SNS・教材制作にスムーズに進めます。\n\n## 進め方\n1. ChatGPT または Claude を使い、① 自己紹介文の生成 ② メール文面のリライト ③ 要約文の作成 の 3 つを実際に試します。\n2. 出力の品質を比較し、良い指示の出し方を学びます。\n\n## このレッスンで残すもの\n- AI生成文章サンプル 3 種類\n- 編集済み成果物\n\n## 詰まりやすいポイント\n- 出力が汎用的すぎて使えない、自分の文体と合わない、AIの文章をそのまま使っていいか不安。\n\n## AI への依頼例\n```text\n今は「AIで文章を書いてみよう」を進めています。\n目的: この lesson を終えると、AIを使って目的に応じた文章を生成できるようになります\n現状: AIチャットツールを使って文章を生成・編集する基本スキルを学ぶ\n今回残したい成果物: AI生成文章サンプル 3 種類、編集済み成果物\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- AIで 3 種類以上の文章（紹介文・メール・要約）を生成し、それぞれ自分の目的に合うよう編集できていること。\n\n## 関連キーワード\n- `AIライティング`\n- `文章生成`\n- `AI 文章`\n- `ライティング基礎`\n- `コンテンツ制作`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('a634428d-65ac-5462-8967-98fc626cd52c', '4cccaa52-992a-5b99-89db-5d6a1239c95a', 'callout', 4, '{"variant":"warning","text":"出力が汎用的すぎて使えない、自分の文体と合わない、AIの文章をそのまま使っていいか不安。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('a568f871-b882-5f56-9aa6-fe772514875b', '4cccaa52-992a-5b99-89db-5d6a1239c95a', 'rubric', 5, '{"criteria":"AIで 3 種類以上の文章（紹介文・メール・要約）を生成し、それぞれ自分の目的に合うよう編集できていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('f3d49d4f-037e-57d7-995d-34922085de39', '32dbdbec-b3cc-5917-a898-7ef86ae9b0e6', 'markdown', 0, '{"text":"文章生成に特化したプロンプト設計パターンを学び、AIの出力品質を高める","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d77c6454-05e8-533f-bc10-43aefb5b656a', '32dbdbec-b3cc-5917-a898-7ef86ae9b0e6', 'callout', 1, '{"variant":"why","text":"同じAIでもプロンプト次第で出力品質が劇的に変わります。「ペルソナ設定」「トーン指定」「構成指示」「出力形式指定」の 4 パターンを使い分けることで、実用的なコンテンツを安定して生成できます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('7f8aeceb-8204-5d9d-8a6d-5a269eb90939', '32dbdbec-b3cc-5917-a898-7ef86ae9b0e6', 'markdown', 2, '{"text":"① ターゲット読者（ペルソナ）の設定 ② トーン・文体の指定 ③ 構成テンプレートの提供 ④ 出力形式（Markdown・箇条書き・表）の指定 の 4 パターンを同じテーマで比較し、最適なプロンプトを見つけます。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('9f3398b6-c684-52ec-8507-35b5db43be8e', '32dbdbec-b3cc-5917-a898-7ef86ae9b0e6', 'markdown', 3, '{"text":"# コンテンツ制作のためのプロンプト設計\n\n文章生成に特化したプロンプト設計パターンを学び、AIの出力品質を高める\n\n## このレッスンのゴール\nこの lesson を終えると、コンテンツの種類に応じた効果的なプロンプトを設計できるようになります\n\n## 先に把握しておくこと\n- モジュール: **AIライティング基礎**\n- 想定時間: **25 分**\n- 到達したい状態: コンテンツ制作用プロンプトテンプレート集\n\n## なぜ今やるのか\n同じAIでもプロンプト次第で出力品質が劇的に変わります。「ペルソナ設定」「トーン指定」「構成指示」「出力形式指定」の 4 パターンを使い分けることで、実用的なコンテンツを安定して生成できます。\n\n## 進め方\n1. ターゲット読者（ペルソナ）の設定 ② トーン・文体の指定 ③ 構成テンプレートの提供 ④ 出力形式（Markdown・箇条書き・表）の指定 の 4 パターンを同じテーマで比較し、最適なプロンプトを見つけます。\n\n## このレッスンで残すもの\n- プロンプトパターン比較表\n- コンテンツ制作用テンプレート集\n\n## 詰まりやすいポイント\n- プロンプトが長すぎて管理できない、出力の一貫性を保てない、ペルソナ設定が曖昧。\n\n## AI への依頼例\n```text\n今は「コンテンツ制作のためのプロンプト設計」を進めています。\n目的: この lesson を終えると、コンテンツの種類に応じた効果的なプロンプトを設計できるようになります\n現状: 文章生成に特化したプロンプト設計パターンを学び、AIの出力品質を高める\n今回残したい成果物: プロンプトパターン比較表、コンテンツ制作用テンプレート集\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- つのプロンプトパターンを使い分けた比較結果があり、コンテンツ制作用プロンプトテンプレートを 3 つ以上作成できていること。\n\n## 関連キーワード\n- `プロンプト設計`\n- `プロンプト`\n- `文章生成プロンプト`\n- `コンテンツプロンプト`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('11ae822f-c262-5888-9704-c91545c7329a', '32dbdbec-b3cc-5917-a898-7ef86ae9b0e6', 'callout', 4, '{"variant":"warning","text":"プロンプトが長すぎて管理できない、出力の一貫性を保てない、ペルソナ設定が曖昧。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c2359fbc-9a46-51f5-a0eb-3aa36c31c39d', '32dbdbec-b3cc-5917-a898-7ef86ae9b0e6', 'rubric', 5, '{"criteria":"4 つのプロンプトパターンを使い分けた比較結果があり、コンテンツ制作用プロンプトテンプレートを 3 つ以上作成できていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('f2954b71-c9fc-5f30-9bd7-dc2f6683df7b', '6467352b-c9a4-5ed6-8ce1-b8dd0f0ba489', 'markdown', 0, '{"text":"ブログ記事の企画・構成・執筆・編集をAIと一緒に行い、公開可能な記事を完成させる","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('b0b77528-f437-5cd6-acd7-4d3b64a9ee0d', '6467352b-c9a4-5ed6-8ce1-b8dd0f0ba489', 'callout', 1, '{"variant":"why","text":"ブログはコンテンツマーケティングの基本です。AIを使えば記事の企画・リサーチ・構成・執筆を大幅に効率化できますが、品質を担保するには人間の編集眼が必要です。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('40381173-50a2-5424-bfb0-66f5dde43afb', '6467352b-c9a4-5ed6-8ce1-b8dd0f0ba489', 'markdown', 2, '{"text":"① AIにテーマ案を出してもらう ② 読者ペルソナと検索意図を設定 ③ 記事構成（見出し構造）をAIと設計 ④ 各セクションをAIで下書き ⑤ 人間がファクトチェック・トーン調整・オリジナリティ追加で仕上げます。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('512dc6bf-e671-57a2-b7f8-14da905eb4da', '6467352b-c9a4-5ed6-8ce1-b8dd0f0ba489', 'markdown', 3, '{"text":"# AIでブログ記事を書こう\n\nブログ記事の企画・構成・執筆・編集をAIと一緒に行い、公開可能な記事を完成させる\n\n## このレッスンのゴール\nこの lesson を終えると、AIを使ってSEOを意識したブログ記事を効率的に制作できるようになります\n\n## 先に把握しておくこと\n- モジュール: **テキストコンテンツ制作**\n- 想定時間: **40 分**\n- 到達したい状態: 公開可能なブログ記事ドラフト\n\n## なぜ今やるのか\nブログはコンテンツマーケティングの基本です。AIを使えば記事の企画・リサーチ・構成・執筆を大幅に効率化できますが、品質を担保するには人間の編集眼が必要です。\n\n## 進め方\n1. AIにテーマ案を出してもらう ② 読者ペルソナと検索意図を設定 ③ 記事構成（見出し構造）をAIと設計 ④ 各セクションをAIで下書き ⑤ 人間がファクトチェック・トーン調整・オリジナリティ追加で仕上げます。\n\n## このレッスンで残すもの\n- ブログ記事ドラフト\n- 構成テンプレート\n- SEOチェックリスト\n\n## 詰まりやすいポイント\n- AIの文章が汎用的すぎる、SEOキーワードの入れ方がわからない、ファクトチェックの方法が不明。\n\n## AI への依頼例\n```text\n今は「AIでブログ記事を書こう」を進めています。\n目的: この lesson を終えると、AIを使ってSEOを意識したブログ記事を効率的に制作できるようになります\n現状: ブログ記事の企画・構成・執筆・編集をAIと一緒に行い、公開可能な記事を完成させる\n今回残したい成果物: ブログ記事ドラフト、構成テンプレート、SEOチェックリスト\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- AIと協力してブログ記事を 1 本完成させ、構成・SEO・ファクトチェックの 3 点を説明できること。\n\n## 関連キーワード\n- `ブログ`\n- `記事作成`\n- `AI ブログ`\n- `SEO`\n- `コンテンツマーケティング`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('5b227b58-4cad-5918-a51a-19ff0a04ea7e', '6467352b-c9a4-5ed6-8ce1-b8dd0f0ba489', 'callout', 4, '{"variant":"warning","text":"AIの文章が汎用的すぎる、SEOキーワードの入れ方がわからない、ファクトチェックの方法が不明。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('23e3ab27-9077-503d-80fe-3c633a556786', '6467352b-c9a4-5ed6-8ce1-b8dd0f0ba489', 'rubric', 5, '{"criteria":"AIと協力してブログ記事を 1 本完成させ、構成・SEO・ファクトチェックの 3 点を説明できること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('df25e402-e8e3-5962-80fb-af856582595b', '52daab15-e659-5a72-866f-651153e8de9d', 'markdown', 0, '{"text":"Twitter/X・Instagram・LinkedInなど各プラットフォームに最適化したSNS投稿をAIで制作する","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('a78c30cd-a511-5837-a223-cb0a4265b805', '52daab15-e659-5a72-866f-651153e8de9d', 'callout', 1, '{"variant":"why","text":"SNSはリーチ拡大の最重要チャネルですが、各プラットフォームで求められるフォーマット・トーン・文字数が異なります。AIを使えばプラットフォーム別の最適化を効率的に行えます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('382a4c01-53e1-5497-9058-9833d6abc769', '52daab15-e659-5a72-866f-651153e8de9d', 'markdown', 2, '{"text":"① 各SNSの特性（文字数・ハッシュタグ・画像比率）を整理 ② ブログ記事から各SNS向け投稿をAIで変換 ③ 1 週間分の投稿カレンダーをAIで作成 ④ エンゲージメントを高めるフック文のパターンを練習します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('841362a9-ee0a-50d8-9e9a-0fdf2c69fc0e', '52daab15-e659-5a72-866f-651153e8de9d', 'markdown', 3, '{"text":"# SNSコンテンツ戦略とAI活用\n\nTwitter/X・Instagram・LinkedInなど各プラットフォームに最適化したSNS投稿をAIで制作する\n\n## このレッスンのゴール\nこの lesson を終えると、各SNSプラットフォームに適した投稿をAIで効率的に量産できるようになります\n\n## 先に把握しておくこと\n- モジュール: **テキストコンテンツ制作**\n- 想定時間: **30 分**\n- 到達したい状態: SNS投稿セット + 投稿カレンダー\n\n## なぜ今やるのか\nSNSはリーチ拡大の最重要チャネルですが、各プラットフォームで求められるフォーマット・トーン・文字数が異なります。AIを使えばプラットフォーム別の最適化を効率的に行えます。\n\n## 進め方\n1. 各SNSの特性（文字数・ハッシュタグ・画像比率）を整理 ② ブログ記事から各SNS向け投稿をAIで変換 ③ 1 週間分の投稿カレンダーをAIで作成 ④ エンゲージメントを高めるフック文のパターンを練習します。\n\n## このレッスンで残すもの\n- SNS投稿セット（3プラットフォーム分）\n- 1週間分の投稿カレンダー\n\n## 詰まりやすいポイント\n- プラットフォームごとの最適化が面倒、投稿ネタが続かない、ハッシュタグ選定がわからない。\n\n## AI への依頼例\n```text\n今は「SNSコンテンツ戦略とAI活用」を進めています。\n目的: この lesson を終えると、各SNSプラットフォームに適した投稿をAIで効率的に量産できるようになります\n現状: Twitter/X・Instagram・LinkedInなど各プラットフォームに最適化したSNS投稿をAIで制作する\n今回残したい成果物: SNS投稿セット（3プラットフォーム分）、1週間分の投稿カレンダー\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- つ以上のSNSプラットフォーム向けに最適化された投稿セットが完成していること。\n\n## 関連キーワード\n- `SNS`\n- `ソーシャルメディア`\n- `Twitter`\n- `Instagram`\n- `SNSコンテンツ`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c181cee8-7cfc-5fc4-8ce0-571f32dddd24', '52daab15-e659-5a72-866f-651153e8de9d', 'callout', 4, '{"variant":"warning","text":"プラットフォームごとの最適化が面倒、投稿ネタが続かない、ハッシュタグ選定がわからない。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('769ba381-a0c4-5412-a6c0-5490ae83c263', '52daab15-e659-5a72-866f-651153e8de9d', 'rubric', 5, '{"criteria":"3 つ以上のSNSプラットフォーム向けに最適化された投稿セットが完成していること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c7327a1d-7df2-5bf5-a45c-a6dbf1cb11c2', 'fef65479-2ed2-510b-b1c6-700117057284', 'markdown', 0, '{"text":"研修資料・マニュアル・チュートリアルなどの教材コンテンツをAIで効率的に制作する","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('efe52b24-5d18-57f1-a619-3ba81efc4c2d', 'fef65479-2ed2-510b-b1c6-700117057284', 'callout', 1, '{"variant":"why","text":"教材制作は時間がかかる仕事ですが、AIを使えば構成設計・例題作成・解説文の生成を大幅に効率化できます。ただし正確性と段階的な難易度設計は人間の判断が不可欠です。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d50418ca-8573-5e0b-8ea8-699636b5681f', 'fef65479-2ed2-510b-b1c6-700117057284', 'markdown', 2, '{"text":"① 学習目標と対象者を明確にする ② AIに単元構成と学習順序を設計させる ③ 各単元の解説・例題・演習問題をAIで生成 ④ 人間がレビュー・修正して完成させます。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('6fdd0d08-32ce-5610-b525-1e4fc0caf237', 'fef65479-2ed2-510b-b1c6-700117057284', 'markdown', 3, '{"text":"# AIで教材・学習コンテンツを作ろう\n\n研修資料・マニュアル・チュートリアルなどの教材コンテンツをAIで効率的に制作する\n\n## このレッスンのゴール\nこの lesson を終えると、学習者の理解度に合わせた教材をAIで制作できるようになります\n\n## 先に把握しておくこと\n- モジュール: **テキストコンテンツ制作**\n- 想定時間: **35 分**\n- 到達したい状態: 教材コンテンツ（解説 + 例題 + 演習）\n\n## なぜ今やるのか\n教材制作は時間がかかる仕事ですが、AIを使えば構成設計・例題作成・解説文の生成を大幅に効率化できます。ただし正確性と段階的な難易度設計は人間の判断が不可欠です。\n\n## 進め方\n1. 学習目標と対象者を明確にする ② AIに単元構成と学習順序を設計させる ③ 各単元の解説・例題・演習問題をAIで生成 ④ 人間がレビュー・修正して完成させます。\n\n## このレッスンで残すもの\n- 教材ドラフト\n- 学習目標シート\n- 例題・演習問題セット\n\n## 詰まりやすいポイント\n- 対象者のレベル設定が難しい、AIの説明が正確か判断できない、演習問題の難易度調整。\n\n## AI への依頼例\n```text\n今は「AIで教材・学習コンテンツを作ろう」を進めています。\n目的: この lesson を終えると、学習者の理解度に合わせた教材をAIで制作できるようになります\n現状: 研修資料・マニュアル・チュートリアルなどの教材コンテンツをAIで効率的に制作する\n今回残したい成果物: 教材ドラフト、学習目標シート、例題・演習問題セット\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- つのテーマで教材（解説 + 例題 + 演習）を制作し、学習目標との整合性を説明できること。\n\n## 関連キーワード\n- `教材`\n- `学習コンテンツ`\n- `チュートリアル`\n- `マニュアル`\n- `研修資料`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('305e05d6-07fc-5325-b5c2-de3cddbbdcc8', 'fef65479-2ed2-510b-b1c6-700117057284', 'callout', 4, '{"variant":"warning","text":"対象者のレベル設定が難しい、AIの説明が正確か判断できない、演習問題の難易度調整。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('9f5a43bd-876f-599d-a6e1-6976448e702e', 'fef65479-2ed2-510b-b1c6-700117057284', 'rubric', 5, '{"criteria":"1 つのテーマで教材（解説 + 例題 + 演習）を制作し、学習目標との整合性を説明できること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('57761760-45d9-501e-bd11-e73820f667fd', '84ecbf37-56c1-5ae9-9174-1628357dc45d', 'markdown', 0, '{"text":"DALL-E・Midjourney・Stable Diffusionなどの画像生成AIを使い、コンテンツ用ビジュアルを制作する","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('8cac002b-9799-5422-8bb2-b6275ff87bce', '84ecbf37-56c1-5ae9-9174-1628357dc45d', 'callout', 1, '{"variant":"why","text":"テキストだけのコンテンツは視覚的なインパクトに欠けます。AI画像生成を活用すれば、デザインスキルがなくても記事のアイキャッチ・SNS画像・図解を制作できます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('7ddc145a-bb30-5163-a2cc-628496d09464', '84ecbf37-56c1-5ae9-9174-1628357dc45d', 'markdown', 2, '{"text":"① 画像生成AIツール（DALL-E / Midjourney）の基本操作を学ぶ ② コンテンツ用途別（アイキャッチ・SNS・図解）のプロンプトパターンを練習 ③ 生成画像の著作権・利用規約を確認 ④ ブログ記事やSNS投稿に組み込みます。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('28064ca6-3920-56ff-91cd-6b35bf75c04c', '84ecbf37-56c1-5ae9-9174-1628357dc45d', 'markdown', 3, '{"text":"# AI画像生成をコンテンツに活用しよう\n\nDALL-E・Midjourney・Stable Diffusionなどの画像生成AIを使い、コンテンツ用ビジュアルを制作する\n\n## このレッスンのゴール\nこの lesson を終えると、AI画像生成ツールでコンテンツに合ったビジュアルを制作できるようになります\n\n## 先に把握しておくこと\n- モジュール: **ビジュアルコンテンツ制作**\n- 想定時間: **35 分**\n- 到達したい状態: コンテンツ用AI生成画像セット\n\n## なぜ今やるのか\nテキストだけのコンテンツは視覚的なインパクトに欠けます。AI画像生成を活用すれば、デザインスキルがなくても記事のアイキャッチ・SNS画像・図解を制作できます。\n\n## 進め方\n1. 画像生成AIツール（DALL-E / Midjourney）の基本操作を学ぶ ② コンテンツ用途別（アイキャッチ・SNS・図解）のプロンプトパターンを練習 ③ 生成画像の著作権・利用規約を確認 ④ ブログ記事やSNS投稿に組み込みます。\n\n## このレッスンで残すもの\n- AI生成画像（3用途分）\n- 画像プロンプトテンプレート\n- 利用規約チェックリスト\n\n## 詰まりやすいポイント\n- 意図した画像が生成できない、プロンプトの書き方がわからない、著作権の扱いが不安。\n\n## AI への依頼例\n```text\n今は「AI画像生成をコンテンツに活用しよう」を進めています。\n目的: この lesson を終えると、AI画像生成ツールでコンテンツに合ったビジュアルを制作できるようになります\n現状: DALL-E・Midjourney・Stable Diffusionなどの画像生成AIを使い、コンテンツ用ビジュアルを制作する\n今回残したい成果物: AI生成画像（3用途分）、画像プロンプトテンプレート、利用規約チェックリスト\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- 種類以上の用途（アイキャッチ・SNS・図解）でAI画像を生成し、コンテンツに組み込めていること。\n\n## 関連キーワード\n- `AI画像`\n- `画像生成`\n- `DALL-E`\n- `Midjourney`\n- `アイキャッチ`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('b1d0d90a-82f8-5438-955d-56b91994fd4e', '84ecbf37-56c1-5ae9-9174-1628357dc45d', 'callout', 4, '{"variant":"warning","text":"意図した画像が生成できない、プロンプトの書き方がわからない、著作権の扱いが不安。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('cfd89895-03e4-5529-8ae2-59888a5ea6f1', '84ecbf37-56c1-5ae9-9174-1628357dc45d', 'rubric', 5, '{"criteria":"3 種類以上の用途（アイキャッチ・SNS・図解）でAI画像を生成し、コンテンツに組み込めていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('4c317fb9-0f60-586b-b5ab-cec2df4e91c4', '0947f7f2-4214-5083-8113-2064326a622f', 'markdown', 0, '{"text":"AIを使ってプレゼン資料のストーリー構成・スライドデザイン・話す原稿を効率的に制作する","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('9addd0fe-8204-5def-8440-3cdeee180275', '0947f7f2-4214-5083-8113-2064326a622f', 'callout', 1, '{"variant":"why","text":"プレゼン資料は「伝わる構成」が命ですが、構成設計は時間がかかります。AIにストーリー構成を任せ、人間はメッセージの磨き込みに集中することで、質と効率を両立できます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('45cafed2-3547-54e3-b6a4-375e124e2a67', '0947f7f2-4214-5083-8113-2064326a622f', 'markdown', 2, '{"text":"① プレゼンの目的・聴衆・所要時間を設定 ② AIにストーリーライン（起承転結）を設計させる ③ 各スライドの内容・キーメッセージをAIで生成 ④ Gamma や Google Slides でビジュアル化 ⑤ 話す原稿をAIで生成・調整します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('74a4f6c4-7044-542e-9f9e-07ba1889e9b1', '0947f7f2-4214-5083-8113-2064326a622f', 'markdown', 3, '{"text":"# AIでプレゼン資料を作ろう\n\nAIを使ってプレゼン資料のストーリー構成・スライドデザイン・話す原稿を効率的に制作する\n\n## このレッスンのゴール\nこの lesson を終えると、AIを使って説得力のあるプレゼン資料を短時間で制作できるようになります\n\n## 先に把握しておくこと\n- モジュール: **ビジュアルコンテンツ制作**\n- 想定時間: **40 分**\n- 到達したい状態: 完成したプレゼン資料 + 話す原稿\n\n## なぜ今やるのか\nプレゼン資料は「伝わる構成」が命ですが、構成設計は時間がかかります。AIにストーリー構成を任せ、人間はメッセージの磨き込みに集中することで、質と効率を両立できます。\n\n## 進め方\n1. プレゼンの目的・聴衆・所要時間を設定 ② AIにストーリーライン（起承転結）を設計させる ③ 各スライドの内容・キーメッセージをAIで生成 ④ Gamma や Google Slides でビジュアル化 ⑤ 話す原稿をAIで生成・調整します。\n\n## このレッスンで残すもの\n- プレゼン資料（10スライド以上）\n- 話す原稿\n- ストーリー構成図\n\n## 詰まりやすいポイント\n- スライドの情報量が多すぎる、デザインがチープになる、AIの構成が論理的でない。\n\n## AI への依頼例\n```text\n今は「AIでプレゼン資料を作ろう」を進めています。\n目的: この lesson を終えると、AIを使って説得力のあるプレゼン資料を短時間で制作できるようになります\n現状: AIを使ってプレゼン資料のストーリー構成・スライドデザイン・話す原稿を効率的に制作する\n今回残したい成果物: プレゼン資料（10スライド以上）、話す原稿、ストーリー構成図\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- AIと協力してプレゼン資料（10 スライド以上）を完成させ、ストーリー構成を説明できること。\n\n## 関連キーワード\n- `プレゼン`\n- `資料作成`\n- `スライド`\n- `プレゼンテーション`\n- `AI資料`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('b22798cd-a435-51c8-b026-6d0970fafb2e', '0947f7f2-4214-5083-8113-2064326a622f', 'callout', 4, '{"variant":"warning","text":"スライドの情報量が多すぎる、デザインがチープになる、AIの構成が論理的でない。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('52a7a3c0-a0b9-58e6-b09e-9e684c83fcc9', '0947f7f2-4214-5083-8113-2064326a622f', 'rubric', 5, '{"criteria":"AIと協力してプレゼン資料（10 スライド以上）を完成させ、ストーリー構成を説明できること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('4aa72d27-a2a9-5ba1-b009-abf299cdb067', 'ff4c04c2-909f-52ee-8212-1dc6437f067d', 'markdown', 0, '{"text":"コンテンツの企画→制作→レビュー→公開→分析の全工程をAIで効率化するワークフローを設計・構築する","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('71d686e2-a48b-555d-8460-7e656ea01667', 'ff4c04c2-909f-52ee-8212-1dc6437f067d', 'callout', 1, '{"variant":"why","text":"個別のコンテンツをAIで作れるようになった次のステップは、制作プロセス全体の効率化です。テンプレート化・バッチ処理・品質チェックの仕組みを整えることで、継続的なコンテンツ制作が持続可能になります。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('5a98df8f-fd7b-5409-a22c-0c0e185be654', 'ff4c04c2-909f-52ee-8212-1dc6437f067d', 'markdown', 2, '{"text":"① 現在のコンテンツ制作フローを書き出す ② 各工程で使うAIツール・プロンプトを決定 ③ テンプレート集とチェックリストを整備 ④ 週次・月次の制作スケジュールを設計 ⑤ 振り返り（どの工程にどれだけ時間がかかったか）の仕組みを入れます。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c7c7045a-bb4f-5e85-a3da-267efa4d6a52', 'ff4c04c2-909f-52ee-8212-1dc6437f067d', 'markdown', 3, '{"text":"# コンテンツ制作ワークフローを自動化しよう\n\nコンテンツの企画→制作→レビュー→公開→分析の全工程をAIで効率化するワークフローを設計・構築する\n\n## このレッスンのゴール\nこの lesson を終えると、コンテンツ制作の全工程をAIで効率化する仕組みが整います\n\n## 先に把握しておくこと\n- モジュール: **コンテンツワークフロー構築**\n- 想定時間: **35 分**\n- 到達したい状態: コンテンツ制作ワークフロー一式\n\n## なぜ今やるのか\n個別のコンテンツをAIで作れるようになった次のステップは、制作プロセス全体の効率化です。テンプレート化・バッチ処理・品質チェックの仕組みを整えることで、継続的なコンテンツ制作が持続可能になります。\n\n## 進め方\n1. 現在のコンテンツ制作フローを書き出す ② 各工程で使うAIツール・プロンプトを決定 ③ テンプレート集とチェックリストを整備 ④ 週次・月次の制作スケジュールを設計 ⑤ 振り返り（どの工程にどれだけ時間がかかったか）の仕組みを入れます。\n\n## このレッスンで残すもの\n- ワークフロー設計図\n- テンプレート集\n- チェックリスト\n- 制作スケジュール\n\n## 詰まりやすいポイント\n- ワークフローが複雑すぎて運用できない、テンプレートの更新が滞る、品質チェックの基準が曖昧。\n\n## AI への依頼例\n```text\n今は「コンテンツ制作ワークフローを自動化しよう」を進めています。\n目的: この lesson を終えると、コンテンツ制作の全工程をAIで効率化する仕組みが整います\n現状: コンテンツの企画→制作→レビュー→公開→分析の全工程をAIで効率化するワークフローを設計・構築する\n今回残したい成果物: ワークフロー設計図、テンプレート集、チェックリスト、制作スケジュール\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- コンテンツ制作ワークフロー（テンプレート集 + チェックリスト + スケジュール）が完成し、実際に 1 サイクル運用できていること。\n\n## 関連キーワード\n- `ワークフロー`\n- `コンテンツ運用`\n- `自動化`\n- `効率化`\n- `テンプレート`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('82389de5-3e5a-5d22-8fcc-26c25b457cbe', 'ff4c04c2-909f-52ee-8212-1dc6437f067d', 'callout', 4, '{"variant":"warning","text":"ワークフローが複雑すぎて運用できない、テンプレートの更新が滞る、品質チェックの基準が曖昧。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('69735c87-0a2e-5359-b5f4-a832153c26f8', 'ff4c04c2-909f-52ee-8212-1dc6437f067d', 'rubric', 5, '{"criteria":"コンテンツ制作ワークフロー（テンプレート集 + チェックリスト + スケジュール）が完成し、実際に 1 サイクル運用できていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('11df4743-7edc-57fe-9bb9-bc70181ea155', 'c025546b-4276-5009-bba8-1792f8b3db42', 'markdown', 0, '{"text":"1 つのコンテンツを複数フォーマット（ブログ→SNS→スライド→メルマガ）にAIで変換・展開する方法を学ぶ","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('a12b7b5f-2864-5780-a116-7d4a973900a6', 'c025546b-4276-5009-bba8-1792f8b3db42', 'callout', 1, '{"variant":"why","text":"毎回ゼロからコンテンツを作るのは非効率です。1 つの「核」となるコンテンツを複数フォーマットに変換（リパーパス）することで、少ない労力で発信量を倍増できます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('21a9fbac-5f68-5540-a1e1-4028642adfad', 'c025546b-4276-5009-bba8-1792f8b3db42', 'markdown', 2, '{"text":"① ブログ記事を「核」コンテンツとして選ぶ ② AIでSNS投稿 5 本に変換 ③ 要点をスライド化 ④ メルマガ原稿に変換 ⑤ 各フォーマットのテンプレートを保存して再利用可能にします。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('50cb4692-5799-5d34-9b64-a2382c4ab366', 'c025546b-4276-5009-bba8-1792f8b3db42', 'markdown', 3, '{"text":"# コンテンツリパーパスで発信量を倍増させよう\n\n1 つのコンテンツを複数フォーマット（ブログ→SNS→スライド→メルマガ）にAIで変換・展開する方法を学ぶ\n\n## このレッスンのゴール\nこの lesson を終えると、1 つのコンテンツから複数の発信物をAIで効率的に生成できるようになります\n\n## 先に把握しておくこと\n- モジュール: **コンテンツワークフロー構築**\n- 想定時間: **30 分**\n- 到達したい状態: リパーパスされたコンテンツセット + テンプレート\n\n## なぜ今やるのか\n毎回ゼロからコンテンツを作るのは非効率です。1 つの「核」となるコンテンツを複数フォーマットに変換（リパーパス）することで、少ない労力で発信量を倍増できます。\n\n## 進め方\n1. ブログ記事を「核」コンテンツとして選ぶ ② AIでSNS投稿 5 本に変換 ③ 要点をスライド化 ④ メルマガ原稿に変換 ⑤ 各フォーマットのテンプレートを保存して再利用可能にします。\n\n## このレッスンで残すもの\n- リパーパスコンテンツ（3フォーマット以上）\n- リパーパステンプレート集\n\n## 詰まりやすいポイント\n- フォーマット変換で内容が薄くなる、各媒体の特性に合わせた調整が面倒。\n\n## AI への依頼例\n```text\n今は「コンテンツリパーパスで発信量を倍増させよう」を進めています。\n目的: この lesson を終えると、1 つのコンテンツから複数の発信物をAIで効率的に生成できるようになります\n現状: 1 つのコンテンツを複数フォーマット（ブログ→SNS→スライド→メルマガ）にAIで変換・展開する方法を学ぶ\n今回残したい成果物: リパーパスコンテンツ（3フォーマット以上）、リパーパステンプレート集\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- つの核コンテンツから 3 フォーマット以上への変換が完了し、リパーパステンプレートが整備されていること。\n\n## 関連キーワード\n- `リパーパス`\n- `コンテンツ転用`\n- `再利用`\n- `発信量`\n- `コンテンツ展開`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('bd149d39-3d88-562c-981b-b9f262b3198d', 'c025546b-4276-5009-bba8-1792f8b3db42', 'callout', 4, '{"variant":"warning","text":"フォーマット変換で内容が薄くなる、各媒体の特性に合わせた調整が面倒。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('4d3c0d9e-7613-5a67-8653-769e097c02a5', 'c025546b-4276-5009-bba8-1792f8b3db42', 'rubric', 5, '{"criteria":"1 つの核コンテンツから 3 フォーマット以上への変換が完了し、リパーパステンプレートが整備されていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('16e7bd06-cc96-5440-8d06-42a9c5be7d81', 'db710ce5-4bc2-5157-ba8a-84afa9095167', 'markdown', 0, '{"text":"AIチャットを使ってアプリのアイデアを構造化し、要件定義ドキュメントを作成する","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('b3a0c441-b1a3-56f5-9aac-71a60adeee30', 'db710ce5-4bc2-5157-ba8a-84afa9095167', 'callout', 1, '{"variant":"why","text":"アプリ開発で最も多い失敗は「作り始めてから何を作るか迷う」ことです。AIと対話しながら要件を整理することで、開発のブレを防ぎ、完成までの道筋を明確にできます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('00254ab0-bc4b-583c-aa86-65e4dbc1e462', 'db710ce5-4bc2-5157-ba8a-84afa9095167', 'markdown', 2, '{"text":"① AIに「こんなアプリを作りたい」とアイデアを伝える ② AIに機能一覧・ユーザーストーリーを生成させる ③ 優先度をつけてMVP（最小限の製品）を定義 ④ 要件定義ドキュメントとしてまとめます。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('2604e087-582f-5cd0-9420-adb19a4e7c28', 'db710ce5-4bc2-5157-ba8a-84afa9095167', 'markdown', 3, '{"text":"# AIでアプリ要件を整理しよう\n\nAIチャットを使ってアプリのアイデアを構造化し、要件定義ドキュメントを作成する\n\n## このレッスンのゴール\nこの lesson を終えると、AIを使ってアプリの要件を漏れなく整理できるようになります\n\n## 先に把握しておくこと\n- モジュール: **アプリ設計・要件整理**\n- 想定時間: **25 分**\n- 到達したい状態: 要件定義ドキュメント\n\n## なぜ今やるのか\nアプリ開発で最も多い失敗は「作り始めてから何を作るか迷う」ことです。AIと対話しながら要件を整理することで、開発のブレを防ぎ、完成までの道筋を明確にできます。\n\n## 進め方\n1. AIに「こんなアプリを作りたい」とアイデアを伝える ② AIに機能一覧・ユーザーストーリーを生成させる ③ 優先度をつけてMVP（最小限の製品）を定義 ④ 要件定義ドキュメントとしてまとめます。\n\n## このレッスンで残すもの\n- 要件定義ドキュメント\n- 機能一覧\n- MVPスコープ定義\n\n## 詰まりやすいポイント\n- アイデアが漠然としすぎている、機能を盛り込みすぎてMVPが大きくなる、ユーザーストーリーの書き方がわからない。\n\n## AI への依頼例\n```text\n今は「AIでアプリ要件を整理しよう」を進めています。\n目的: この lesson を終えると、AIを使ってアプリの要件を漏れなく整理できるようになります\n現状: AIチャットを使ってアプリのアイデアを構造化し、要件定義ドキュメントを作成する\n今回残したい成果物: 要件定義ドキュメント、機能一覧、MVPスコープ定義\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- AIと協力して要件定義ドキュメント（目的・ターゲットユーザー・機能一覧・MVPスコープ）が完成していること。\n\n## 関連キーワード\n- `アプリ要件`\n- `要件定義`\n- `アプリ設計`\n- `MVP`\n- `ユーザーストーリー`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('e267fe78-709c-5dc1-957c-ea77af7e763e', 'db710ce5-4bc2-5157-ba8a-84afa9095167', 'callout', 4, '{"variant":"warning","text":"アイデアが漠然としすぎている、機能を盛り込みすぎてMVPが大きくなる、ユーザーストーリーの書き方がわからない。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('768fbb6a-757a-5f98-a4ea-577d14bf2229', 'db710ce5-4bc2-5157-ba8a-84afa9095167', 'rubric', 5, '{"criteria":"AIと協力して要件定義ドキュメント（目的・ターゲットユーザー・機能一覧・MVPスコープ）が完成していること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c531dfba-955d-5e17-b382-330e1ca7f772', 'df8ebcd2-c4e2-5671-93f7-f272fa4cc661', 'markdown', 0, '{"text":"AIを使ってアプリのデータ構造（テーブル設計・リレーション）を設計する","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('83e9faef-f644-5f05-b3ad-76fe168fbca6', 'df8ebcd2-c4e2-5671-93f7-f272fa4cc661', 'callout', 1, '{"variant":"why","text":"データモデルはアプリの骨格です。最初にしっかり設計しておくことで、後のCRUD実装やAPI設計がスムーズになります。AIに相談しながら設計することで、正規化やリレーションの判断を効率化できます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c604c04d-d212-58e6-ba31-8ce50c104d16', 'df8ebcd2-c4e2-5671-93f7-f272fa4cc661', 'markdown', 2, '{"text":"① 要件定義から必要なエンティティ（ユーザー・投稿・コメントなど）を洗い出す ② AIにER図の提案を依頼 ③ 各テーブルのカラム・型・制約をAIと決定 ④ Supabaseのテーブル定義（SQL）をAIに生成させます。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('88d5d94b-e069-55b1-bf24-fd2d333c19cd', 'df8ebcd2-c4e2-5671-93f7-f272fa4cc661', 'markdown', 3, '{"text":"# AIでデータモデルを設計しよう\n\nAIを使ってアプリのデータ構造（テーブル設計・リレーション）を設計する\n\n## このレッスンのゴール\nこの lesson を終えると、AIを使ってアプリに必要なデータベース構造を設計できるようになります\n\n## 先に把握しておくこと\n- モジュール: **アプリ設計・要件整理**\n- 想定時間: **30 分**\n- 到達したい状態: データモデル設計（ER図+SQL）\n\n## なぜ今やるのか\nデータモデルはアプリの骨格です。最初にしっかり設計しておくことで、後のCRUD実装やAPI設計がスムーズになります。AIに相談しながら設計することで、正規化やリレーションの判断を効率化できます。\n\n## 進め方\n1. 要件定義から必要なエンティティ（ユーザー・投稿・コメントなど）を洗い出す ② AIにER図の提案を依頼 ③ 各テーブルのカラム・型・制約をAIと決定 ④ Supabaseのテーブル定義（SQL）をAIに生成させます。\n\n## このレッスンで残すもの\n- ER図\n- テーブル定義SQL\n- データモデル設計書\n\n## 詰まりやすいポイント\n- 正規化の度合いがわからない、リレーションの方向が逆、インデックスの設計が不安。\n\n## AI への依頼例\n```text\n今は「AIでデータモデルを設計しよう」を進めています。\n目的: この lesson を終えると、AIを使ってアプリに必要なデータベース構造を設計できるようになります\n現状: AIを使ってアプリのデータ構造（テーブル設計・リレーション）を設計する\n今回残したい成果物: ER図、テーブル定義SQL、データモデル設計書\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- AIと協力してER図とテーブル定義SQL（3テーブル以上）が完成していること。\n\n## 関連キーワード\n- `データモデル`\n- `テーブル設計`\n- `ER図`\n- `データベース設計`\n- `SQL`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('f4c8accb-e2a4-5be9-b69a-74a6d3838a90', 'df8ebcd2-c4e2-5671-93f7-f272fa4cc661', 'callout', 4, '{"variant":"warning","text":"正規化の度合いがわからない、リレーションの方向が逆、インデックスの設計が不安。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('50036d01-6dbc-50de-87a7-174086397a89', 'df8ebcd2-c4e2-5671-93f7-f272fa4cc661', 'rubric', 5, '{"criteria":"AIと協力してER図とテーブル定義SQL（3テーブル以上）が完成していること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('ebcc07f7-f3cd-5b26-a69c-83db29a05a1b', '2aec64b2-31c0-5fd7-b463-1330cf363d9e', 'markdown', 0, '{"text":"Claude CodeやCursorなどのAIコーディングツールでデータのCRUD操作を実装する","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('4d4a0ea3-6556-5d6f-acb0-e4d67417e5b6', '2aec64b2-31c0-5fd7-b463-1330cf363d9e', 'callout', 1, '{"variant":"why","text":"CRUD（Create/Read/Update/Delete）はほぼ全てのアプリの基盤です。AIコーディングツールを使えば、Supabaseクライアントの初期化からクエリ実装まで高速に進められます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('e24a4822-9bd5-54d4-8ba4-3761971fac64', '2aec64b2-31c0-5fd7-b463-1330cf363d9e', 'markdown', 2, '{"text":"① Supabaseプロジェクトを作成しテーブルを作る ② AIコーディングツールでSupabaseクライアントを初期化 ③ データ作成（INSERT）→読取（SELECT）→更新（UPDATE）→削除（DELETE）を順に実装 ④ 動作確認テストを実行します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('8554c07f-f5fc-512e-98fa-bd845f533fa6', '2aec64b2-31c0-5fd7-b463-1330cf363d9e', 'markdown', 3, '{"text":"# AIコーディングでCRUD操作を実装しよう\n\nClaude CodeやCursorなどのAIコーディングツールでデータのCRUD操作を実装する\n\n## このレッスンのゴール\nこの lesson を終えると、AIコーディングツールでデータの読み書きを実装できるようになります\n\n## 先に把握しておくこと\n- モジュール: **バックエンド開発**\n- 想定時間: **40 分**\n- 到達したい状態: 動作するCRUD API\n\n## なぜ今やるのか\nCRUD（Create/Read/Update/Delete）はほぼ全てのアプリの基盤です。AIコーディングツールを使えば、Supabaseクライアントの初期化からクエリ実装まで高速に進められます。\n\n## 進め方\n1. Supabaseプロジェクトを作成しテーブルを作る ② AIコーディングツールでSupabaseクライアントを初期化 ③ データ作成（INSERT）→読取（SELECT）→更新（UPDATE）→削除（DELETE）を順に実装 ④ 動作確認テストを実行します。\n\n## このレッスンで残すもの\n- CRUD実装コード\n- 動作確認スクリーンショット\n\n## 詰まりやすいポイント\n- Supabaseの初期設定がわからない、RLS（行レベルセキュリティ）でデータが取れない、型定義が合わない。\n\n## AI への依頼例\n```text\n今は「AIコーディングでCRUD操作を実装しよう」を進めています。\n目的: この lesson を終えると、AIコーディングツールでデータの読み書きを実装できるようになります\n現状: Claude CodeやCursorなどのAIコーディングツールでデータのCRUD操作を実装する\n今回残したい成果物: CRUD実装コード、動作確認スクリーンショット\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- AIコーディングツールで4つのCRUD操作（作成・読取・更新・削除）が動作確認できていること。\n\n## 関連キーワード\n- `CRUD`\n- `データ操作`\n- `Supabase`\n- `バックエンド`\n- `API実装`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('99bad80e-d0df-50c7-a443-0401a55e49c7', '2aec64b2-31c0-5fd7-b463-1330cf363d9e', 'callout', 4, '{"variant":"warning","text":"Supabaseの初期設定がわからない、RLS（行レベルセキュリティ）でデータが取れない、型定義が合わない。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('fe217e5f-0e9d-5634-a180-97d2e134cf76', '2aec64b2-31c0-5fd7-b463-1330cf363d9e', 'rubric', 5, '{"criteria":"AIコーディングツールで4つのCRUD操作（作成・読取・更新・削除）が動作確認できていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('8e20de1d-60a5-5ffc-968c-1257dce18262', 'c92048d6-e15e-5ba6-8485-8dd6039a3093', 'markdown', 0, '{"text":"Supabase Authを使ったサインアップ・ログイン・ログアウトをAIコーディングで実装する","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('ae622d33-1a2d-5a97-aed2-adf4874ff40f', 'c92048d6-e15e-5ba6-8485-8dd6039a3093', 'callout', 1, '{"variant":"why","text":"ユーザー認証はアプリのセキュリティの要です。Supabase Authを使えば複雑な認証ロジックをゼロから書く必要がなく、AIコーディングツールで素早くセットアップできます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d81ad3b7-ff11-5081-9091-f84f9e3cf332', 'c92048d6-e15e-5ba6-8485-8dd6039a3093', 'markdown', 2, '{"text":"① Supabase AuthのEmail/Password認証を有効化 ② AIでサインアップフォームとAPI実装 ③ ログイン/ログアウト機能を追加 ④ セッション管理（middleware）を実装 ⑤ RLSポリシーでユーザー別データアクセスを設定します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('e981bb9b-3c91-51cb-9ac5-3803cea4f855', 'c92048d6-e15e-5ba6-8485-8dd6039a3093', 'markdown', 3, '{"text":"# AIで認証フローを構築しよう\n\nSupabase Authを使ったサインアップ・ログイン・ログアウトをAIコーディングで実装する\n\n## このレッスンのゴール\nこの lesson を終えると、AIを使ってユーザー認証フローを実装できるようになります\n\n## 先に把握しておくこと\n- モジュール: **バックエンド開発**\n- 想定時間: **35 分**\n- 到達したい状態: 動作する認証フロー\n\n## なぜ今やるのか\nユーザー認証はアプリのセキュリティの要です。Supabase Authを使えば複雑な認証ロジックをゼロから書く必要がなく、AIコーディングツールで素早くセットアップできます。\n\n## 進め方\n1. Supabase AuthのEmail/Password認証を有効化 ② AIでサインアップフォームとAPI実装 ③ ログイン/ログアウト機能を追加 ④ セッション管理（middleware）を実装 ⑤ RLSポリシーでユーザー別データアクセスを設定します。\n\n## このレッスンで残すもの\n- 認証フォームUI\n- ミドルウェア実装\n- RLSポリシー設定\n\n## 詰まりやすいポイント\n- セッションが切れる、RLSポリシーの設定が難しい、OAuth設定が複雑。\n\n## AI への依頼例\n```text\n今は「AIで認証フローを構築しよう」を進めています。\n目的: この lesson を終えると、AIを使ってユーザー認証フローを実装できるようになります\n現状: Supabase Authを使ったサインアップ・ログイン・ログアウトをAIコーディングで実装する\n今回残したい成果物: 認証フォームUI、ミドルウェア実装、RLSポリシー設定\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- サインアップ→ログイン→認証済みページアクセス→ログアウトのフローが動作すること。\n\n## 関連キーワード\n- `認証`\n- `ログイン`\n- `サインアップ`\n- `Auth`\n- `セキュリティ`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('91a34b73-7648-5b4c-b97a-3f08754d039e', 'c92048d6-e15e-5ba6-8485-8dd6039a3093', 'callout', 4, '{"variant":"warning","text":"セッションが切れる、RLSポリシーの設定が難しい、OAuth設定が複雑。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('31bab920-20c3-5e63-91e4-b562c5b3afbe', 'c92048d6-e15e-5ba6-8485-8dd6039a3093', 'rubric', 5, '{"criteria":"サインアップ→ログイン→認証済みページアクセス→ログアウトのフローが動作すること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('5ee259b1-d54a-55fd-9333-2f7c4af0f548', '87008f16-23c8-58a3-951d-ce18c758ce99', 'markdown', 0, '{"text":"RESTful APIの設計原則を学び、AIコーディングツールでNext.js API Routesを実装する","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d0e7a643-86c9-5021-b43b-5ef8d442f6e3', '87008f16-23c8-58a3-951d-ce18c758ce99', 'callout', 1, '{"variant":"why","text":"APIはフロントエンドとバックエンドの接点です。適切なAPI設計ができていれば、フロントエンド実装がスムーズになり、将来のモバイルアプリ対応も容易になります。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('18a29b66-f7cb-5098-956a-820e940f5eb9', '87008f16-23c8-58a3-951d-ce18c758ce99', 'markdown', 2, '{"text":"① AIにAPI設計（エンドポイント一覧・リクエスト/レスポンス形式）を相談 ② Next.js API Routes でエンドポイントを実装 ③ バリデーション（Zod）を追加 ④ エラーハンドリングを実装 ⑤ APIテストで動作確認します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('24aebb00-3463-5af3-92f5-8bfacf24e42f', '87008f16-23c8-58a3-951d-ce18c758ce99', 'markdown', 3, '{"text":"# AIでAPI設計・実装をしよう\n\nRESTful APIの設計原則を学び、AIコーディングツールでNext.js API Routesを実装する\n\n## このレッスンのゴール\nこの lesson を終えると、AIを使ってRESTful APIを設計・実装できるようになります\n\n## 先に把握しておくこと\n- モジュール: **バックエンド開発**\n- 想定時間: **40 分**\n- 到達したい状態: 設計されたRESTful API\n\n## なぜ今やるのか\nAPIはフロントエンドとバックエンドの接点です。適切なAPI設計ができていれば、フロントエンド実装がスムーズになり、将来のモバイルアプリ対応も容易になります。\n\n## 進め方\n1. AIにAPI設計（エンドポイント一覧・リクエスト/レスポンス形式）を相談 ② Next.\n2. js API Routes でエンドポイントを実装 ③ バリデーション（Zod）を追加 ④ エラーハンドリングを実装 ⑤ APIテストで動作確認します。\n\n## このレッスンで残すもの\n- API設計書\n- API Routes実装\n- バリデーションスキーマ\n\n## 詰まりやすいポイント\n- RESTful設計のルールがわからない、バリデーションの書き方、エラーレスポンスの統一。\n\n## AI への依頼例\n```text\n今は「AIでAPI設計・実装をしよう」を進めています。\n目的: この lesson を終えると、AIを使ってRESTful APIを設計・実装できるようになります\n現状: RESTful APIの設計原則を学び、AIコーディングツールでNext.js API Routesを実装する\n今回残したい成果物: API設計書、API Routes実装、バリデーションスキーマ\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- つ以上のAPIエンドポイントが動作し、バリデーション・エラーハンドリングが実装されていること。\n\n## 関連キーワード\n- `API設計`\n- `REST`\n- `エンドポイント`\n- `API Routes`\n- `バリデーション`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('39b3d9d7-9b33-5e85-b3df-6fb198722f67', '87008f16-23c8-58a3-951d-ce18c758ce99', 'callout', 4, '{"variant":"warning","text":"RESTful設計のルールがわからない、バリデーションの書き方、エラーレスポンスの統一。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('68c56d2a-ba50-5114-86fe-61442d5a4ab2', '87008f16-23c8-58a3-951d-ce18c758ce99', 'rubric', 5, '{"criteria":"3つ以上のAPIエンドポイントが動作し、バリデーション・エラーハンドリングが実装されていること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('622babbd-6704-5e7b-9016-07dc8f9c2cb5', '85bc9bbf-9a9c-58c7-8b8c-07fa1411f25b', 'markdown', 0, '{"text":"AIコーディングツールでReactコンポーネントを素早く構築し、ユーザー体験を形にする","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('d66883b6-dead-5f0f-8a8e-342a5b5edd91', '85bc9bbf-9a9c-58c7-8b8c-07fa1411f25b', 'callout', 1, '{"variant":"why","text":"アイデアを素早くUIにすることで、使い勝手を早期に検証できます。AIコーディングツールなら、Tailwind CSS + shadcn/uiのコンポーネントを指示一つで生成できます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('adf765bc-bd17-506a-a3ca-1bde7b5588cc', '85bc9bbf-9a9c-58c7-8b8c-07fa1411f25b', 'markdown', 2, '{"text":"① 画面ワイヤーフレームをAIに説明 ② AIでページレイアウト・ナビゲーションを生成 ③ shadcn/uiコンポーネント（Button・Form・Card・Table）を配置 ④ フォーム入力→API呼び出し→結果表示のフローを接続します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('26cbaae7-91f9-5742-93ae-f687e22f52c6', '85bc9bbf-9a9c-58c7-8b8c-07fa1411f25b', 'markdown', 3, '{"text":"# AIでUIプロトタイプを作ろう\n\nAIコーディングツールでReactコンポーネントを素早く構築し、ユーザー体験を形にする\n\n## このレッスンのゴール\nこの lesson を終えると、AIを使ってUIコンポーネントを素早くプロトタイピングできるようになります\n\n## 先に把握しておくこと\n- モジュール: **フロントエンド実装**\n- 想定時間: **45 分**\n- 到達したい状態: 動作するUIプロトタイプ\n\n## なぜ今やるのか\nアイデアを素早くUIにすることで、使い勝手を早期に検証できます。AIコーディングツールなら、Tailwind CSS + shadcn/uiのコンポーネントを指示一つで生成できます。\n\n## 進め方\n1. 画面ワイヤーフレームをAIに説明 ② AIでページレイアウト・ナビゲーションを生成 ③ shadcn/uiコンポーネント（Button・Form・Card・Table）を配置 ④ フォーム入力→API呼び出し→結果表示のフローを接続します。\n\n## このレッスンで残すもの\n- UIコンポーネント\n- ページレイアウト\n- フォーム→API連携\n\n## 詰まりやすいポイント\n- デザインが思い通りにならない、レスポンシブ対応が難しい、状態管理の方法がわからない。\n\n## AI への依頼例\n```text\n今は「AIでUIプロトタイプを作ろう」を進めています。\n目的: この lesson を終えると、AIを使ってUIコンポーネントを素早くプロトタイピングできるようになります\n現状: AIコーディングツールでReactコンポーネントを素早く構築し、ユーザー体験を形にする\n今回残したい成果物: UIコンポーネント、ページレイアウト、フォーム→API連携\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- 画面以上のUIが完成し、フォーム送信→API連携→結果表示が動作すること。\n\n## 関連キーワード\n- `UIプロトタイプ`\n- `フロントエンド`\n- `React`\n- `コンポーネント`\n- `shadcn`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('6ab1e106-b87c-55e3-9454-50860475dfb4', '85bc9bbf-9a9c-58c7-8b8c-07fa1411f25b', 'callout', 4, '{"variant":"warning","text":"デザインが思い通りにならない、レスポンシブ対応が難しい、状態管理の方法がわからない。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('28002c78-e0e2-5ac1-bac5-f7b451620973', '85bc9bbf-9a9c-58c7-8b8c-07fa1411f25b', 'rubric', 5, '{"criteria":"3画面以上のUIが完成し、フォーム送信→API連携→結果表示が動作すること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('9cde18ec-b644-5f52-ba7e-6584dcf33c33', 'fb073101-7651-57c1-95b8-cb39acf6c862', 'markdown', 0, '{"text":"AIを使ってアプリのテスト戦略を設計し、主要フローの自動テストを実装する","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('37002948-ee08-5d36-975d-2d7e0152d1b2', 'fb073101-7651-57c1-95b8-cb39acf6c862', 'callout', 1, '{"variant":"why","text":"テストがあることで安心してコードを変更でき、バグの早期発見につながります。AIコーディングツールはテストコード生成が得意なので、テスト未経験でも効率的にテストを書けます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c50f275c-315f-5b00-bdee-3dde4de85e39', 'fb073101-7651-57c1-95b8-cb39acf6c862', 'markdown', 2, '{"text":"① AIにテスト戦略（何をどのレベルでテストするか）を相談 ② ユニットテスト（個別関数）をAIで生成 ③ 統合テスト（API→DB）をAIで生成 ④ E2Eテスト（ユーザーフロー）の設計をAIと検討します。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('9910d0e4-efb7-53e7-8f06-cc7d9b811848', 'fb073101-7651-57c1-95b8-cb39acf6c862', 'markdown', 3, '{"text":"# AIでテスト戦略を立てよう\n\nAIを使ってアプリのテスト戦略を設計し、主要フローの自動テストを実装する\n\n## このレッスンのゴール\nこの lesson を終えると、AIを使ってアプリのテストを効率的に書けるようになります\n\n## 先に把握しておくこと\n- モジュール: **フロントエンド実装**\n- 想定時間: **35 分**\n- 到達したい状態: テスト戦略 + 自動テストコード\n\n## なぜ今やるのか\nテストがあることで安心してコードを変更でき、バグの早期発見につながります。AIコーディングツールはテストコード生成が得意なので、テスト未経験でも効率的にテストを書けます。\n\n## 進め方\n1. AIにテスト戦略（何をどのレベルでテストするか）を相談 ② ユニットテスト（個別関数）をAIで生成 ③ 統合テスト（API→DB）をAIで生成 ④ E2Eテスト（ユーザーフロー）の設計をAIと検討します。\n\n## このレッスンで残すもの\n- テスト戦略ドキュメント\n- ユニットテスト\n- 統合テスト\n\n## 詰まりやすいポイント\n- テストの粒度がわからない、モックの書き方が不明、テストが落ちる原因の特定が難しい。\n\n## AI への依頼例\n```text\n今は「AIでテスト戦略を立てよう」を進めています。\n目的: この lesson を終えると、AIを使ってアプリのテストを効率的に書けるようになります\n現状: AIを使ってアプリのテスト戦略を設計し、主要フローの自動テストを実装する\n今回残したい成果物: テスト戦略ドキュメント、ユニットテスト、統合テスト\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- ユニットテスト3本以上+統合テスト1本以上が動作し、テスト戦略ドキュメントがあること。\n\n## 関連キーワード\n- `テスト`\n- `テスト戦略`\n- `ユニットテスト`\n- `自動テスト`\n- `Vitest`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('634e3cf0-a5ec-55db-9d6e-eb18ac5400bd', 'fb073101-7651-57c1-95b8-cb39acf6c862', 'callout', 4, '{"variant":"warning","text":"テストの粒度がわからない、モックの書き方が不明、テストが落ちる原因の特定が難しい。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('40535b2b-de35-5224-83df-f74738bb236b', 'fb073101-7651-57c1-95b8-cb39acf6c862', 'rubric', 5, '{"criteria":"ユニットテスト3本以上+統合テスト1本以上が動作し、テスト戦略ドキュメントがあること。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('f54d981d-3212-5eca-a87a-b95a12327f95', 'c9a95da1-fdbf-507d-8923-c099be287015', 'markdown', 0, '{"text":"Vercelにアプリをデプロイし、環境変数設定・カスタムドメイン・エラー監視の基礎を学ぶ","role":"summary"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('cae844a5-5add-5f54-a2e0-389eb6bc55db', 'c9a95da1-fdbf-507d-8923-c099be287015', 'callout', 1, '{"variant":"why","text":"アプリは公開して初めて価値を発揮します。Vercelなら数クリックでデプロイでき、AIに聞きながら環境変数やドメイン設定も効率的に進められます。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('e48e3c40-6c4f-5fe6-abf3-c13b3a7630f6', 'c9a95da1-fdbf-507d-8923-c099be287015', 'markdown', 2, '{"text":"① GitHubリポジトリとVercelを接続 ② 環境変数（Supabase URL、API Key等）を設定 ③ デプロイ実行と動作確認 ④ カスタムドメインの設定（任意） ⑤ エラー監視・ログ確認の方法を学びます。","role":"how_to"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('5441890c-3f33-5d36-922d-0718deb946c4', 'c9a95da1-fdbf-507d-8923-c099be287015', 'markdown', 3, '{"text":"# AIでアプリをデプロイしよう\n\nVercelにアプリをデプロイし、環境変数設定・カスタムドメイン・エラー監視の基礎を学ぶ\n\n## このレッスンのゴール\nこの lesson を終えると、アプリを本番環境にデプロイし運用を開始できるようになります\n\n## 先に把握しておくこと\n- モジュール: **デプロイ・運用**\n- 想定時間: **30 分**\n- 到達したい状態: デプロイ済みアプリ + 運用基礎設定\n\n## なぜ今やるのか\nアプリは公開して初めて価値を発揮します。Vercelなら数クリックでデプロイでき、AIに聞きながら環境変数やドメイン設定も効率的に進められます。\n\n## 進め方\n1. GitHubリポジトリとVercelを接続 ② 環境変数（Supabase URL、API Key等）を設定 ③ デプロイ実行と動作確認 ④ カスタムドメインの設定（任意） ⑤ エラー監視・ログ確認の方法を学びます。\n\n## このレッスンで残すもの\n- 公開URL\n- 環境変数設定\n- エラー監視設定\n\n## 詰まりやすいポイント\n- 環境変数の設定漏れ、ビルドエラーの原因がわからない、本番とローカルの挙動差異。\n\n## AI への依頼例\n```text\n今は「AIでアプリをデプロイしよう」を進めています。\n目的: この lesson を終えると、アプリを本番環境にデプロイし運用を開始できるようになります\n現状: Vercelにアプリをデプロイし、環境変数設定・カスタムドメイン・エラー監視の基礎を学ぶ\n今回残したい成果物: 公開URL、環境変数設定、エラー監視設定\n次の一手を 3 ステップで提案し、確認ポイントも添えてください。\n```\n\n## 完了チェック\n- Vercelにデプロイされた公開URLでアプリが動作し、エラー監視の設定が完了していること。\n\n## 関連キーワード\n- `デプロイ`\n- `Vercel`\n- `本番公開`\n- `環境変数`\n- `運用`","role":"body"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('c1977950-0909-544b-8873-2db2db8392a8', 'c9a95da1-fdbf-507d-8923-c099be287015', 'callout', 4, '{"variant":"warning","text":"環境変数の設定漏れ、ビルドエラーの原因がわからない、本番とローカルの挙動差異。"}'::jsonb) ON CONFLICT DO NOTHING;
  INSERT INTO lesson_blocks (id, lesson_version_id, type, sort_order, content) VALUES ('b76ee744-1a74-5265-a318-b7286c1fa273', 'c9a95da1-fdbf-507d-8923-c099be287015', 'rubric', 5, '{"criteria":"Vercelにデプロイされた公開URLでアプリが動作し、エラー監視の設定が完了していること。"}'::jsonb) ON CONFLICT DO NOTHING;
